{
  "name": "SafeVoice GBV App",
  "description": "An anonymous reporting, tracking, and education platform for Gender-Based Violence support.",
  "requestFramePermissions": [
    "camera",
    "microphone",
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppView {
  HOME = 'home',
  REPORT = 'report',
  TRACK = 'track',
  EDUCATION = 'education',
  HOTLINES = 'hotlines',
}

export enum GBVType {
  PHYSICAL = 'Physical Violence',
  SEXUAL = 'Sexual Violence',
  EMOTIONAL = 'Emotional/Psychological',
  ECONOMIC = 'Economic Abuse',
  HARASSMENT = 'Sexual Harassment',
  OTHER = 'Other',
}

export enum ReportStatus {
  RECEIVED = 'Received',
  ASSIGNED = 'Assigned to Case Worker',
  IN_REVIEW = 'In Review',
  ACTION_TAKEN = 'Action Taken',
  RESOLVED = 'Resolved',
}

export interface Attachment {
  name: string;
  type: 'image' | 'video' | 'audio';
  url: string; // Base64 or mock URL
}

export interface Report {
  id: string;
  trackingCode: string;
  type: GBVType;
  location: string;
  description: string;
  attachments: Attachment[];
  status: ReportStatus;
  statusHistory: { status: ReportStatus; timestamp: string }[];
  createdAt: string;
}

export interface EducationModule {
  id: string;
  title: string;
  description: string;
  content: string; // Markdown or text
  imageUrl: string;
  quiz?: QuizQuestion[];
}

export interface QuizQuestion {
  question: string;
  options: string[];
  correctIndex: number;
}

export interface Hotline {
  id: string;
  name: string;
  number: string;
  category: 'Emergency' | 'Legal' | 'Medical' | 'Counseling';
  location?: { lat: number; lng: number };
}

export interface SupportCentre {
  id: string;
  name: string;
  address: string;
  distance: string;
  type: string;
}

import { Report, ReportStatus, GBVType, Attachment, EducationModule, Hotline, SupportCentre } from '../types';

// Initial Mock Data
const MOCK_EDUCATION: EducationModule[] = [
  {
    id: '1',
    title: 'What is GBV?',
    description: 'Understanding the basics of Gender-Based Violence.',
    imageUrl: 'https://picsum.photos/400/200?random=1',
    content: `Gender-Based Violence (GBV) refers to harmful acts directed at an individual based on their gender. It is rooted in gender inequality, the abuse of power and harmful norms.

    GBV includes sexual, physical, mental and economic harm inflicted in public or in private. It also includes threats of violence, coercion and manipulation.`,
  },
  {
    id: '2',
    title: 'Warning Signs',
    description: 'How to spot the early signs of abusive behavior.',
    imageUrl: 'https://picsum.photos/400/200?random=2',
    content: `Abuse isn't always physical. Look out for these signs:

    1. **Isolation:** Keeping you away from friends and family.
    2. **Control:** Monitoring your phone, money, or movements.
    3. **Jealousy:** Accusing you of cheating without evidence.
    4. **Gaslighting:** Making you doubt your own sanity or memory.`,
  },
  {
    id: '3',
    title: 'Legal Rights in Kenya',
    description: 'Know your protection under the law.',
    imageUrl: 'https://picsum.photos/400/200?random=3',
    content: `The Sexual Offences Act and the Protection Against Domestic Violence Act provide strong legal frameworks. You have the right to:
    - Police protection orders.
    - Free medical care at public facilities.
    - Legal representation.`,
  }
];

const MOCK_HOTLINES: Hotline[] = [
  { id: '1', name: 'National GBV Helpline', number: '1195', category: 'Emergency' },
  { id: '2', name: 'Police Emergency', number: '999', category: 'Emergency' },
  { id: '3', name: 'FIDA Kenya (Legal Aid)', number: '0800720501', category: 'Legal' },
  { id: '4', name: 'LVCT Health', number: '1190', category: 'Medical' },
];

const MOCK_CENTRES: SupportCentre[] = [
  { id: '1', name: 'GVRC - Nairobi Women\'s Hospital', address: 'Hurlingham, Nairobi', distance: '2.5 km', type: 'Medical & Psychosocial' },
  { id: '2', name: 'Politecare Hospital', address: 'Ngong Road', distance: '4.1 km', type: 'Medical' },
  { id: '3', name: 'Kenyatta National Hospital GBV Center', address: 'Upper Hill', distance: '5.0 km', type: 'Comprehensive Care' },
];

const STORAGE_KEY_REPORTS = 'safevoice_reports';

// Helper to simulate network delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const MockBackend = {
  // Create Report
  async createReport(data: Omit<Report, 'id' | 'trackingCode' | 'status' | 'statusHistory' | 'createdAt'>): Promise<Report> {
    await delay(1500); // Simulate upload latency

    const trackingCode = `SV-${Math.floor(1000 + Math.random() * 9000)}-${new Date().getFullYear()}`;
    const newReport: Report = {
      id: crypto.randomUUID(),
      trackingCode,
      ...data,
      status: ReportStatus.RECEIVED,
      statusHistory: [{ status: ReportStatus.RECEIVED, timestamp: new Date().toISOString() }],
      createdAt: new Date().toISOString(),
    };

    // Save to local storage
    const reports = JSON.parse(localStorage.getItem(STORAGE_KEY_REPORTS) || '[]');
    reports.push(newReport);
    localStorage.setItem(STORAGE_KEY_REPORTS, JSON.stringify(reports));

    return newReport;
  },

  // Get Report
  async getReportByCode(code: string): Promise<Report | null> {
    await delay(1000);
    const reports = JSON.parse(localStorage.getItem(STORAGE_KEY_REPORTS) || '[]') as Report[];
    const report = reports.find(r => r.trackingCode.toUpperCase() === code.toUpperCase());

    // Simulate backend updating status over time if it exists
    if (report) {
       // Mock logic to advance status based on time passed for demo purposes
       const now = new Date().getTime();
       const created = new Date(report.createdAt).getTime();
       const diffMins = (now - created) / 60000;

       if (diffMins > 2 && report.status === ReportStatus.RECEIVED) {
         report.status = ReportStatus.ASSIGNED;
         report.statusHistory.push({ status: ReportStatus.ASSIGNED, timestamp: new Date().toISOString() });
       }
    }

    return report || null;
  },

  // Get Education
  async getEducationModules(): Promise<EducationModule[]> {
    await delay(500);
    return MOCK_EDUCATION;
  },

  // Get Hotlines
  async getHotlines(): Promise<Hotline[]> {
    await delay(500);
    return MOCK_HOTLINES;
  },

  // Get Support Centres
  async getSupportCentres(lat: number, lng: number): Promise<SupportCentre[]> {
    await delay(800);
    // In a real app, use lat/lng to query Geo-spatial DB
    return MOCK_CENTRES;
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { QuizQuestion } from '../types';

// Safely get API key, though in this demo environment it might be mocked or user provided
const API_KEY = process.env.API_KEY || '';

const ai = new GoogleGenAI({ apiKey: API_KEY });

export const GeminiService = {

  async generateQuizForTopic(topic: string): Promise<QuizQuestion[]> {
    if (!API_KEY) {
      console.warn("No API Key available for Gemini. Returning mock quiz.");
      return [
        {
          question: `What is a primary warning sign of ${topic}?`,
          options: ["Supportive behavior", "Isolation from friends", "Open communication", "Respecting boundaries"],
          correctIndex: 1
        },
        {
          question: "Who can you contact for immediate help?",
          options: ["A stranger", "The abuser", "Emergency Hotline 1195", "No one"],
          correctIndex: 2
        }
      ];
    }

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `Create a simple 3-question multiple choice quiz about "${topic}" related to Gender Based Violence awareness. Return JSON only.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                question: { type: Type.STRING },
                options: { type: Type.ARRAY, items: { type: Type.STRING } },
                correctIndex: { type: Type.INTEGER, description: "Zero-based index of the correct option" }
              }
            }
          }
        }
      });

      const jsonText = response.text;
      return JSON.parse(jsonText || '[]');
    } catch (error) {
      console.error("Gemini Quiz Generation failed:", error);
      return [];
    }
  },

  async analyzeReportSafety(description: string): Promise<string> {
    if (!API_KEY) return "Unable to analyze safety (No API Key).";

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `Analyze this GBV report description for immediate risk level. Provide a one sentence safety advice. Description: "${description}"`,
      });
      return response.text || "Please seek immediate help if you are in danger.";
    } catch (error) {
      console.error("Safety analysis failed", error);
      return "Please ensure you are in a safe location.";
    }
  }
};

import React, { useState } from 'react';
import { GBVType, Attachment } from '../types';
import { MockBackend } from '../services/mockBackend';
import { AlertCircle, Camera, Mic, MapPin, Loader2, CheckCircle, FileUp } from 'lucide-react';

export const ReportView: React.FC<{ onReportSubmitted: (code: string) => void }> = ({ onReportSubmitted }) => {
  const [type, setType] = useState<GBVType>(GBVType.PHYSICAL);
  const [location, setLocation] = useState('');
  const [description, setDescription] = useState('');
  const [files, setFiles] = useState<Attachment[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [success, setSuccess] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const newAttachment: Attachment = {
        name: file.name,
        type: file.type.startsWith('image') ? 'image' : file.type.startsWith('audio') ? 'audio' : 'video',
        url: URL.createObjectURL(file) // For preview only
      };
      setFiles([...files, newAttachment]);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!location || !description) return;

    setIsSubmitting(true);
    try {
      const report = await MockBackend.createReport({
        type,
        location,
        description,
        attachments: files
      });
      setSuccess(true);
      setTimeout(() => {
        onReportSubmitted(report.trackingCode);
      }, 2000);
    } catch (error) {
      alert("Failed to submit report. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (success) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center p-6 animate-fade-in">
        <CheckCircle className="w-20 h-20 text-green-500 mb-4" />
        <h2 className="text-2xl font-bold mb-2">Report Submitted</h2>
        <p className="text-gray-600 dark:text-gray-300">Your report has been securely received.</p>
        <p className="text-sm mt-4 text-gray-500">Redirecting to tracking...</p>
      </div>
    );
  }

  return (
    <div className="p-4 pb-20 animate-slide-up">
      <h1 className="text-2xl font-bold mb-6 text-brand-700 dark:text-brand-400">Anonymous Report</h1>

      <div className="bg-yellow-50 dark:bg-yellow-900/20 border-l-4 border-yellow-400 p-4 mb-6 rounded-r">
        <div className="flex">
          <AlertCircle className="w-5 h-5 text-yellow-500 mr-2 flex-shrink-0" />
          <p className="text-sm text-yellow-700 dark:text-yellow-200">
            Your safety is priority. If you are in immediate danger, please call 1195 or 999 immediately.
          </p>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label className="block text-sm font-medium mb-1">Type of Incident</label>
          <select 
            value={type} 
            onChange={(e) => setType(e.target.value as GBVType)}
            className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none"
          >
            {Object.values(GBVType).map(t => (
              <option key={t} value={t}>{t}</option>
            ))}
          </select>
        </div>

        <div>
          <label className="block text-sm font-medium mb-1">Location</label>
          <div className="relative">
            <MapPin className="absolute left-3 top-3.5 w-5 h-5 text-gray-400" />
            <input 
              type="text" 
              placeholder="e.g. Kibera, Nairobi"
              value={location}
              onChange={(e) => setLocation(e.target.value)}
              className="w-full pl-10 p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none"
              required
            />
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium mb-1">Description</label>
          <textarea 
            placeholder="Describe what happened..."
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            className="w-full p-3 h-32 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none resize-none"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium mb-2">Evidence / Attachments (Optional)</label>
          <div className="flex gap-4 mb-4">
             <label className="flex flex-col items-center justify-center w-24 h-24 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400 transition-colors">
                <Camera className="w-6 h-6 text-gray-400 mb-1" />
                <span className="text-xs text-gray-500">Photo</span>
                <input type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
             </label>
             <label className="flex flex-col items-center justify-center w-24 h-24 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400 transition-colors">
                <Mic className="w-6 h-6 text-gray-400 mb-1" />
                <span className="text-xs text-gray-500">Audio</span>
                <input type="file" accept="audio/*" className="hidden" onChange={handleFileChange} />
             </label>
             <label className="flex flex-col items-center justify-center w-24 h-24 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400 transition-colors">
                <FileUp className="w-6 h-6 text-gray-400 mb-1" />
                <span className="text-xs text-gray-500">Video</span>
                <input type="file" accept="video/*" className="hidden" onChange={handleFileChange} />
             </label>
          </div>
          {files.length > 0 && (
            <div className="space-y-2">
              {files.map((f, idx) => (
                <div key={idx} className="flex items-center text-sm p-2 bg-gray-100 dark:bg-gray-800 rounded-lg">
                  <CheckCircle className="w-4 h-4 text-green-500 mr-2" />
                  <span className="truncate">{f.name}</span>
                </div>
              ))}
            </div>
          )}
        </div>

        <button 
          type="submit" 
          disabled={isSubmitting}
          className="w-full bg-brand-600 hover:bg-brand-700 text-white p-4 rounded-xl font-bold shadow-lg shadow-brand-500/30 transition-all active:scale-95 disabled:opacity-70 flex justify-center items-center"
        >
          {isSubmitting ? <Loader2 className="animate-spin w-5 h-5" /> : 'Submit Securely'}
        </button>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { Report, ReportStatus } from '../types';
import { MockBackend } from '../services/mockBackend';
import { Search, Clipboard, Loader2, CheckCircle2, Circle } from 'lucide-react';

interface Props {
  initialCode?: string;
}

export const TrackView: React.FC<Props> = ({ initialCode = '' }) => {
  const [code, setCode] = useState(initialCode);
  const [report, setReport] = useState<Report | null>(null);
  const [loading, setLoading] = useState(false);
  const [searched, setSearched] = useState(false);

  const handleTrack = async () => {
    if (!code) return;
    setLoading(true);
    setSearched(true);
    try {
      const result = await MockBackend.getReportByCode(code);
      setReport(result);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const copyCode = () => {
    navigator.clipboard.writeText(code);
    alert('Code copied to clipboard');
  };

  const statusOrder = [
    ReportStatus.RECEIVED,
    ReportStatus.ASSIGNED,
    ReportStatus.IN_REVIEW,
    ReportStatus.RESOLVED
  ];

  const getStatusIndex = (status: ReportStatus) => {
    // Simplified mapping for demo
    if (status === ReportStatus.ACTION_TAKEN) return 2;
    return statusOrder.indexOf(status);
  };

  const currentStatusIndex = report ? getStatusIndex(report.status) : -1;

  return (
    <div className="p-4 pb-20 animate-slide-up h-full flex flex-col">
      <h1 className="text-2xl font-bold mb-6 text-brand-700 dark:text-brand-400">Track Case</h1>

      <div className="flex gap-2 mb-8">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-3.5 w-5 h-5 text-gray-400" />
          <input 
            type="text" 
            placeholder="Enter Tracking Code (e.g. SV-1234)"
            value={code}
            onChange={(e) => setCode(e.target.value)}
            className="w-full pl-10 p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none uppercase"
          />
        </div>
        <button 
          onClick={handleTrack}
          disabled={loading || !code}
          className="bg-brand-600 text-white px-6 rounded-xl font-medium disabled:opacity-50"
        >
          {loading ? <Loader2 className="animate-spin w-5 h-5" /> : 'Track'}
        </button>
      </div>

      {report && (
        <div className="bg-white dark:bg-gray-800 rounded-2xl p-6 shadow-sm border border-gray-100 dark:border-gray-700 animate-fade-in flex-1 overflow-y-auto">
          <div className="flex justify-between items-center mb-6 border-b border-gray-200 dark:border-gray-700 pb-4">
             <div>
               <p className="text-xs text-gray-500 uppercase tracking-wider">Tracking Code</p>
               <h2 className="text-xl font-mono font-bold text-brand-600">{report.trackingCode}</h2>
             </div>
             <button onClick={copyCode} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full">
               <Clipboard className="w-5 h-5 text-gray-400" />
             </button>
          </div>

          <div className="relative pl-4 space-y-8 before:absolute before:left-[19px] before:top-2 before:bottom-2 before:w-0.5 before:bg-gray-200 dark:before:bg-gray-700">
            {statusOrder.map((status, idx) => {
              const isCompleted = idx <= currentStatusIndex;
              const isCurrent = idx === currentStatusIndex;

              return (
                <div key={status} className="relative pl-8">
                  <div className={`absolute left-0 top-1 w-10 h-10 -ml-5 flex items-center justify-center rounded-full border-4 ${
                    isCompleted 
                      ? 'bg-brand-500 border-white dark:border-gray-800 text-white' 
                      : 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-300'
                  }`}>
                    {isCompleted ? <CheckCircle2 className="w-5 h-5" /> : <Circle className="w-5 h-5" />}
                  </div>
                  <div>
                    <h3 className={`font-semibold ${isCompleted ? 'text-gray-900 dark:text-white' : 'text-gray-400'}`}>
                      {status}
                    </h3>
                    {isCurrent && (
                      <p className="text-sm text-brand-500 mt-1">Current Status</p>
                    )}
                    {/* Mock Date for demo */}
                    {isCompleted && (
                      <p className="text-xs text-gray-400 mt-1">
                         {new Date().toLocaleDateString()}
                      </p>
                    )}
                  </div>
                </div>
              );
            })}
          </div>

          <div className="mt-8 p-4 bg-gray-50 dark:bg-gray-700/50 rounded-xl">
            <h4 className="font-medium mb-2 text-sm text-gray-500">Submitted Description</h4>
            <p className="text-gray-700 dark:text-gray-300 italic">"{report.description}"</p>
          </div>
        </div>
      )}

      {!report && searched && !loading && (
        <div className="text-center mt-10 text-gray-500">
          <p>No report found with that code.</p>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { EducationModule, QuizQuestion } from '../types';
import { MockBackend } from '../services/mockBackend';
import { GeminiService } from '../services/geminiService';
import { ChevronRight, ArrowLeft, BookOpen, BrainCircuit, Loader2 } from 'lucide-react';

export const EducationView: React.FC = () => {
  const [modules, setModules] = useState<EducationModule[]>([]);
  const [selectedModule, setSelectedModule] = useState<EducationModule | null>(null);
  const [quizMode, setQuizMode] = useState(false);
  const [quizQuestions, setQuizQuestions] = useState<QuizQuestion[]>([]);
  const [loadingQuiz, setLoadingQuiz] = useState(false);
  const [quizScore, setQuizScore] = useState<number | null>(null);

  useEffect(() => {
    MockBackend.getEducationModules().then(setModules);
  }, []);

  const handleStartQuiz = async () => {
    if (!selectedModule) return;
    setLoadingQuiz(true);
    setQuizMode(true);
    const questions = await GeminiService.generateQuizForTopic(selectedModule.title);
    setQuizQuestions(questions);
    setLoadingQuiz(false);
    setQuizScore(null);
  };

  const handleBack = () => {
    if (quizMode) {
      setQuizMode(false);
      setQuizScore(null);
    } else {
      setSelectedModule(null);
    }
  };

  if (selectedModule) {
    if (quizMode) {
      return (
        <QuizComponent 
          title={selectedModule.title}
          questions={quizQuestions} 
          loading={loadingQuiz}
          onBack={handleBack}
        />
      );
    }

    return (
      <div className="p-4 pb-20 animate-slide-up bg-white dark:bg-gray-900 min-h-full">
        <button onClick={handleBack} className="flex items-center text-gray-500 mb-4 hover:text-brand-600">
          <ArrowLeft className="w-5 h-5 mr-1" /> Back
        </button>

        <img 
          src={selectedModule.imageUrl} 
          alt={selectedModule.title} 
          className="w-full h-48 object-cover rounded-2xl mb-6 shadow-md"
        />

        <h1 className="text-2xl font-bold mb-4 text-gray-900 dark:text-white">{selectedModule.title}</h1>

        <div className="prose dark:prose-invert max-w-none text-gray-600 dark:text-gray-300 mb-8 whitespace-pre-line">
          {selectedModule.content}
        </div>

        <button 
          onClick={handleStartQuiz}
          className="w-full bg-indigo-600 hover:bg-indigo-700 text-white p-4 rounded-xl font-bold shadow-lg flex items-center justify-center gap-2"
        >
          <BrainCircuit className="w-5 h-5" />
          Take AI Quiz
        </button>
      </div>
    );
  }

  return (
    <div className="p-4 pb-20 animate-slide-up">
      <h1 className="text-2xl font-bold mb-6 text-brand-700 dark:text-brand-400">Education Center</h1>
      <div className="grid gap-4">
        {modules.map(mod => (
          <div 
            key={mod.id} 
            onClick={() => setSelectedModule(mod)}
            className="bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex items-center cursor-pointer hover:shadow-md transition-shadow active:scale-[0.98]"
          >
            <div className="w-16 h-16 bg-gray-200 rounded-xl overflow-hidden mr-4 flex-shrink-0">
                <img src={mod.imageUrl} alt="" className="w-full h-full object-cover" />
            </div>
            <div className="flex-1">
              <h3 className="font-bold text-gray-900 dark:text-white">{mod.title}</h3>
              <p className="text-sm text-gray-500 dark:text-gray-400 line-clamp-1">{mod.description}</p>
            </div>
            <ChevronRight className="w-5 h-5 text-gray-400" />
          </div>
        ))}
      </div>
    </div>
  );
};

// Sub-component for Quiz
const QuizComponent: React.FC<{
  title: string;
  questions: QuizQuestion[];
  loading: boolean;
  onBack: () => void;
}> = ({ title, questions, loading, onBack }) => {
  const [answers, setAnswers] = useState<number[]>([]);
  const [submitted, setSubmitted] = useState(false);

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center h-full pt-40">
        <Loader2 className="w-10 h-10 text-brand-600 animate-spin mb-4" />
        <p className="text-gray-500">Generating quiz with AI...</p>
      </div>
    );
  }

  if (questions.length === 0) {
      return (
        <div className="p-4 text-center">
            <p>Could not load quiz.</p>
            <button onClick={onBack} className="mt-4 text-brand-600">Go Back</button>
        </div>
      )
  }

  const handleAnswer = (qIndex: number, optIndex: number) => {
    if (submitted) return;
    const newAns = [...answers];
    newAns[qIndex] = optIndex;
    setAnswers(newAns);
  };

  const calculateScore = () => {
    setSubmitted(true);
  };

  const score = answers.reduce((acc, ans, idx) => acc + (ans === questions[idx].correctIndex ? 1 : 0), 0);

  return (
    <div className="p-4 pb-20 animate-slide-up">
      <button onClick={onBack} className="flex items-center text-gray-500 mb-4">
        <ArrowLeft className="w-5 h-5 mr-1" /> Exit Quiz
      </button>

      <h1 className="text-xl font-bold mb-2">Quiz: {title}</h1>
      <p className="text-sm text-gray-500 mb-6">Test your knowledge.</p>

      <div className="space-y-6">
        {questions.map((q, qIdx) => (
          <div key={qIdx} className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm">
            <h3 className="font-semibold mb-3">{q.question}</h3>
            <div className="space-y-2">
              {q.options.map((opt, optIdx) => {
                let btnClass = "w-full p-3 rounded-lg text-left text-sm border transition-colors ";

                if (submitted) {
                  if (optIdx === q.correctIndex) btnClass += "bg-green-100 border-green-500 text-green-800 dark:bg-green-900/30 dark:text-green-200 ";
                  else if (answers[qIdx] === optIdx) btnClass += "bg-red-100 border-red-500 text-red-800 dark:bg-red-900/30 dark:text-red-200 ";
                  else btnClass += "border-gray-200 dark:border-gray-700 opacity-50 ";
                } else {
                  if (answers[qIdx] === optIdx) btnClass += "bg-brand-50 border-brand-500 text-brand-700 dark:bg-brand-900/20 dark:text-brand-300 ";
                  else btnClass += "border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 ";
                }

                return (
                  <button 
                    key={optIdx}
                    onClick={() => handleAnswer(qIdx, optIdx)}
                    className={btnClass}
                    disabled={submitted}
                  >
                    {opt}
                  </button>
                );
              })}
            </div>
          </div>
        ))}
      </div>

      {!submitted ? (
        <button 
          onClick={calculateScore}
          disabled={answers.length < questions.length}
          className="w-full mt-8 bg-brand-600 text-white p-4 rounded-xl font-bold disabled:opacity-50"
        >
          Submit Answers
        </button>
      ) : (
        <div className="mt-8 p-4 bg-brand-50 dark:bg-brand-900/20 rounded-xl text-center">
          <p className="text-lg font-bold text-brand-800 dark:text-brand-200">
            You scored {score} / {questions.length}
          </p>
          <button onClick={onBack} className="mt-4 text-sm underline text-brand-600">
            Back to Modules
          </button>
        </div>
      )}
    </div>
  );
};

