                   onClick={() => setView(AppView.EDUCATION)}
                   className="bg-white dark:bg-gray-800 p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 text-left hover:shadow-md transition-shadow active:scale-95"
