          <NavButton target={AppView.HOME} icon={<Home className="w-6 h-6" />} label="Home" />
          <NavButton target={AppView.REPORT} icon={<FilePlus className="w-6 h-6" />} label="Report" />
          <NavButton target={AppView.TRACK} icon={<UserCircle className="w-6 h-6" />} label="Track" />
          <NavButton target={AppView.EDUCATION} icon={<BookOpen className="w-6 h-6" />} label="Learn" />
        </nav>
      </div>
    </div>
  );
};

export default App;

