// Helper to simulate network delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const MockBackend = {
  // Create Report
  async createReport(data: Omit<Report, 'id' | 'trackingCode' | 'status' | 'statusHistory' | 'createdAt'>): Promise<Report> {
    await delay(1500); // Simulate upload latency

    const trackingCode = `SV-${Math.floor(1000 + Math.random() * 9000)}-${new Date().getFullYear()}`;
    const newReport: Report = {
      id: crypto.randomUUID(),
      trackingCode,
      ...data,
      status: ReportStatus.RECEIVED,
      statusHistory: [{ status: ReportStatus.RECEIVED, timestamp: new Date().toISOString() }],
      createdAt: new Date().toISOString(),
    };

    // Save to local storage
    const reports = JSON.parse(localStorage.getItem(STORAGE_KEY_REPORTS) || '[]');
    reports.push(newReport);
    localStorage.setItem(STORAGE_KEY_REPORTS, JSON.stringify(reports));

    return newReport;
  },

  // Get Report
  async getReportByCode(code: string): Promise<Report | null> {
    await delay(1000);
    const reports = JSON.parse(localStorage.getItem(STORAGE_KEY_REPORTS) || '[]') as Report[];
    const report = reports.find(r => r.trackingCode.toUpperCase() === code.toUpperCase());

    // Simulate backend updating status over time if it exists
    if (report) {
       // Mock logic to advance status based on time passed for demo purposes
       const now = new Date().getTime();
       const created = new Date(report.createdAt).getTime();
       const diffMins = (now - created) / 60000;

       // Only auto-update if it's still in initial state and has been a few minutes
       if (diffMins > 2 && report.status === ReportStatus.RECEIVED) {
         // Note: In a real backend, this would happen via admin action or automated trigger
         // We won't mutate local storage here to preserve admin dashboard demo capability
       }
    }

    return report || null;
  },

  // Get Education
  async getEducationModules(): Promise<EducationModule[]> {
    await delay(500);
    return MOCK_EDUCATION;
  },

  // Get Hotlines
  async getHotlines(): Promise<Hotline[]> {
    await delay(500);
    return MOCK_HOTLINES;
  },

  // Get Support Centres
  async getSupportCentres(lat: number, lng: number): Promise<SupportCentre[]> {
    await delay(800);
    // In a real app, use lat/lng to query Geo-spatial DB
    return MOCK_CENTRES;
  },

  // --- ADMIN METHODS ---

  async adminLogin(email: string, password: string): Promise<boolean> {
    await delay(1000);
    // Mock Auth
    return email === 'admin@safevoice.org' && password === 'admin123';
  },

  async getAllReports(): Promise<Report[]> {
    await delay(800);
    return JSON.parse(localStorage.getItem(STORAGE_KEY_REPORTS) || '[]');
  },

  async updateReportStatus(reportId: string, newStatus: ReportStatus): Promise<Report | null> {
    await delay(600);
    const reports = JSON.parse(localStorage.getItem(STORAGE_KEY_REPORTS) || '[]') as Report[];
    const index = reports.findIndex(r => r.id === reportId);

    if (index !== -1) {
      const updatedReport = { ...reports[index] };
      updatedReport.status = newStatus;
      updatedReport.statusHistory.push({ 
        status: newStatus, 
        timestamp: new Date().toISOString() 
      });

      reports[index] = updatedReport;
      localStorage.setItem(STORAGE_KEY_REPORTS, JSON.stringify(reports));
      return updatedReport;
    }
    return null;
  }
};

