/**
 * SafeVoice Backend API
 * 
 * Instructions:
 * 1. Install dependencies: npm install
 * 2. Set environment variables in .env (PORT, SECRET_KEY)
 * 3. Run: npm start
 */

const express = require('express');
const cors = require('cors');
const multer = require('multer');
const jwt = require('jsonwebtoken');
const { v4: uuidv4 } = require('uuid');
const path = require('path');

const app = express();
const PORT = process.env.PORT || 3000;
const SECRET_KEY = process.env.SECRET_KEY || 'safevoice-super-secret-key';

// Middleware
app.use(cors());
app.use(express.json());
app.use('/uploads', express.static(path.join(__dirname, 'uploads')));

// Storage Setup (Disk Storage for Demo)
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    // Ensure 'uploads' directory exists
    cb(null, 'uploads/');
  },
  filename: (req, file, cb) => {
    cb(null, Date.now() + '-' + file.originalname);
  }
});
const upload = multer({ storage });

// --- In-Memory Database (Replace with MongoDB/Postgres in Production) ---
let reports = [];
const ADMIN_CREDENTIALS = {
  email: 'admin@safevoice.org',
  password: 'admin123' // Hash this in production!
};

// --- Middleware: Authenticate Admin ---
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) return res.sendStatus(401);

  jwt.verify(token, SECRET_KEY, (err, user) => {
    if (err) return res.sendStatus(403);
    req.user = user;
    next();
  });
};

// --- Routes ---

// 1. Submit Report (Anonymous)
app.post('/api/gbv-report', upload.array('attachments'), (req, res) => {
  const { type, location, description, anonymousUserId } = req.body;

  if (!type || !location || !description) {
    return res.status(400).json({ error: 'Missing required fields' });
  }

  const trackingCode = `SV-${Math.floor(1000 + Math.random() * 9000)}-${new Date().getFullYear()}`;

  const newReport = {
    id: uuidv4(),
    trackingCode,
    type,
    location,
    description,
    anonymousUserId: anonymousUserId || uuidv4(),
    status: 'Received',
    statusHistory: [{ status: 'Received', timestamp: new Date().toISOString() }],
    createdAt: new Date().toISOString(),
    attachments: req.files ? req.files.map(f => ({
      name: f.originalname,
      type: f.mimetype.split('/')[0],
      url: `/uploads/${f.filename}` // In prod, upload to S3/Cloudinary and store URL
    })) : []
  };

  reports.push(newReport);
  console.log(`[New Report] ${trackingCode} from ${location}`);

  res.status(201).json({ 
    message: 'Report submitted successfully', 
    trackingCode: newReport.trackingCode 
  });
});

// 2. Track Report (Public)
app.get('/api/gbv-report/:trackingCode', (req, res) => {
  const { trackingCode } = req.params;
  const report = reports.find(r => r.trackingCode.toUpperCase() === trackingCode.toUpperCase());

  if (!report) {
    return res.status(404).json({ error: 'Report not found' });
  }

  // Return limited info for privacy
  res.json({
    trackingCode: report.trackingCode,
    status: report.status,
    statusHistory: report.statusHistory,
    createdAt: report.createdAt,
    description: report.description // Optional, depending on privacy policy
  });
});

// 3. Admin Login
app.post('/api/auth/login', (req, res) => {
  const { email, password } = req.body;

  // Simple check (Use bcrypt in production)
  if (email === ADMIN_CREDENTIALS.email && password === ADMIN_CREDENTIALS.password) {
    const token = jwt.sign({ email }, SECRET_KEY, { expiresIn: '12h' });
    res.json({ token });
  } else {
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

// 4. Admin: Get All Reports
app.get('/api/admin/reports', authenticateToken, (req, res) => {
  res.json(reports);
});

// 5. Admin: Get Single Report Detail
app.get('/api/admin/reports/:id', authenticateToken, (req, res) => {
  const report = reports.find(r => r.id === req.params.id);
  if (!report) return res.status(404).json({ error: 'Not found' });
  res.json(report);
});

// 6. Admin: Update Status
app.patch('/api/admin/reports/:id', authenticateToken, (req, res) => {
  const { status } = req.body;
  const reportIndex = reports.findIndex(r => r.id === req.params.id);

  if (reportIndex === -1) return res.status(404).json({ error: 'Not found' });

  reports[reportIndex].status = status;
  reports[reportIndex].statusHistory.push({
    status,
    timestamp: new Date().toISOString()
  });

  res.json(reports[reportIndex]);
});

// Start Server
app.listen(PORT, () => {
  console.log(`SafeVoice Backend running on http://localhost:${PORT}`);
});

