export const BackendService = {

  // --- CLIENT-SIDE DATABASE SIMULATION ---

  async createReport(data: Omit<Report, 'id' | 'trackingCode' | 'status' | 'statusHistory' | 'createdAt'>): Promise<Report> {
    await delay(800); // Simulate network request

    const trackingCode = `SV-${Math.floor(1000 + Math.random() * 9000)}-${new Date().getFullYear()}`;

    const newReport: Report = {
      id: crypto.randomUUID(),
      trackingCode,
      ...data,
      status: ReportStatus.RECEIVED,
      statusHistory: [{ status: ReportStatus.RECEIVED, timestamp: new Date().toISOString() }],
      createdAt: new Date().toISOString(),
      // Ensure attachments are stored (mock upload)
      attachments: data.attachments || [] 
    };

    // Save to LocalStorage "Database"
    const currentReports = this._getDbReports();
    currentReports.push(newReport);
    localStorage.setItem(DB_KEY_REPORTS, JSON.stringify(currentReports));

    // Save tracking code to user's local history
    this.addToHistory(trackingCode);

    return newReport;
  },

  async getReportByCode(code: string): Promise<Report | null> {
    await delay(500);
    const reports = this._getDbReports();
    const report = reports.find(r => r.trackingCode === code);
    return report || null;
  },

  // --- ADMIN API SIMULATION ---

  async adminLogin(email: string, password: string): Promise<boolean> {
    await delay(600);

    const validUser = ADMIN_ACCOUNTS.find(
      account => account.email === email && account.password === password
    );

    if (validUser) {
      // Store a mock token that includes the role for display purposes if needed
      localStorage.setItem(STORAGE_KEY_ADMIN_TOKEN, `mock-jwt-token-${validUser.role}`);
      return true;
    }

    return false;
  },

  async getAllReports(): Promise<Report[]> {
    await delay(600);
    const token = localStorage.getItem(STORAGE_KEY_ADMIN_TOKEN);
    if (!token) return [];
    return this._getDbReports();
  },

  async updateReportStatus(id: string, status: ReportStatus): Promise<void> {
    await delay(400);
    const reports = this._getDbReports();
    const reportIndex = reports.findIndex(r => r.id === id);

    if (reportIndex > -1) {
      const report = reports[reportIndex];
      report.status = status;
      report.statusHistory.push({ status, timestamp: new Date().toISOString() });

      reports[reportIndex] = report;
      localStorage.setItem(DB_KEY_REPORTS, JSON.stringify(reports));
    } else {
      throw new Error("Report not found");
    }
  },

  // --- INTERNAL HELPERS ---

  _getDbReports(): Report[] {
    try {
      return JSON.parse(localStorage.getItem(DB_KEY_REPORTS) || '[]');
    } catch {
      return [];
    }
  },

  addToHistory(code: string) {
    const history = JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
    if (!history.includes(code)) {
      history.unshift(code);
      localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(history));
    }
  },

  getHistory(): string[] {
    return JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
  },

  // --- STATIC DATA ---

  async getEducationModules(): Promise<EducationModule[]> {
    return MOCK_EDUCATION;
  },

  async getHotlines(): Promise<Hotline[]> {
    return MOCK_HOTLINES;
  },

  async getSupportCentres(lat: number, lng: number): Promise<SupportCentre[]> {
    // If lat/lng is 0 (permission denied or default), return raw list
    if (lat === 0 && lng === 0) {
        return MOCK_CENTRES_DB.map(c => ({
            ...c,
            distance: 'Unknown distance',
            id: c.id
        }));
    }

    // Calculate real distance offline
    const sorted = MOCK_CENTRES_DB.map(center => {
        const dist = calculateDistance(lat, lng, center.lat, center.lng);
        return {
            ...center,
            distance: `${dist.toFixed(1)} km`,
            rawDist: dist
        };
    }).sort((a, b) => a.rawDist - b.rawDist);

    return sorted;
  }
};

import React, { useState, useRef, useEffect } from 'react';
