    let plan = `### Your Safety Plan (Offline Mode)\n\n`;

    plan += `**1. Stay Ready:**\nKeep your phone charged. Memorize 1195 (National Helpline).\n\n`;

    if (inputs.livingSituation === 'Living with abuser') {
