export const AdminDashboard: React.FC<{ onLogout: () => void }> = ({ onLogout }) => {
  const [reports, setReports] = useState<Report[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedReport, setSelectedReport] = useState<Report | null>(null);
  const [filterStatus, setFilterStatus] = useState<string>('All');
  const [searchTerm, setSearchTerm] = useState('');

  // New state for update message
  const [newUpdate, setNewUpdate] = useState('');
  const [sendingUpdate, setSendingUpdate] = useState(false);

  // Fetch data on mount
  const refreshData = async () => {
    setLoading(true);
    const data = await BackendService.getAllReports();
    // Sort by newest first
    const sorted = data.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
    setReports(sorted);
    setLoading(false);
  };

  useEffect(() => {
    refreshData();
  }, []);

  const handleStatusUpdate = async (newStatus: ReportStatus) => {
    if (!selectedReport) return;
    try {
      await BackendService.updateReportStatus(selectedReport.id, newStatus);
      setSelectedReport(prev => prev ? { ...prev, status: newStatus } : null);
      refreshData();
    } catch (e) {
      alert("Failed to update status");
    }
  };

  const handleSendUpdate = async () => {
    if (!selectedReport || !newUpdate.trim()) return;
    setSendingUpdate(true);
    try {
        await BackendService.addCaseUpdate(selectedReport.id, newUpdate);
        // Refresh local selected report updates
        const freshReports = await BackendService.getAllReports();
        const updatedReport = freshReports.find(r => r.id === selectedReport.id) || null;
        setSelectedReport(updatedReport);
        setReports(freshReports);
        setNewUpdate('');
