                </div>

                {/* Description */}
                <div>
                   <h3 className="text-sm font-semibold text-gray-500 uppercase mb-2">Description</h3>
                   <div className="bg-gray-50 dark:bg-gray-800 p-4 rounded-xl text-gray-700 dark:text-gray-300 whitespace-pre-line leading-relaxed text-sm">
                     {selectedReport.description}
                   </div>
                </div>

                {/* Attachments */}
                {selectedReport.attachments.length > 0 && (
                  <div>
                    <h3 className="text-sm font-semibold text-gray-500 uppercase mb-3">Evidence / Attachments</h3>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      {selectedReport.attachments.map((att, i) => (
                        <div key={i} className="border border-gray-200 dark:border-gray-700 rounded-lg p-3 flex items-center gap-3 bg-white dark:bg-gray-800">
                           <div className="w-10 h-10 bg-gray-100 dark:bg-gray-700 rounded-lg flex items-center justify-center text-gray-400 flex-shrink-0">
