          <div className="flex items-center gap-3">
             <div className="relative">
                <Search className="absolute left-3 top-2.5 w-4 h-4 text-gray-400" />
                <input 
                  type="text" 
                  placeholder="Search code..." 
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
