             {/* Mobile Exit Button */}
             <button 
                onClick={onLogout} 
                className="md:hidden flex items-center gap-1.5 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 px-3 py-2 rounded-lg text-xs font-bold transition-colors active:scale-95 border border-red-100 dark:border-red-900"
             >
