                      <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase whitespace-nowrap">Type</th>
                      <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase whitespace-nowrap">Date</th>
                      <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase whitespace-nowrap">Status</th>
                      <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase text-right whitespace-nowrap">Action</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
