                    ))}
                  </tbody>
                </table>
              </div>

              {/* Mobile Card View */}
              <div className="md:hidden space-y-4">
                 {filteredReports.map(report => (
                    <div 
                      key={report.id} 
                      onClick={() => setSelectedReport(report)}
                      className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 active:scale-[0.98] transition-transform"
