                       <div className="flex justify-between items-start mb-3">
                          <div>
                             <span className="font-mono text-lg font-bold text-brand-600">{report.trackingCode}</span>
                             <p className="text-xs text-gray-500">{new Date(report.createdAt).toLocaleDateString()}</p>
                          </div>
                          <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(report.status)}`}>
                            {report.status}
                          </span>
                       </div>

                       <div className="flex items-center justify-between text-sm text-gray-700 dark:text-gray-300 mb-2">
