                SV
              </div>
              <h1 className="font-bold text-lg tracking-tight text-gray-800 dark:text-white hidden sm:block">SafeVoice</h1>
            </div>
            <div className="flex items-center gap-3">
              {/* Quick Exit */}
              <button 
                onClick={handleQuickExit}
