export const GeminiService = {

  async generateQuizForTopic(topic: string): Promise<QuizQuestion[]> {
    // 1. Try Online AI
    if (ai && navigator.onLine) {
      try {
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash',
          contents: `Create a simple 3-question multiple choice quiz about "${topic}" related to Gender Based Violence awareness. Return JSON only.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: { type: Type.ARRAY, items: { type: Type.STRING } },
                  correctIndex: { type: Type.INTEGER, description: "Zero-based index of the correct option" }
                }
              }
            }
          }
        });
        const jsonText = response.text;
        if (jsonText) return JSON.parse(jsonText);
      } catch (error) {
        console.warn("Online quiz generation failed, switching to offline database.");
      }
    }

    // 2. Offline Fallback
    // Return specific topic quiz or a generic fallback
    return LOCAL_QUIZ_DB[topic] || [
      { question: `True or False: Information about ${topic} empowers you.`, options: ["False", "True"], correctIndex: 1 },
      { question: "If you feel unsafe, what is the best first step?", options: ["Ignore it", "Trust your instincts and seek safety", "Argue back"], correctIndex: 1 },
      { question: "You are:", options: ["Alone", "Not alone", "To blame"], correctIndex: 1 }
    ];
  },

  async chatWithAI(userText: string): Promise<string> {
    // 1. Try Online AI
    if (ai && navigator.onLine) {
      try {
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash',
          contents: `You are an expert Crisis Response Specialist for a GBV app. 
          Your goal is to provide **CONCRETE, ACTIONABLE SOLUTIONS** and **SAFETY PROTOCOLS**.
          Do not just say "I'm sorry". Give steps.

          Examples of good responses:
          - "Pack a go-bag with ID, cash, and medication. Hide it at a friend's house."
          - "Go to the hospital immediately. Do not shower before going, to preserve evidence."
          - "Use a code word like 'Groceries' to text your sister so she knows to call the police."

          User said: "${userText}"

          Provide a concise, step-by-step solution (max 3 steps).`,
        });
        if (response.text) return response.text;
      } catch (e) {
        console.warn("Chat offline or API failed.");
      }
    }

    // 2. Offline Keyword Matcher
    const lowerInput = userText.toLowerCase();

    // Sort keys by length (descending) to match specific phrases first
    // e.g., match "children" before "hi" if "hi" is in "children" (though rare), 
    // or match "sexual" before "sex" if defined.
    const keys = Object.keys(CHAT_KEYWORDS).sort((a, b) => b.length - a.length);

    for (const key of keys) {
      if (lowerInput.includes(key)) {
        return CHAT_KEYWORDS[key];
      }
    }

    // 3. Last Resort Fallback
    return "I hear you. To help you best, could you please tell me if you need 'Medical', 'Legal', or 'Safety' advice? Typing one of those words will help me guide you.";
  },

  async generateSafetyPlan(inputs: { livingSituation: string; hasChildren: boolean; accessToMoney: string; trustedContact: boolean }): Promise<string> {
    // 1. Try Online AI
    if (ai && navigator.onLine) {
      try {
        const prompt = `
          You are a tactical security expert for domestic violence victims. 
          Create a **HIGHLY PRACTICAL, STEP-BY-STEP EXIT STRATEGY**.
          Focus on logistics: documents, money, escape routes, and communication security.

          User Context: Living: ${inputs.livingSituation}, Children: ${inputs.hasChildren ? 'Yes' : 'No'}, Money: ${inputs.accessToMoney}, Contact: ${inputs.trustedContact ? 'Yes' : 'No'}

          Output format: Markdown. Use bold verbs (e.g., **HIDE**, **MEMORIZE**). Max 5 distinct steps.
        `;
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash',
          contents: prompt,
        });
        if (response.text) return response.text;
      } catch (error) {
        console.warn("Safety plan offline.");
      }
    }

    // 2. Offline Logic Generator (Enhanced for "Real Solutions")
    let plan = `### Tactical Safety Action Plan (Offline)\n\n`;

    plan += `**1. IMMEDIATE SECURITY:**\n- Memorize the National Helpline: **1195**.\n- Keep your phone charged above 50% at all times.\n- Delete your call history after seeking help.\n\n`;

    if (inputs.livingSituation === 'Living with abuser') {
      plan += `**2. HOME STRATEGY:**\n- Identify the "Safe Room" (one with a lock and window, NO knives/tools).\n- Practice walking to the exit in the dark.\n- Keep a spare set of house keys hidden outside or with a neighbor.\n\n`;
    } else {
       plan += `**2. PERIMETER SECURITY:**\n- Change all locks immediately.\n- Install a motion-sensor light (solar ones are cheap) at the entry.\n- Vary your route home from work/market.\n\n`;
    }

    if (inputs.hasChildren) {
      plan += `**3. CHILD PROTOCOL:**\n- Teach them the "Code Word" (e.g., "Blueberry"). When they hear it, they must run to [Neighbor/Shop] immediately.\n- Pack a small bag for them with 1 toy, 1 change of clothes, and their birth certificates. Hide it.\n\n`;
    }

    if (inputs.accessToMoney === 'No access' || inputs.accessToMoney === 'Shared accounts') {
      plan += `**4. FINANCIAL EXTRACTION:**\n- Start skimming "change" from grocery shopping. Hide cash in a sanitary pad box or inside a curtain hem.\n- Photograph all financial documents (Title deeds, ID, Logbooks) and email them to a secret email address.\n\n`;
    } else {
      plan += `**4. FINANCIAL RESERVES:**\n- Open a mobile money account (M-PESA) using a new SIM card the abuser doesn't know about.\n- Keep transport fare for a taxi/bus in your shoe or bra at all times.\n\n`;
    }

    if (inputs.trustedContact) {
      plan += `**5. COMMUNICATION WEB:**\n- Establish a "Silent Signal" with your contact (e.g., 3 missed calls in a row = Call Police).\n- Share your live location on WhatsApp for 8 hours if you feel tension rising.\n\n`;
    } else {
      plan += `**5. SAFE HAVEN:**\n- Identify a 24-hour location (Hospital, Petrol Station, Police Station) you can run to.\n- Call 1195 to get a case worker assigned who can be your contact.\n\n`;
    }

    return plan;
  }
};

