export const GeminiService = {

  // --- CHAT API ---

  createChat(): Chat | null {
    if (ai) {
      try {
        return ai.chats.create({
          model: 'gemini-2.5-flash',
          config: {
            systemInstruction: `You are SafeVoice AI, an expert Crisis Response Specialist.
            - Your Priority: Victim Safety.
            - Tone: Empathetic, Direct, Action-Oriented.
            - Rule: Provide concrete steps (e.g., "Go to X", "Call Y").
            - Context: You are in Kenya. Refer to 1195 (Helpline), Police Gender Desks, and GVRCs (Gender Violence Recovery Centers).
            - Brevity: Keep responses short and readable on mobile.`
          }
        });
      } catch (e) {
        console.error("Failed to create chat session", e);
        return null;
      }
    }
    return null;
  },

  // Fallback for when the Chat object isn't available or fails
  getOfflineResponse(userText: string): string {
    const lowerInput = userText.toLowerCase();

    // 1. Check for specific keywords
    const keys = Object.keys(CHAT_KEYWORDS).sort((a, b) => b.length - a.length);
    for (const key of keys) {
      if (lowerInput.includes(key)) {
        return CHAT_KEYWORDS[key];
      }
    }

    // 2. Rotate through generic helpful messages if no keyword matches
    // This prevents the "same message" fatigue
    const randomIndex = Math.floor(Math.random() * FALLBACK_RESPONSES.length);
    return FALLBACK_RESPONSES[randomIndex];
  },

  // --- CONTENT GENERATION API ---

  async generateQuizForTopic(topic: string): Promise<QuizQuestion[]> {
    if (ai) {
      try {
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash',
          contents: `Create a simple 3-question multiple choice quiz about "${topic}" related to Gender Based Violence awareness. Return JSON only.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: { type: Type.ARRAY, items: { type: Type.STRING } },
                  correctIndex: { type: Type.INTEGER }
                }
              }
            }
          }
        });
        if (response.text) return JSON.parse(response.text);
      } catch (error) {
        // Fall through to offline
      }
    }
    return LOCAL_QUIZ_DB[topic] || LOCAL_QUIZ_DB["What is GBV?"];
  },

  async generateSafetyPlan(inputs: any): Promise<string> {
    if (ai) {
      try {
        const prompt = `Create a tactical safety plan for a victim. Context: ${JSON.stringify(inputs)}. 
        Format: Markdown. 5 Steps. Bold verbs.`;
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash',
          contents: prompt,
        });
        if (response.text) return response.text;
      } catch (error) {
        // Fall through
      }
    }

    // Simple Offline Plan Generator
    return `### Safety Plan (Offline Mode)

    **1. Emergency Contacts:**
    - Memorize 1195 (National Helpline).

    **2. Safe Word:**
    - Pick a word like "Blueberry". Tell your ${inputs.hasChildren ? 'children' : 'neighbors'} to call for help when they hear it.

    **3. Escape Route:**
    - Identify the safest exit (door/window) that is not blocked.

    **4. Essentials Bag:**
    - Pack ID, ${inputs.accessToMoney === 'No access' ? 'hidden cash' : 'bank cards'}, and medicines. Hide it near the door.

    **5. Technology:**
    - Delete this app history if your phone is monitored.`;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { GeminiService } from '../services/geminiService';
import { Send, Bot, Loader2, ShieldCheck, AlertTriangle } from 'lucide-react';
import { Chat } from "@google/genai";

interface Message {
  id: string;
  text: string;
  sender: 'user' | 'bot';
  timestamp: Date;
}

export const ChatView: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      text: "Hello. I am SafeVoice AI. I am here to listen and provide guidance anonymously. I can help with legal rights, medical advice, or safety planning. How can I help you today?",
      sender: 'bot',
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Store the chat session instance
  const chatSession = useRef<Chat | null>(null);

  // Initialize Chat Session on Mount
  useEffect(() => {
    const session = GeminiService.createChat();
    if (session) {
      chatSession.current = session;
    }
  }, []);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(scrollToBottom, [messages]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || loading) return;

    const userText = input;
    const userMsg: Message = {
      id: Date.now().toString(),
      text: userText,
      sender: 'user',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      let botText = "";

      // 1. Try to use the Online Chat Session
      if (chatSession.current) {
        try {
          const result = await chatSession.current.sendMessage({ message: userText });
          botText = result.text || "";
        } catch (apiError) {
          console.warn("Online chat failed, switching to offline logic for this turn.");
          botText = GeminiService.getOfflineResponse(userText);
        }
      } else {
        // 2. Fallback if session initialization failed (e.g. no API key)
        botText = GeminiService.getOfflineResponse(userText);
      }

      // Ensure we have a response
      if (!botText) {
         botText = "I'm having trouble connecting. Please try again or check the Hotlines section for immediate help.";
      }

      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        text: botText,
        sender: 'bot',
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMsg]);

    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-gray-100 dark:bg-gray-900 pb-20 animate-slide-up">
      {/* Header */}
      <div className="bg-white dark:bg-gray-800 p-4 border-b border-gray-200 dark:border-gray-700 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-indigo-100 dark:bg-indigo-900/30 flex items-center justify-center">
            <Bot className="w-6 h-6 text-indigo-600 dark:text-indigo-400" />
          </div>
          <div>
            <h1 className="font-bold text-gray-800 dark:text-white">Safe Chat</h1>
            <div className="flex items-center text-xs text-green-500">
              <span className="w-2 h-2 bg-green-500 rounded-full mr-1"></span>
              Online • Anonymous
            </div>
          </div>
        </div>
        <ShieldCheck className="w-6 h-6 text-gray-400" />
      </div>

      {/* Safety Banner */}
      <div className="bg-yellow-50 dark:bg-yellow-900/10 p-2 text-center text-xs text-yellow-700 dark:text-yellow-500 flex items-center justify-center gap-2">
         <AlertTriangle className="w-3 h-3" />
         <span>Messages are not monitored by humans. In danger? Call 1195.</span>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div className={`max-w-[85%] p-3 rounded-2xl text-sm leading-relaxed ${
              msg.sender === 'user' 
              ? 'bg-brand-600 text-white rounded-tr-none' 
              : 'bg-white dark:bg-gray-800 text-gray-800 dark:text-gray-200 rounded-tl-none border border-gray-200 dark:border-gray-700'
            }`}>
              {/* Simple Markdown Rendering for Lists */}
              {msg.text.split('\n').map((line, i) => (
                <p key={i} className={`min-h-[1em] ${line.trim().startsWith('-') ? 'ml-4 list-disc' : ''}`}>
                   {line}
                </p>
              ))}
            </div>
          </div>
        ))}
        {loading && (
           <div className="flex justify-start">
             <div className="bg-white dark:bg-gray-800 p-3 rounded-2xl rounded-tl-none border border-gray-200 dark:border-gray-700">
               <Loader2 className="w-5 h-5 animate-spin text-gray-400" />
             </div>
           </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="p-4 bg-white dark:bg-gray-800 border-t border-gray-200 dark:border-gray-700">
        <form onSubmit={handleSend} className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Type a message..."
            className="flex-1 p-3 rounded-xl bg-gray-100 dark:bg-gray-700 border-none outline-none focus:ring-2 focus:ring-brand-500 dark:text-white"
          />
          <button 
            type="submit" 
            disabled={!input.trim() || loading}
            className="bg-brand-600 text-white p-3 rounded-xl disabled:opacity-50 hover:bg-brand-700 transition-colors shadow-lg shadow-brand-500/30"
          >
            <Send className="w-5 h-5" />
          </button>
        </form>
      </div>
    </div>
  );
};

