export const BackendService = {

  // --- REAL BACKEND API INTEGRATION ---

  async createReport(data: any): Promise<Report> {
    const formData = new FormData();
    formData.append('type', data.type);
    formData.append('location', data.location);
    formData.append('description', data.description);
    if(data.anonymousUserId) formData.append('anonymousUserId', data.anonymousUserId);

    if (data.attachments && data.attachments.length > 0) {
      data.attachments.forEach((att: any) => {
          if (att.file) {
              formData.append('attachments', att.file);
          }
      });
    }

    try {
      const response = await fetch(`${API_URL}/api/gbv-report`, {
          method: 'POST',
          body: formData
      });

      if (!response.ok) throw new Error('Backend error: ' + response.statusText);

      const result = await response.json();

      // Save tracking code to user's local history
      if (result.trackingCode) {
         this.addToHistory(result.trackingCode);
         // Return a constructed report object for the UI to use immediately
         return {
             ...data,
             id: 'temp', 
             trackingCode: result.trackingCode,
             status: ReportStatus.RECEIVED,
             createdAt: new Date().toISOString()
         } as Report;
      }
      throw new Error("No tracking code received");
    } catch (error) {
      console.error("Failed to submit report", error);
      throw error;
    }
  },

  async getReportByCode(code: string): Promise<Report | null> {
    try {
        const response = await fetch(`${API_URL}/api/gbv-report/${code}`);
        if (response.status === 404) return null;
        if (!response.ok) throw new Error("Network error");
        return await response.json();
    } catch (e) {
        console.error("Fetch error", e);
        return null;
    }
  },

  // --- ADMIN API ---

  async adminLogin(email: string, password: string): Promise<boolean> {
    try {
        const response = await fetch(`${API_URL}/api/admin/login`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ email, password })
        });

        if (response.ok) {
            const data = await response.json();
            localStorage.setItem(STORAGE_KEY_ADMIN_TOKEN, data.token);
            return true;
        }
        return false;
    } catch (e) {
        return false;
    }
  },

  async getAllReports(): Promise<Report[]> {
    const token = localStorage.getItem(STORAGE_KEY_ADMIN_TOKEN);
    if (!token) return [];

    try {
        const response = await fetch(`${API_URL}/api/admin/reports`, {
            headers: { 'Authorization': `Bearer ${token}` }
        });
        if (!response.ok) return [];
        return await response.json();
    } catch (e) {
        return [];
    }
  },

  async updateReportStatus(id: string, status: ReportStatus): Promise<void> {
    const token = localStorage.getItem(STORAGE_KEY_ADMIN_TOKEN);
    if (!token) throw new Error("Unauthorized");

    const response = await fetch(`${API_URL}/api/admin/reports/${id}`, {
        method: 'PATCH',
        headers: { 
            'Authorization': `Bearer ${token}`,
            'Content-Type': 'application/json'
        },
        body: JSON.stringify({ status })
    });

    if (!response.ok) throw new Error("Failed to update status");
  },

  async addCaseUpdate(reportId: string, content: string): Promise<CaseUpdate> {
    const token = localStorage.getItem(STORAGE_KEY_ADMIN_TOKEN);
    if (!token) throw new Error("Unauthorized");

    const response = await fetch(`${API_URL}/api/admin/reports/${reportId}/message`, {
        method: 'POST',
        headers: { 
            'Authorization': `Bearer ${token}`,
            'Content-Type': 'application/json'
        },
        body: JSON.stringify({ content })
    });

    if (!response.ok) throw new Error("Failed to send update");
    return await response.json();
  },

  // --- INTERNAL HELPERS (History Client-Side Only) ---

  addToHistory(code: string) {
    const history = JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
    if (!history.includes(code)) {
      history.unshift(code);
      localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(history));
    }
  },

  getHistory(): string[] {
    return JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
  },

  // --- STATIC DATA ---

  async getEducationModules(): Promise<EducationModule[]> {
    return MOCK_EDUCATION;
  },

  async getHotlines(): Promise<Hotline[]> {
    return MOCK_HOTLINES;
