  async getSupportCentres(lat: number, lng: number): Promise<SupportCentre[]> {
    if (lat === 0 && lng === 0) {
        return MOCK_CENTRES_DB.map(c => ({
            ...c,
            distance: 'Unknown distance',
            id: c.id
        }));
    }

    const sorted = MOCK_CENTRES_DB.map(center => {
        const dist = calculateDistance(lat, lng, center.lat, center.lng);
        return {
            ...center,
            distance: `${dist.toFixed(1)} km`,
            rawDist: dist
        };
    }).sort((a, b) => a.rawDist - b.rawDist);

    return sorted;
  }
};

/**
 * SafeVoice Backend API (MariaDB Version)
 * 
 * Instructions:
 * 1. Install dependencies: npm install
 * 2. Setup MariaDB and ensure 'reports' table has 'case_updates' (JSON) column
 * 3. Configure .env with DB credentials
 * 4. Run: npm start
 */

require('dotenv').config();
const express = require('express');
const cors = require('cors');
const multer = require('multer');
const jwt = require('jsonwebtoken');
const { v4: uuidv4 } = require('uuid');
const path = require('path');
const mariadb = require('mariadb');

const app = express();
const PORT = process.env.PORT || 3000;
const SECRET_KEY = process.env.SECRET_KEY || 'safevoice-super-secret-key';

// --- MariaDB Connection Pool ---
const pool = mariadb.createPool({
  host: process.env.DB_HOST || 'localhost', 
  user: process.env.DB_USER || 'root', 
  password: process.env.DB_PASSWORD || 'password',
  database: process.env.DB_NAME || 'safevoice_db',
  connectionLimit: 5
});

// Middleware
app.use(cors());
app.use(express.json());

// Serve Uploads
app.use('/uploads', express.static(path.join(__dirname, 'uploads')));

// Serve Admin Dashboard (Static Files)
app.use('/admin', express.static(path.join(__dirname, 'public')));

// Storage Setup
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, 'uploads/');
  },
  filename: (req, file, cb) => {
    cb(null, Date.now() + '-' + file.originalname);
  }
});
const upload = multer({ storage });

const ADMIN_CREDENTIALS = {
  email: 'admin@safevoice.org',
  password: 'admin123' 
};

// --- Middleware: Authenticate Admin ---
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) return res.sendStatus(401);

  jwt.verify(token, SECRET_KEY, (err, user) => {
    if (err) return res.sendStatus(403);
    req.user = user;
    next();
  });
};

// --- Helper: Format DB Row to API Object ---
const formatReport = (row) => ({
  id: row.id,
  trackingCode: row.tracking_code,
  type: row.type,
  location: row.location,
  description: row.description,
  anonymousUserId: row.anonymous_user_id,
  status: row.status,
  createdAt: row.created_at,
  // Parse JSON columns back to objects. Handle strings or pre-parsed objects.
  attachments: typeof row.attachments === 'string' ? JSON.parse(row.attachments) : (row.attachments || []),
  statusHistory: typeof row.status_history === 'string' ? JSON.parse(row.status_history) : (row.status_history || []),
  caseUpdates: typeof row.case_updates === 'string' ? JSON.parse(row.case_updates) : (row.case_updates || [])
});

// --- Routes ---

// 1. Submit Report (Anonymous)
app.post('/api/gbv-report', upload.array('attachments'), async (req, res) => {
  const { type, location, description, anonymousUserId } = req.body;

  if (!type || !location || !description) {
    return res.status(400).json({ error: 'Missing required fields' });
  }

  const id = uuidv4();
  const trackingCode = `SV-${Math.floor(1000 + Math.random() * 9000)}-${new Date().getFullYear()}`;
  const userId = anonymousUserId || uuidv4();
  const status = 'Received';
  const createdAt = new Date();

  const attachments = req.files ? req.files.map(f => ({
    name: f.originalname,
    type: f.mimetype.split('/')[0],
    url: `${req.protocol}://${req.get('host')}/uploads/${f.filename}` 
  })) : [];

  const statusHistory = [{ status: 'Received', timestamp: createdAt.toISOString() }];
  const caseUpdates = [];

  let conn;
  try {
    conn = await pool.getConnection();
    // Ensure 'case_updates' column exists in your DB schema
    const query = `
      INSERT INTO reports 
      (id, tracking_code, type, location, description, anonymous_user_id, status, created_at, attachments, status_history, case_updates) 
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `;

    await conn.query(query, [
      id, 
      trackingCode, 
      type, 
      location, 
      description, 
      userId, 
      status, 
      createdAt, 
      JSON.stringify(attachments), 
      JSON.stringify(statusHistory),
      JSON.stringify(caseUpdates)
    ]);

    console.log(`[MariaDB] New Report: ${trackingCode}`);
    res.status(201).json({ message: 'Report submitted', trackingCode });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Database error. Ensure DB schema has all columns including case_updates.' });
  } finally {
    if (conn) conn.release();
  }
});

// 2. Track Report (Public)
app.get('/api/gbv-report/:trackingCode', async (req, res) => {
  const { trackingCode } = req.params;
  let conn;
  try {
    conn = await pool.getConnection();
    const rows = await conn.query("SELECT * FROM reports WHERE tracking_code = ?", [trackingCode]);

    if (rows.length === 0) return res.status(404).json({ error: 'Report not found' });

    const report = formatReport(rows[0]);

    // Return privacy-safe data to user
    res.json({
      trackingCode: report.trackingCode,
      status: report.status,
      statusHistory: report.statusHistory,
      caseUpdates: report.caseUpdates, // Include messaging for user
      createdAt: report.createdAt,
      description: report.description 
    });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Database error' });
  } finally {
    if (conn) conn.release();
  }
});

// 3. Admin Login
app.post('/api/admin/login', (req, res) => {
  const { email, password } = req.body;
  if (email === ADMIN_CREDENTIALS.email && password === ADMIN_CREDENTIALS.password) {
    const token = jwt.sign({ email }, SECRET_KEY, { expiresIn: '12h' });
    res.json({ token });
  } else {
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

// 4. Admin: Get All Reports
app.get('/api/admin/reports', authenticateToken, async (req, res) => {
  let conn;
  try {
    conn = await pool.getConnection();
    const rows = await conn.query("SELECT * FROM reports ORDER BY created_at DESC");
    const reports = rows.map(formatReport);
    res.json(reports);
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Database error' });
  } finally {
    if (conn) conn.release();
  }
});

// 5. Admin: Get Single Report
app.get('/api/admin/reports/:id', authenticateToken, async (req, res) => {
  let conn;
  try {
    conn = await pool.getConnection();
    const rows = await conn.query("SELECT * FROM reports WHERE id = ?", [req.params.id]);
    if (rows.length === 0) return res.status(404).json({ error: 'Not found' });
    res.json(formatReport(rows[0]));
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Database error' });
  } finally {
    if (conn) conn.release();
  }
});

// 6. Admin: Update Status
app.patch('/api/admin/reports/:id', authenticateToken, async (req, res) => {
  const { status } = req.body;
  const { id } = req.params;
  let conn;
  try {
    conn = await pool.getConnection();

    const rows = await conn.query("SELECT status_history FROM reports WHERE id = ?", [id]);
    if (rows.length === 0) return res.status(404).json({ error: 'Report not found' });

    let history = typeof rows[0].status_history === 'string' ? JSON.parse(rows[0].status_history) : rows[0].status_history;
    if (!history) history = [];

    history.push({ status, timestamp: new Date().toISOString() });

    await conn.query(
      "UPDATE reports SET status = ?, status_history = ? WHERE id = ?", 
      [status, JSON.stringify(history), id]
    );

    res.json({ id, status, statusHistory: history });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Database error' });
  } finally {
    if (conn) conn.release();
  }
});

// 7. Admin: Add Message / Case Update
app.post('/api/admin/reports/:id/message', authenticateToken, async (req, res) => {
  const { content } = req.body;
  const { id } = req.params;
  let conn;
  try {
    conn = await pool.getConnection();
    const rows = await conn.query("SELECT case_updates FROM reports WHERE id = ?", [id]);
    if (rows.length === 0) return res.status(404).json({ error: 'Report not found' });

    let updates = typeof rows[0].case_updates === 'string' ? JSON.parse(rows[0].case_updates) : rows[0].case_updates;
    if (!updates) updates = [];

    const newUpdate = {
        id: uuidv4(),
        content,
        timestamp: new Date().toISOString(),
        author: 'Case Worker' 
    };
    updates.push(newUpdate);

    await conn.query("UPDATE reports SET case_updates = ? WHERE id = ?", [JSON.stringify(updates), id]);
    res.json(newUpdate);
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Database error' });
  } finally {
    if (conn) conn.release();
  }
});

app.listen(PORT, () => {
  console.log(`SafeVoice Backend running on http://localhost:${PORT}`);
});

import React, { useState, useEffect } from 'react';
import { Report, ReportStatus, GBVType } from '../types';
import { BackendService } from '../services/mockBackend';
import { 
  LayoutDashboard, LogOut, Search, Filter, Eye, 
  MoreHorizontal, Calendar, MapPin, CheckCircle2, 
  AlertCircle, Clock, X, Save, MessageSquare, Send, ChevronRight, ChevronDown, Loader2, RefreshCw
} from 'lucide-react';

export const AdminDashboard: React.FC<{ onLogout: () => void }> = ({ onLogout }) => {
  const [reports, setReports] = useState<Report[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedReport, setSelectedReport] = useState<Report | null>(null);
  const [filterStatus, setFilterStatus] = useState<string>('All');
  const [searchTerm, setSearchTerm] = useState('');
  const [lastRefreshed, setLastRefreshed] = useState(new Date());

  // New state for status update workflow
  const [draftStatus, setDraftStatus] = useState<ReportStatus | null>(null);
  const [statusNote, setStatusNote] = useState('');
  const [isUpdatingStatus, setIsUpdatingStatus] = useState(false);

  // Existing state for standalone update message
  const [newUpdate, setNewUpdate] = useState('');
  const [sendingUpdate, setSendingUpdate] = useState(false);

  // Fetch data function
  const refreshData = async (silent = false) => {
    if (!silent) setLoading(true);
    const data = await BackendService.getAllReports();
    // Sort by newest first
    const sorted = data.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
    setReports(sorted);
    setLastRefreshed(new Date());
    if (!silent) setLoading(false);
  };

  useEffect(() => {
    refreshData();
    // Auto-refresh every 10 seconds to sync with other admins
    const interval = setInterval(() => {
        refreshData(true);
    }, 10000);
    return () => clearInterval(interval);
  }, []);

  // Sync draft status when selected report changes
  useEffect(() => {
    if (selectedReport) {
      setDraftStatus(selectedReport.status);
      setStatusNote('');
      // Update the selected report object from the fresh list if it exists to show new messages
      const freshVersion = reports.find(r => r.id === selectedReport.id);
      if (freshVersion && JSON.stringify(freshVersion) !== JSON.stringify(selectedReport)) {
          setSelectedReport(freshVersion);
      }
    }
  }, [selectedReport, reports]);

  const handleSaveStatus = async () => {
    if (!selectedReport || !draftStatus) return;

    setIsUpdatingStatus(true);
    try {
        let updateMade = false;

        // 1. Update Status if changed
        if (draftStatus !== selectedReport.status) {
            await BackendService.updateReportStatus(selectedReport.id, draftStatus);
            updateMade = true;
        }

        // 2. Add Message if exists
        if (statusNote.trim()) {
            // Add context if status changed
            const context = draftStatus !== selectedReport.status 
                ? `[Status: ${draftStatus}] ` 
                : '';

            await BackendService.addCaseUpdate(selectedReport.id, context + statusNote);
            updateMade = true;
        }

        if (updateMade) {
            await refreshData(true); // Fetch fresh data to get updated timestamps/server info
            setStatusNote('');
            alert("Case updated successfully");
        }
    } catch (e) {
        alert("Failed to update case");
    } finally {
        setIsUpdatingStatus(false);
