  "thank": "You are strong. Please stay safe. We are here if you need more info."
};

export const GeminiService = {

  // --- CHAT API ---

  createChat(): Chat | null {
    if (ai) {
      try {
        return ai.chats.create({
          model: 'gemini-2.5-flash',
          config: {
            tools: [{ googleSearch: {} }], // ENABLED INTERNET ACCESS for real answers
            systemInstruction: `You are SafeVoice AI, an advanced Crisis Response Specialist.
            - MISSION: Provide immediate, accurate, and life-saving information to victims of Gender-Based Violence (GBV).
            - CAPABILITIES: You have access to Google Search. Use it to find open shelters, legal aid contacts, and hospital hours in the user's location if asked.
            - TONE: Empathetic, calm, direct, and authoritative on safety matters.
            - SAFETY FIRST: If a user is in danger, prioritize getting them to physical safety (Police, Hospital, Safe House).
            - LOCAL CONTEXT: Assume the context is Kenya unless specified otherwise (Ref: 1195 Helpline, Gender Desks).
            - FORMAT: Use bullet points for steps. Keep it readable on mobile.`
          }
        });
      } catch (e) {
        console.error("Failed to create chat session", e);
        return null;
      }
    }
    return null;
  },

  // Fallback for when the Chat object isn't available or fails
  getOfflineResponse(userText: string): string {
    const lowerInput = userText.toLowerCase();

    // 1. Check for specific keywords
    const keys = Object.keys(CHAT_KEYWORDS).sort((a, b) => b.length - a.length);
    for (const key of keys) {
      if (lowerInput.includes(key)) {
        return CHAT_KEYWORDS[key];
      }
    }

    // 2. Rotate through generic helpful messages if no keyword matches
    const randomIndex = Math.floor(Math.random() * FALLBACK_RESPONSES.length);
    return FALLBACK_RESPONSES[randomIndex];
  },

  // --- CONTENT GENERATION API ---

  async generateQuizForTopic(topic: string): Promise<QuizQuestion[]> {
    if (ai) {
      try {
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash',
          contents: `Create a simple 3-question multiple choice quiz about "${topic}" related to Gender Based Violence awareness. Return JSON only.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: { type: Type.ARRAY, items: { type: Type.STRING } },
                  correctIndex: { type: Type.INTEGER }
                }
              }
            }
          }
        });
        if (response.text) return JSON.parse(response.text);
      } catch (error) {
        // Fall through to offline
      }
    }
    return LOCAL_QUIZ_DB[topic] || LOCAL_QUIZ_DB["What is GBV?"];
  },

  async generateSafetyPlan(inputs: any): Promise<string> {
    if (ai) {
      try {
        const prompt = `Create a tactical safety plan for a victim. Context: ${JSON.stringify(inputs)}. 
        Format: Markdown. 5 Steps. Bold verbs.`;
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash',
          contents: prompt,
        });
        if (response.text) return response.text;
      } catch (error) {
        // Fall through
      }
    }

    // Simple Offline Plan Generator
    return `### Safety Plan (Offline Mode)

    **1. Emergency Contacts:**
    - Memorize 1195 (National Helpline).

    **2. Safe Word:**
    - Pick a word like "Blueberry". Tell your ${inputs.hasChildren ? 'children' : 'neighbors'} to call for help when they hear it.

    **3. Escape Route:**
    - Identify the safest exit (door/window) that is not blocked.

    **4. Essentials Bag:**
    - Pack ID, ${inputs.accessToMoney === 'No access' ? 'hidden cash' : 'bank cards'}, and medicines. Hide it near the door.

    **5. Technology:**
    - Delete this app history if your phone is monitored.`;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { GeminiService } from '../services/geminiService';
import { Send, Bot, Loader2, ShieldCheck, AlertTriangle, ExternalLink, Globe } from 'lucide-react';
import { Chat } from "@google/genai";

interface Message {
  id: string;
  text: string;
  sender: 'user' | 'bot';
  timestamp: Date;
  sources?: { title: string; uri: string }[];
}

export const ChatView: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      text: "Hello. I am SafeVoice AI. I am connected to the internet to find you real-time help (shelters, laws, hospitals). I am here to listen and provide guidance anonymously. How can I help you today?",
      sender: 'bot',
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Store the chat session instance
  const chatSession = useRef<Chat | null>(null);

  // Initialize Chat Session on Mount
  useEffect(() => {
    const session = GeminiService.createChat();
    if (session) {
      chatSession.current = session;
    }
  }, []);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(scrollToBottom, [messages]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || loading) return;

    const userText = input;
    const userMsg: Message = {
      id: Date.now().toString(),
      text: userText,
      sender: 'user',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      let botText = "";
      let sources: { title: string; uri: string }[] = [];

      // 1. Try to use the Online Chat Session
      if (chatSession.current) {
        try {
          const result = await chatSession.current.sendMessage({ message: userText });
          botText = result.text || "";

          // Extract Grounding Metadata (Search Results)
          const grounding = result.candidates?.[0]?.groundingMetadata;
          if (grounding?.groundingChunks) {
            grounding.groundingChunks.forEach((chunk: any) => {
               if (chunk.web) {
                 sources.push({ title: chunk.web.title, uri: chunk.web.uri });
               }
            });
          }

        } catch (apiError) {
          console.warn("Online chat failed, switching to offline logic for this turn.", apiError);
          botText = GeminiService.getOfflineResponse(userText);
        }
      } else {
        // 2. Fallback if session initialization failed (e.g. no API key)
        botText = GeminiService.getOfflineResponse(userText);
      }

      // Ensure we have a response
      if (!botText) {
         botText = "I'm having trouble connecting to the internet. Here is general advice: Call 1195 for immediate help.";
      }

      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        text: botText,
        sender: 'bot',
        timestamp: new Date(),
        sources: sources.length > 0 ? sources : undefined
      };
      setMessages(prev => [...prev, botMsg]);

    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-gray-100 dark:bg-gray-900 pb-20 animate-slide-up">
      {/* Header */}
      <div className="bg-white dark:bg-gray-800 p-4 border-b border-gray-200 dark:border-gray-700 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-indigo-100 dark:bg-indigo-900/30 flex items-center justify-center">
            <Bot className="w-6 h-6 text-indigo-600 dark:text-indigo-400" />
          </div>
          <div>
            <h1 className="font-bold text-gray-800 dark:text-white">Safe Chat</h1>
            <div className="flex items-center text-xs text-green-500">
              <span className="w-2 h-2 bg-green-500 rounded-full mr-1"></span>
              Live Intelligence Active
            </div>
          </div>
        </div>
        <ShieldCheck className="w-6 h-6 text-gray-400" />
      </div>

      {/* Safety Banner */}
      <div className="bg-yellow-50 dark:bg-yellow-900/10 p-2 text-center text-xs text-yellow-700 dark:text-yellow-500 flex items-center justify-center gap-2">
         <AlertTriangle className="w-3 h-3" />
         <span>Messages are not monitored by humans. In danger? Call 1195.</span>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex flex-col ${msg.sender === 'user' ? 'items-end' : 'items-start'}`}
          >
            <div className={`max-w-[85%] p-3 rounded-2xl text-sm leading-relaxed ${
              msg.sender === 'user' 
              ? 'bg-brand-600 text-white rounded-tr-none' 
              : 'bg-white dark:bg-gray-800 text-gray-800 dark:text-gray-200 rounded-tl-none border border-gray-200 dark:border-gray-700'
            }`}>
              {/* Simple Markdown Rendering for Lists */}
              {msg.text.split('\n').map((line, i) => (
                <p key={i} className={`min-h-[1em] ${line.trim().startsWith('-') ? 'ml-4 list-disc' : ''}`}>
                   {line}
                </p>
              ))}
            </div>

            {/* Display Sources if available */}
            {msg.sources && msg.sources.length > 0 && (
              <div className="mt-2 max-w-[85%]">
                <p className="text-[10px] text-gray-500 uppercase font-bold mb-1 flex items-center gap-1">
                  <Globe className="w-3 h-3" /> Sources Found
                </p>
                <div className="flex flex-wrap gap-2">
                  {msg.sources.map((source, idx) => (
                    <a 
                      key={idx}
                      href={source.uri}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="text-xs bg-indigo-50 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-300 px-2 py-1 rounded-md border border-indigo-100 dark:border-indigo-800 flex items-center gap-1 hover:underline"
                    >
                      {source.title || 'Source'} <ExternalLink className="w-3 h-3" />
                    </a>
                  ))}
                </div>
              </div>
            )}

          </div>
        ))}
        {loading && (
           <div className="flex justify-start">
             <div className="bg-white dark:bg-gray-800 p-3 rounded-2xl rounded-tl-none border border-gray-200 dark:border-gray-700">
               <Loader2 className="w-5 h-5 animate-spin text-gray-400" />
             </div>
           </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="p-4 bg-white dark:bg-gray-800 border-t border-gray-200 dark:border-gray-700">
        <form onSubmit={handleSend} className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask anything (e.g., 'shelters near me')..."
            className="flex-1 p-3 rounded-xl bg-gray-100 dark:bg-gray-700 border-none outline-none focus:ring-2 focus:ring-brand-500 dark:text-white"
          />
          <button 
            type="submit" 
            disabled={!input.trim() || loading}
            className="bg-brand-600 text-white p-3 rounded-xl disabled:opacity-50 hover:bg-brand-700 transition-colors shadow-lg shadow-brand-500/30"
          >
            <Send className="w-5 h-5" />
          </button>
        </form>
      </div>
    </div>
  );
};

/**
 * SafeVoice Backend API (MariaDB Version) - Scaled for 100+ Devices
 */

require('dotenv').config();
const express = require('express');
const cors = require('cors');
const multer = require('multer');
const jwt = require('jsonwebtoken');
const { v4: uuidv4 } = require('uuid');
const path = require('path');
const mariadb = require('mariadb');
const fs = require('fs');

const app = express();
const PORT = process.env.PORT || 3000;
const SECRET_KEY = process.env.SECRET_KEY || 'safevoice-super-secret-key';

// --- Ensure Upload Directory Exists (Prevents Crash on First Report) ---
const uploadDir = path.join(__dirname, 'uploads');
if (!fs.existsSync(uploadDir)){
    fs.mkdirSync(uploadDir, { recursive: true });
    console.log('Created uploads directory.');
}

// --- MariaDB Connection Pool (Scaled) ---
// increased limit to 50 to handle concurrent requests from 100+ devices
const pool = mariadb.createPool({
  host: process.env.DB_HOST || 'localhost', 
  user: process.env.DB_USER || 'root', 
  password: process.env.DB_PASSWORD || 'password',
  database: process.env.DB_NAME || 'safevoice_db',
  connectionLimit: 50 
});

// Middleware
app.use(cors());
app.use(express.json());

// Serve Uploads
app.use('/uploads', express.static(uploadDir));

// Serve Admin Dashboard (Static Files)
app.use('/admin', express.static(path.join(__dirname, 'public')));

// Storage Setup
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, 'uploads/');
  },
  filename: (req, file, cb) => {
    // Sanitize filename for safety
    const safeName = file.originalname.replace(/[^a-zA-Z0-9.]/g, '_');
    cb(null, `${Date.now()}-${safeName}`);
  }
});
const upload = multer({ storage });

const ADMIN_CREDENTIALS = {
  email: 'admin@safevoice.org',
  password: 'admin123' 
};

// --- Middleware: Authenticate Admin ---
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) return res.sendStatus(401);

  jwt.verify(token, SECRET_KEY, (err, user) => {
    if (err) return res.sendStatus(403);
    req.user = user;
    next();
  });
};

// --- Helper: Format DB Row to API Object ---
const formatReport = (row) => ({
  id: row.id,
  trackingCode: row.tracking_code,
  type: row.type,
  location: row.location,
  description: row.description,
  anonymousUserId: row.anonymous_user_id,
  status: row.status,
  createdAt: row.created_at,
  attachments: typeof row.attachments === 'string' ? JSON.parse(row.attachments) : (row.attachments || []),
  statusHistory: typeof row.status_history === 'string' ? JSON.parse(row.status_history) : (row.status_history || []),
  caseUpdates: typeof row.case_updates === 'string' ? JSON.parse(row.case_updates) : (row.case_updates || [])
});

// --- Routes ---

// 1. Submit Report (Anonymous) - Handles Concurrency
app.post('/api/gbv-report', upload.array('attachments'), async (req, res) => {
  const { type, location, description, anonymousUserId } = req.body;

  if (!type || !location || !description) {
    return res.status(400).json({ error: 'Missing required fields' });
  }

  const id = uuidv4();
  const trackingCode = `SV-${Math.floor(1000 + Math.random() * 9000)}-${new Date().getFullYear()}`;
  const userId = anonymousUserId || uuidv4();
  const status = 'Received';
  const createdAt = new Date();

  // Construct Server URL dynamically based on request to ensure images load on mobile
  const serverBaseUrl = `${req.protocol}://${req.get('host')}`;

  const attachments = req.files ? req.files.map(f => ({
    name: f.originalname,
    type: f.mimetype.split('/')[0],
    url: `${serverBaseUrl}/uploads/${f.filename}` 
  })) : [];

  const statusHistory = [{ status: 'Received', timestamp: createdAt.toISOString() }];
  const caseUpdates = [];

  let conn;
  try {
    conn = await pool.getConnection();
    const query = `
      INSERT INTO reports 
      (id, tracking_code, type, location, description, anonymous_user_id, status, created_at, attachments, status_history, case_updates) 
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `;

    await conn.query(query, [
      id, trackingCode, type, location, description, userId, status, createdAt, 
      JSON.stringify(attachments), JSON.stringify(statusHistory), JSON.stringify(caseUpdates)
    ]);

    console.log(`[New Report] Code: ${trackingCode} | Type: ${type} | Loc: ${location} | Device IP: ${req.ip}`);
    res.status(201).json({ message: 'Report submitted', trackingCode });
  } catch (err) {
    console.error("DB Insert Error:", err);
    res.status(500).json({ error: 'Database error. Please try again.' });
  } finally {
    if (conn) conn.release();
  }
});

// 2. Track Report (Public)
app.get('/api/gbv-report/:trackingCode', async (req, res) => {
  const { trackingCode } = req.params;
  let conn;
  try {
    conn = await pool.getConnection();
    const rows = await conn.query("SELECT * FROM reports WHERE tracking_code = ?", [trackingCode]);

    if (rows.length === 0) return res.status(404).json({ error: 'Report not found' });

    const report = formatReport(rows[0]);
    res.json({
      trackingCode: report.trackingCode,
      status: report.status,
      statusHistory: report.statusHistory,
      caseUpdates: report.caseUpdates,
      createdAt: report.createdAt,
      description: report.description 
    });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Database error' });
  } finally {
    if (conn) conn.release();
  }
});

// 3. Admin Login
app.post('/api/admin/login', (req, res) => {
  const { email, password } = req.body;
  if (email === ADMIN_CREDENTIALS.email && password === ADMIN_CREDENTIALS.password) {
    const token = jwt.sign({ email }, SECRET_KEY, { expiresIn: '12h' });
    console.log(`[Admin Login] ${email} logged in from ${req.ip}`);
    res.json({ token });
  } else {
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

// 4. Admin: Get All Reports (Optimized for Dashboard Polling)
app.get('/api/admin/reports', authenticateToken, async (req, res) => {
  let conn;
  try {
    conn = await pool.getConnection();
    // Fetch only necessary columns for the list view could be an optimization, 
    // but for <1000 reports, SELECT * is fine.
    const rows = await conn.query("SELECT * FROM reports ORDER BY created_at DESC");
    const reports = rows.map(formatReport);
    res.json(reports);
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Database error' });
  } finally {
    if (conn) conn.release();
  }
});

// 5. Admin: Get Single Report
app.get('/api/admin/reports/:id', authenticateToken, async (req, res) => {
  let conn;
  try {
    conn = await pool.getConnection();
    const rows = await conn.query("SELECT * FROM reports WHERE id = ?", [req.params.id]);
    if (rows.length === 0) return res.status(404).json({ error: 'Not found' });
    res.json(formatReport(rows[0]));
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Database error' });
  } finally {
    if (conn) conn.release();
  }
});

// 6. Admin: Update Status
app.patch('/api/admin/reports/:id', authenticateToken, async (req, res) => {
  const { status } = req.body;
  const { id } = req.params;
  let conn;
  try {
    conn = await pool.getConnection();

    const rows = await conn.query("SELECT status_history FROM reports WHERE id = ?", [id]);
    if (rows.length === 0) return res.status(404).json({ error: 'Report not found' });

    let history = typeof rows[0].status_history === 'string' ? JSON.parse(rows[0].status_history) : rows[0].status_history;
    if (!history) history = [];

    history.push({ status, timestamp: new Date().toISOString() });

    await conn.query(
      "UPDATE reports SET status = ?, status_history = ? WHERE id = ?", 
      [status, JSON.stringify(history), id]
    );

    console.log(`[Status Update] Report ${id} -> ${status}`);
    res.json({ id, status, statusHistory: history });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Database error' });
  } finally {
    if (conn) conn.release();
  }
});

// 7. Admin: Add Message / Case Update
app.post('/api/admin/reports/:id/message', authenticateToken, async (req, res) => {
  const { content } = req.body;
  const { id } = req.params;
  let conn;
  try {
    conn = await pool.getConnection();
    const rows = await conn.query("SELECT case_updates FROM reports WHERE id = ?", [id]);
    if (rows.length === 0) return res.status(404).json({ error: 'Report not found' });

    let updates = typeof rows[0].case_updates === 'string' ? JSON.parse(rows[0].case_updates) : rows[0].case_updates;
    if (!updates) updates = [];

    const newUpdate = {
        id: uuidv4(),
        content,
        timestamp: new Date().toISOString(),
        author: 'Case Worker' 
    };
    updates.push(newUpdate);

    await conn.query("UPDATE reports SET case_updates = ? WHERE id = ?", [JSON.stringify(updates), id]);
    res.json(newUpdate);
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Database error' });
  } finally {
    if (conn) conn.release();
  }
});

// Listen on 0.0.0.0 to accept external connections
app.listen(PORT, '0.0.0.0', () => {
  console.log(`\n===================================================`);
  console.log(`✅ SafeVoice SERVER ONLINE: http://0.0.0.0:${PORT}`);
  console.log(`===================================================`);
  console.log(`👉 To connect 100+ devices:`);
  console.log(`   1. Find this computer's LAN IP (e.g. 192.168.1.X)`);
  console.log(`   2. In the App > Admin Login > Server Settings`);
  console.log(`   3. Enter: http://[YOUR_IP]:${PORT}`);
  console.log(`===================================================\n`);
});

import React, { useState, useEffect } from 'react';
import { Report, ReportStatus, GBVType } from '../types';
import { BackendService } from '../services/mockBackend';
import { 
  LayoutDashboard, LogOut, Search, Filter, Eye, 
  MoreHorizontal, Calendar, MapPin, CheckCircle2, 
  AlertCircle, Clock, X, Save, MessageSquare, Send, ChevronRight, ChevronDown, Loader2, RefreshCw, Activity
} from 'lucide-react';

export const AdminDashboard: React.FC<{ onLogout: () => void }> = ({ onLogout }) => {
  const [reports, setReports] = useState<Report[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedReport, setSelectedReport] = useState<Report | null>(null);
  const [filterStatus, setFilterStatus] = useState<string>('All');
  const [searchTerm, setSearchTerm] = useState('');
  const [lastRefreshed, setLastRefreshed] = useState(new Date());

  // New state for status update workflow
  const [draftStatus, setDraftStatus] = useState<ReportStatus | null>(null);
  const [statusNote, setStatusNote] = useState('');
  const [isUpdatingStatus, setIsUpdatingStatus] = useState(false);

  // Existing state for standalone update message
  const [newUpdate, setNewUpdate] = useState('');
  const [sendingUpdate, setSendingUpdate] = useState(false);

  // Fetch data function
  const refreshData = async (silent = false) => {
    if (!silent) setLoading(true);
    const data = await BackendService.getAllReports();
    // Sort by newest first
    const sorted = data.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
    setReports(sorted);
    setLastRefreshed(new Date());
    if (!silent) setLoading(false);
  };

  useEffect(() => {
    refreshData();
    // High-frequency polling (4s) for "Real-Time" feel when handling 100+ devices
    const interval = setInterval(() => {
        refreshData(true);
    }, 4000);
    return () => clearInterval(interval);
  }, []);

  // Sync draft status when selected report changes
  useEffect(() => {
    if (selectedReport) {
      setDraftStatus(selectedReport.status);
      setStatusNote('');
      // Update the selected report object from the fresh list if it exists to show new messages
      const freshVersion = reports.find(r => r.id === selectedReport.id);
      if (freshVersion && JSON.stringify(freshVersion) !== JSON.stringify(selectedReport)) {
          setSelectedReport(freshVersion);
      }
    }
  }, [selectedReport, reports]);

  const handleSaveStatus = async () => {
    if (!selectedReport || !draftStatus) return;

    setIsUpdatingStatus(true);
    try {
        let updateMade = false;

        // 1. Update Status if changed
        if (draftStatus !== selectedReport.status) {
            await BackendService.updateReportStatus(selectedReport.id, draftStatus);
            updateMade = true;
        }

        // 2. Add Message if exists
        if (statusNote.trim()) {
            // Add context if status changed
            const context = draftStatus !== selectedReport.status 
                ? `[Status: ${draftStatus}] ` 
                : '';

            await BackendService.addCaseUpdate(selectedReport.id, context + statusNote);
            updateMade = true;
        }

        if (updateMade) {
            await refreshData(true); // Fetch fresh data to get updated timestamps/server info
            setStatusNote('');
            alert("Case updated successfully");
        }
    } catch (e) {
        alert("Failed to update case");
