import { Report, ReportStatus, GBVType, Attachment, EducationModule, Hotline, SupportCentre, CaseUpdate } from '../types';

const DEFAULT_API_URL = 'http://localhost:3000';
const STORAGE_KEY_API_URL = 'safevoice_api_url';
const STORAGE_KEY_HISTORY = 'safevoice_report_history';
const STORAGE_KEY_ADMIN_TOKEN = 'safevoice_admin_token';
const CACHE_KEY_EDUCATION = 'safevoice_cache_edu';
const CACHE_KEY_HOTLINES = 'safevoice_cache_hotlines';

export const BackendService = {

  getBaseUrl(): string {
    return localStorage.getItem(STORAGE_KEY_API_URL) || DEFAULT_API_URL;
  },

  setBaseUrl(url: string) {
    const cleanUrl = url.replace(/\/$/, ""); 
    localStorage.setItem(STORAGE_KEY_API_URL, cleanUrl);
  },

  // --- REPORTING API ---

  async createReport(data: any): Promise<Report> {
    const formData = new FormData();
    formData.append('type', data.type);
    formData.append('location', data.location);
    formData.append('description', data.description);
    if (data.incidentDate) formData.append('incidentDate', data.incidentDate);
    if (data.anonymousUserId) formData.append('anonymousUserId', data.anonymousUserId);
    if (data.attachments) {
      data.attachments.forEach((att: any) => {
          if (att.file) formData.append('attachments', att.file);
      });
    }

    try {
      const response = await fetch(`${this.getBaseUrl()}/api/gbv-report`, {
          method: 'POST',
          body: formData
      });
      if (!response.ok) throw new Error('Network error');
      const result = await response.json();
      if (result.trackingCode) {
         this.addToHistory(result.trackingCode);
         return { ...data, trackingCode: result.trackingCode, status: ReportStatus.RECEIVED } as Report;
      }
      throw new Error("No tracking code");
    } catch (error) {
      console.error("Submission failed", error);
      throw error;
    }
  },

  async getReportByCode(code: string): Promise<Report | null> {
    try {
        const response = await fetch(`${this.getBaseUrl()}/api/gbv-report/${code}`);
        if (response.status === 404) return null;
        if (!response.ok) throw new Error("Network error");
        return await response.json();
    } catch (e) {
        return null;
    }
  },

  // --- INFORMATION API (With Offline Caching) ---

  async getEducationModules(): Promise<EducationModule[]> {
    try {
      const response = await fetch(`${this.getBaseUrl()}/api/education`);
      if (response.ok) {
        const data = await response.json();
        localStorage.setItem(CACHE_KEY_EDUCATION, JSON.stringify(data)); // Update Cache
        return data;
      }
    } catch (e) {
      console.warn("Using cached education modules");
    }
    // Fallback to cache or empty
    return JSON.parse(localStorage.getItem(CACHE_KEY_EDUCATION) || '[]');
  },

  async getHotlines(): Promise<Hotline[]> {
    try {
      const response = await fetch(`${this.getBaseUrl()}/api/hotlines`);
      if (response.ok) {
        const data = await response.json();
        localStorage.setItem(CACHE_KEY_HOTLINES, JSON.stringify(data));
        return data;
      }
    } catch (e) {
      console.warn("Using cached hotlines");
    }
    return JSON.parse(localStorage.getItem(CACHE_KEY_HOTLINES) || '[]');
  },

  async getSupportCentres(lat: number, lng: number): Promise<SupportCentre[]> {
    try {
      const response = await fetch(`${this.getBaseUrl()}/api/support-centres?lat=${lat}&lng=${lng}`);
      if (response.ok) {
        return await response.json();
      }
    } catch (e) {
      console.warn("Offline: Cannot fetch nearby centers");
    }
    return [];
  },

  // --- ADMIN API ---

  async adminLogin(email: string, password: string): Promise<boolean> {
    try {
        const response = await fetch(`${this.getBaseUrl()}/api/admin/login`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ email, password })
        });
        if (response.ok) {
            const data = await response.json();
            localStorage.setItem(STORAGE_KEY_ADMIN_TOKEN, data.token);
            return true;
        }
        return false;
    } catch (e) {
        return false;
    }
  },

  async getAllReports(): Promise<Report[]> {
    const token = localStorage.getItem(STORAGE_KEY_ADMIN_TOKEN);
    if (!token) return [];
    try {
        const response = await fetch(`${this.getBaseUrl()}/api/admin/reports`, {
            headers: { 'Authorization': `Bearer ${token}` }
        });
        if (!response.ok) return [];
        return await response.json();
    } catch (e) {
        return [];
    }
  },

  async updateReportStatus(id: string, status: ReportStatus): Promise<void> {
    const token = localStorage.getItem(STORAGE_KEY_ADMIN_TOKEN);
    const response = await fetch(`${this.getBaseUrl()}/api/admin/reports/${id}`, {
        method: 'PATCH',
        headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ status })
    });
    if (!response.ok) throw new Error("Failed");
  },

  async addCaseUpdate(reportId: string, content: string): Promise<CaseUpdate> {
    const token = localStorage.getItem(STORAGE_KEY_ADMIN_TOKEN);
    const response = await fetch(`${this.getBaseUrl()}/api/admin/reports/${reportId}/message`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ content })
    });
    if (!response.ok) throw new Error("Failed");
    return await response.json();
  },

  // --- HELPERS ---

  addToHistory(code: string) {
    const history = JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
    if (!history.includes(code)) {
      history.unshift(code);
      localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(history));
    }
  },

  getHistory(): string[] {
    return JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
  }
};

