app.get('/api/support-centres', (req, res) => {
  const { lat, lng } = req.query;

  if (!lat || !lng) {
    // Return all if no location provided
    return res.json(SUPPORT_CENTRES.map(c => ({...c, distance: 'Unknown distance'})));
  }

  const userLat = parseFloat(lat);
  const userLng = parseFloat(lng);

  const sorted = SUPPORT_CENTRES.map(center => {
    const dist = calculateDistance(userLat, userLng, center.lat, center.lng);
    return { ...center, distance: `${dist.toFixed(1)} km`, rawDist: dist };
  }).sort((a, b) => a.rawDist - b.rawDist);

  res.json(sorted);
});

