    if (rows.length === 0) return res.status(404).json({ error: 'Report not found' });
    res.json(formatReport(rows[0]));
  } catch (err) {
    res.status(500).json({ error: 'Database error' });
  } finally {
    if (conn) conn.release();
  }
});

