  useEffect(() => {
    // Load existing config on mount
    setServerList(BackendService.getServerList());
    setActiveUrl(BackendService.getBaseUrl());
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const success = await BackendService.adminLogin(email, password);
      if (success) {
        onLoginSuccess();
      } else {
        setError("Invalid email or password.");
      }
    } catch (e) {
      setError("Login failed. Check server connection in settings.");
    } finally {
      setLoading(false);
    }
  };

  const handleSaveServers = () => {
    BackendService.saveServerList(serverList);
