    newList[index] = val;
    setServerList(newList);
    if (activeUrl === serverList[index] && val !== serverList[index]) {
        setActiveUrl(val);
    }
    // Reset test result when editing
    setTestResults({...testResults, [index]: null});
  };

  const testConnection = async (index: number, url: string) => {
    if (!url) return;
    setTestingIndex(index);
    try {
        const isOnline = await BackendService.checkConnection(url);
        setTestResults(prev => ({ ...prev, [index]: isOnline }));
    } catch (e) {
        setTestResults(prev => ({ ...prev, [index]: false }));
    } finally {
        setTestingIndex(null);
    }
  };

