              </p>

              <div className="space-y-4 mb-6">
                {serverList.map((url, index) => {
                    const isPublicSlot = index === 0;
                    const isLocalSlot = index === 1;
                    let label = `Server ${index + 1}`;
                    let icon = <Server className="w-3 h-3" />;
                    let placeholder = "http://...";

