export const AdminDashboard: React.FC<{ onLogout: () => void }> = ({ onLogout }) => {
  const [reports, setReports] = useState<Report[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedReport, setSelectedReport] = useState<Report | null>(null);
  const [filterStatus, setFilterStatus] = useState<string>('All');
  const [searchTerm, setSearchTerm] = useState('');

  // New state for status update workflow
  const [draftStatus, setDraftStatus] = useState<ReportStatus | null>(null);
  const [statusNote, setStatusNote] = useState('');
  const [isUpdatingStatus, setIsUpdatingStatus] = useState(false);

  // Existing state for standalone update message
  const [newUpdate, setNewUpdate] = useState('');
  const [sendingUpdate, setSendingUpdate] = useState(false);

  // SESSION VALIDATION
  useEffect(() => {
    const validateSession = async () => {
        const isValid = await BackendService.validateAdminSession();
        if (!isValid) {
            onLogout();
        }
    };
    validateSession();
  }, [onLogout]);

  // REAL-TIME SUBSCRIPTION
  useEffect(() => {
    setLoading(true);
    // This connects to Firestore and listens for changes
    const unsubscribe = BackendService.subscribeToReports((liveReports) => {
      setReports(liveReports);
      setLoading(false);
    });

    // Cleanup listener on unmount
    return () => unsubscribe();
  }, []);

  // Sync draft status when selected report changes (or updates via live stream)
  useEffect(() => {
    if (selectedReport) {
      // If the report was updated in the background (live sync), update the modal view
      const freshVersion = reports.find(r => r.id === selectedReport.id);

      if (freshVersion) {
         // Only update state if data actually changed to avoid loop
         if (JSON.stringify(freshVersion) !== JSON.stringify(selectedReport)) {
            setSelectedReport(freshVersion);
         }
         // Set draft status only if we aren't currently editing it
         if (!isUpdatingStatus) {
            setDraftStatus(freshVersion.status);
         }
      }
    }
  }, [reports, selectedReport]); // Depend on reports to catch real-time updates while modal is open

  const handleSaveStatus = async () => {
    if (!selectedReport || !draftStatus) return;

    setIsUpdatingStatus(true);
    try {
        // 1. Update Status if changed
        if (draftStatus !== selectedReport.status) {
            await BackendService.updateReportStatus(selectedReport.id, draftStatus);
        }

        // 2. Add Message if exists
        if (statusNote.trim()) {
            const context = draftStatus !== selectedReport.status 
                ? `[Status: ${draftStatus}] ` 
                : '';
            await BackendService.addCaseUpdate(selectedReport.id, context + statusNote);
        }

        setStatusNote('');
        // No need to manually refreshData() because the Firestore listener will auto-update the UI
        alert("Case updated successfully");
    } catch (e) {
        alert("Failed to update case");
    } finally {
        setIsUpdatingStatus(false);
    }
  };

  const handleSendUpdate = async () => {
    if (!selectedReport || !newUpdate.trim()) return;
    setSendingUpdate(true);
    try {
        await BackendService.addCaseUpdate(selectedReport.id, newUpdate);
        setNewUpdate('');
    } catch (e) {
        alert("Failed to send update");
    } finally {
        setSendingUpdate(false);
    }
  };

  const filteredReports = reports.filter(r => {
    const matchesStatus = filterStatus === 'All' || r.status === filterStatus;
