  const [loading, setLoading] = useState(true);
  const [selectedReport, setSelectedReport] = useState<Report | null>(null);
  const [filterStatus, setFilterStatus] = useState<string>('All');
  const [searchTerm, setSearchTerm] = useState('');
  const [activeTab, setActiveTab] = useState<'dashboard' | 'settings'>('dashboard');

  // New state for status update workflow
  const [draftStatus, setDraftStatus] = useState<ReportStatus | null>(null);
  const [statusNote, setStatusNote] = useState('');
  const [isUpdatingStatus, setIsUpdatingStatus] = useState(false);

  // Existing state for standalone update message
  const [newUpdate, setNewUpdate] = useState('');
  const [sendingUpdate, setSendingUpdate] = useState(false);

  // SESSION VALIDATION
  useEffect(() => {
    const validateSession = async () => {
        const isValid = await BackendService.validateAdminSession();
        if (!isValid) {
            onLogout();
        }
    };
    validateSession();
  }, [onLogout]);

  // REAL-TIME SUBSCRIPTION
  useEffect(() => {
    setLoading(true);
    // This connects to Firestore and listens for changes
    const unsubscribe = BackendService.subscribeToReports((liveReports) => {
      setReports(liveReports);
      setLoading(false);
    });

    // Cleanup listener on unmount
    return () => unsubscribe();
  }, []);

  // Sync draft status when selected report changes (or updates via live stream)
  useEffect(() => {
    if (selectedReport) {
      // If the report was updated in the background (live sync), update the modal view
      const freshVersion = reports.find(r => r.id === selectedReport.id);

      if (freshVersion) {
         if (JSON.stringify(freshVersion) !== JSON.stringify(selectedReport)) {
            setSelectedReport(freshVersion);
         }
         if (!isUpdatingStatus) {
            setDraftStatus(freshVersion.status);
         }
      }
    }
  }, [reports, selectedReport]);

  const handleSaveStatus = async () => {
    if (!selectedReport || !draftStatus) return;

    setIsUpdatingStatus(true);
    try {
        if (draftStatus !== selectedReport.status) {
            await BackendService.updateReportStatus(selectedReport.id, draftStatus);
        }
        if (statusNote.trim()) {
            const context = draftStatus !== selectedReport.status 
                ? `[Status: ${draftStatus}] ` 
                : '';
            await BackendService.addCaseUpdate(selectedReport.id, context + statusNote);
        }

        setStatusNote('');
        alert("Case updated successfully");
    } catch (e) {
        alert("Failed to update case");
    } finally {
        setIsUpdatingStatus(false);
    }
  };

  const handleSendUpdate = async () => {
    if (!selectedReport || !newUpdate.trim()) return;
    setSendingUpdate(true);
    try {
        await BackendService.addCaseUpdate(selectedReport.id, newUpdate);
        setNewUpdate('');
    } catch (e) {
        alert("Failed to send update");
    } finally {
        setSendingUpdate(false);
    }
  };

  const handleSeed = async () => {
    if(confirm("This will populate Firestore with default Education Modules and Hotlines if they are missing. Continue?")) {
        const success = await BackendService.seedDatabase();
        if(success) alert("Database seeded successfully!");
        else alert("Seeding failed or data already exists.");
    }
  };

  const filteredReports = reports.filter(r => {
    const matchesStatus = filterStatus === 'All' || r.status === filterStatus;
    const matchesSearch = r.trackingCode.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          r.description.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesStatus && matchesSearch;
  });

  const getStatusColor = (status: ReportStatus) => {
    switch (status) {
      case ReportStatus.RECEIVED: return 'bg-gray-100 text-gray-800';
      case ReportStatus.ASSIGNED: return 'bg-blue-100 text-blue-800';
      case ReportStatus.IN_REVIEW: return 'bg-yellow-100 text-yellow-800';
      case ReportStatus.ACTION_TAKEN: return 'bg-purple-100 text-purple-800';
      case ReportStatus.RESOLVED: return 'bg-green-100 text-green-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  return (
    <div className="flex h-screen bg-gray-100 dark:bg-gray-900 overflow-hidden w-full">
      {/* Sidebar (Desktop Only) */}
      <aside className="w-64 bg-white dark:bg-gray-800 border-r border-gray-200 dark:border-gray-700 hidden md:flex flex-col flex-shrink-0">
        <div className="p-6 border-b border-gray-200 dark:border-gray-700">
           <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-brand-500 to-purple-600 flex items-center justify-center text-white font-bold text-sm">
              SV
            </div>
            <h1 className="font-bold text-xl tracking-tight text-gray-800 dark:text-white">Admin Panel</h1>
          </div>
        </div>
        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`flex items-center w-full p-3 rounded-xl font-medium transition-colors ${activeTab === 'dashboard' ? 'bg-brand-50 dark:bg-brand-900/20 text-brand-700 dark:text-brand-300' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-700'}`}
          >
            <LayoutDashboard className="w-5 h-5 mr-3" />
            Dashboard
          </button>
          <button 
            onClick={() => setActiveTab('settings')}
            className={`flex items-center w-full p-3 rounded-xl font-medium transition-colors ${activeTab === 'settings' ? 'bg-brand-50 dark:bg-brand-900/20 text-brand-700 dark:text-brand-300' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-700'}`}
          >
            <Settings className="w-5 h-5 mr-3" />
            Settings
          </button>

          <div className="pt-4 text-xs font-semibold text-gray-400 uppercase tracking-wider pl-3">Stats</div>
          <div className="grid grid-cols-2 gap-2 p-2">
            <div className="bg-blue-50 dark:bg-blue-900/20 p-3 rounded-lg text-center">
              <div className="text-2xl font-bold text-blue-600 dark:text-blue-400">{reports.length}</div>
              <div className="text-xs text-blue-600/70 dark:text-blue-300">Total</div>
            </div>
            <div className="bg-yellow-50 dark:bg-yellow-900/20 p-3 rounded-lg text-center">
              <div className="text-2xl font-bold text-yellow-600 dark:text-yellow-400">
                {reports.filter(r => r.status === ReportStatus.RECEIVED).length}
              </div>
              <div className="text-xs text-yellow-600/70 dark:text-yellow-300">Pending</div>
            </div>
          </div>
        </nav>
        <div className="p-4 border-t border-gray-200 dark:border-gray-700">
          <button onClick={onLogout} className="flex items-center text-gray-500 hover:text-red-500 transition-colors w-full p-2">
            <LogOut className="w-5 h-5 mr-3" />
            Logout
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full relative min-w-0">

        {/* Header */}
        <header className="h-16 bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 flex items-center justify-between px-4 sm:px-6 flex-shrink-0 gap-4">
          <div className="flex items-center gap-2">
              <h2 className="text-lg font-semibold text-gray-800 dark:text-white truncate min-w-0">
                {activeTab === 'dashboard' ? 'Firebase Dashboard' : 'System Settings'}
              </h2>
              <div className="flex items-center gap-1.5 bg-green-50 dark:bg-green-900/30 px-2 py-1 rounded-full border border-green-100 dark:border-green-800">
                  <Zap className="w-3 h-3 text-green-500 fill-current" />
                  <span className="text-[10px] font-bold text-green-700 dark:text-green-300 uppercase tracking-wide">Real-time</span>
              </div>
          </div>
          <div className="flex items-center gap-2 sm:gap-3 flex-shrink-0">
             {/* Only show search on dashboard */}
             {activeTab === 'dashboard' && (
               <div className="relative hidden sm:block">
                  <Search className="absolute left-3 top-2.5 w-4 h-4 text-gray-400" />
                  <input 
                    type="text" 
                    placeholder="Search code..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-9 pr-4 py-2 rounded-lg border border-gray-200 dark:border-gray-600 bg-gray-50 dark:bg-gray-700 text-sm w-48 focus:ring-2 focus:ring-brand-500 outline-none transition-all"
                  />
               </div>
             )}

             {/* Mobile Exit */}
             <button 
                onClick={onLogout} 
                className="md:hidden flex items-center gap-1.5 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 px-3 py-2 rounded-lg text-xs font-bold transition-colors active:scale-95 border border-red-100 dark:border-red-900 whitespace-nowrap"
             >
               <LogOut className="w-4 h-4" />
               Exit
             </button>
          </div>
        </header>

        {/* SETTINGS TAB */}
        {activeTab === 'settings' && (
            <div className="p-6">
                <div className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-sm border border-gray-200 dark:border-gray-700 max-w-2xl">
                    <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                        <Database className="w-5 h-5 text-brand-600" />
                        Database Management
                    </h3>
                    <p className="text-gray-600 dark:text-gray-300 mb-6">
                        Use this to populate your Firestore database with default content (Education Modules, Hotlines, Support Centers) if the app is appearing empty.
                    </p>
                    <button 
                        onClick={handleSeed}
                        className="bg-indigo-600 text-white px-4 py-2 rounded-lg font-bold hover:bg-indigo-700 transition-colors flex items-center gap-2"
                    >
                        <Zap className="w-4 h-4" />
                        Seed Default Data
                    </button>
                </div>
            </div>
        )}

        {/* DASHBOARD TAB */}
        {activeTab === 'dashboard' && (
         <>
          {/* Filters */}
          <div className="flex-shrink-0 w-full border-b border-gray-100 dark:border-gray-800 bg-gray-50/50 dark:bg-gray-900/50">
            <div className="flex gap-2 overflow-x-auto px-4 sm:px-6 py-4 pb-4 w-full">
              {['All', ...Object.values(ReportStatus)].map(status => (
                <button
                  key={status}
                  onClick={() => setFilterStatus(status)}
                  className={`flex-shrink-0 whitespace-nowrap px-5 py-2 rounded-full text-sm font-medium transition-colors border shadow-sm ${
                    filterStatus === status 
                    ? 'bg-brand-600 text-white border-brand-600 ring-2 ring-brand-200 dark:ring-brand-900' 
                    : 'bg-white dark:bg-gray-800 text-gray-600 dark:text-gray-300 border-gray-200 dark:border-gray-700 hover:bg-gray-100 dark:hover:bg-gray-700'
                  }`}
                >
                  {status}
                </button>
              ))}
              <div className="w-4 flex-shrink-0"></div>
            </div>
          </div>

          {/* List Content */}
          <div className="flex-1 overflow-y-auto p-4 sm:p-6 bg-gray-100 dark:bg-gray-900">
            {loading ? (
              <div className="flex justify-center items-center h-64">
                  <div className="animate-pulse text-gray-400 flex items-center gap-2">
                      <Activity className="w-4 h-4 animate-bounce" /> Loading from Firestore...
                  </div>
              </div>
            ) : (
              <>
                {/* Desktop Table */}
                <div className="hidden md:block bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm overflow-x-auto">
                  <table className="w-full text-left min-w-[700px]">
                    <thead className="bg-gray-50 dark:bg-gray-700/50 border-b border-gray-200 dark:border-gray-700">
                      <tr>
                        <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase whitespace-nowrap">Code</th>
                        <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase whitespace-nowrap">Type</th>
                        <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase whitespace-nowrap">Date</th>
                        <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase whitespace-nowrap">Status</th>
                        <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase text-right whitespace-nowrap">Action</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                      {filteredReports.map(report => (
                        <tr key={report.id} className="hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors">
                          <td className="px-6 py-4 font-mono font-medium text-brand-600 whitespace-nowrap">{report.trackingCode}</td>
                          <td className="px-6 py-4 text-sm dark:text-gray-300 whitespace-nowrap">{report.type}</td>
                          <td className="px-6 py-4 text-sm text-gray-500 whitespace-nowrap">
                            {new Date(report.createdAt).toLocaleDateString()}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${getStatusColor(report.status)}`}>
                              {report.status}
                            </span>
                          </td>
                          <td className="px-6 py-4 text-right whitespace-nowrap">
                            <button 
                              onClick={() => setSelectedReport(report)}
                              className="text-gray-400 hover:text-brand-600 p-1 transition-colors"
                            >
                              <Eye className="w-5 h-5" />
                            </button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>

                {/* Mobile Cards */}
                <div className="md:hidden space-y-4">
                  {filteredReports.map(report => (
                      <div 
                        key={report.id} 
                        onClick={() => setSelectedReport(report)}
                        className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 active:scale-[0.98] transition-transform"
                      >
                        <div className="flex justify-between items-start mb-3">
                            <div>
                              <span className="font-mono text-lg font-bold text-brand-600">{report.trackingCode}</span>
                              <p className="text-xs text-gray-500">{new Date(report.createdAt).toLocaleDateString()}</p>
                            </div>
                            <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(report.status)}`}>
                              {report.status}
                            </span>
                        </div>
                        <div className="flex items-center justify-between text-sm text-gray-700 dark:text-gray-300 mb-2">
                            <div className="flex items-center gap-2">
                              <AlertCircle className="w-4 h-4 text-gray-400" />
                              <span>{report.type}</span>
                            </div>
                            <div className="flex items-center gap-2">
                              <MapPin className="w-4 h-4 text-gray-400" />
                              <span className="truncate max-w-[120px]">{report.location}</span>
                            </div>
                        </div>
                      </div>
                  ))}
                </div>

                {filteredReports.length === 0 && (
                    <div className="text-center py-12 text-gray-500">
                      No reports found.
                    </div>
                )}
              </>
            )}
          </div>
         </>
        )}

        {/* Detail Modal */}
        {selectedReport && (
          <div className="absolute inset-0 z-50 bg-black/50 backdrop-blur-sm flex justify-end">
            <div className="w-full md:w-[600px] bg-white dark:bg-gray-900 h-full shadow-2xl animate-slide-up md:animate-none overflow-y-auto">
              <div className="p-4 sm:p-6 border-b border-gray-200 dark:border-gray-700 flex justify-between items-start sticky top-0 bg-white/95 dark:bg-gray-900/95 backdrop-blur z-10">
                 <div>
                    <h2 className="text-xl sm:text-2xl font-bold text-gray-900 dark:text-white">Case Details</h2>
                    <p className="text-brand-600 font-mono text-sm sm:text-base">{selectedReport.trackingCode}</p>
                 </div>
                 <button onClick={() => setSelectedReport(null)} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full">
                    <X className="w-6 h-6 text-gray-500" />
                 </button>
              </div>

              <div className="p-4 sm:p-6 space-y-6 sm:space-y-8 pb-20">
                {/* Status Control */}
                <div className="bg-gray-50 dark:bg-gray-800 rounded-xl p-4 border border-gray-200 dark:border-gray-700 shadow-sm">
                  <label className="text-xs font-semibold text-gray-500 uppercase mb-3 block">Update Case Status</label>
                  <div className="space-y-3">
                    <div className="relative">
                      <select
                        value={draftStatus || ''}
                        onChange={(e) => setDraftStatus(e.target.value as ReportStatus)}
                        className="w-full appearance-none bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white text-sm rounded-xl focus:ring-2 focus:ring-brand-500 focus:border-transparent block p-3 pr-10 shadow-sm transition-all font-medium"
                      >
                        {Object.values(ReportStatus).map((s) => (
                          <option key={s} value={s}>
                            {s}
                          </option>
                        ))}
                      </select>
                      <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-4 text-gray-500">
                        <ChevronDown className="w-5 h-5" />
                      </div>
                    </div>

                    <textarea 
                        value={statusNote}
                        onChange={(e) => setStatusNote(e.target.value)}
                        placeholder="Add a status note/instruction for the victim (optional)..."
                        className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-sm focus:ring-2 focus:ring-brand-500 outline-none h-20 resize-none"
                    />

                    <button 
                        onClick={handleSaveStatus}
                        disabled={isUpdatingStatus || (!statusNote.trim() && draftStatus === selectedReport.status)}
                        className="w-full bg-brand-600 hover:bg-brand-700 text-white p-3 rounded-xl font-bold flex justify-center items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed shadow-md transition-all active:scale-[0.98]"
                    >
                        {isUpdatingStatus ? <Loader2 className="animate-spin w-4 h-4"/> : <Save className="w-4 h-4" />}
                        Update Status & Notify
                    </button>
                  </div>
                </div>

                {/* Case Updates / Messaging History */}
                <div className="bg-blue-50 dark:bg-blue-900/10 rounded-xl p-4 border border-blue-100 dark:border-blue-900/20">
                    <div className="flex items-center gap-2 mb-3">
                        <MessageSquare className="w-4 h-4 text-blue-600" />
                        <label className="text-xs font-semibold text-blue-800 dark:text-blue-300 uppercase">Updates History & Chat</label>
                    </div>

                    <div className="space-y-3 mb-4 max-h-56 overflow-y-auto pr-1 bg-white/50 dark:bg-gray-800/30 p-2 rounded-lg">
                        {(selectedReport.caseUpdates || []).length === 0 ? (
                            <p className="text-sm text-gray-400 italic text-center py-4">No updates or notes yet.</p>
                        ) : (
                            selectedReport.caseUpdates.map(update => (
                                <div key={update.id} className="bg-white dark:bg-gray-800 p-3 rounded-lg text-sm shadow-sm border border-gray-100 dark:border-gray-700">
                                    <p className="text-gray-800 dark:text-gray-200 mb-1 whitespace-pre-wrap">{update.content}</p>
                                    <div className="flex justify-between mt-2 text-[10px] text-gray-400 uppercase font-medium">
                                        <span>{update.author}</span>
                                        <span>{new Date(update.timestamp).toLocaleString()}</span>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>

                    <div className="flex flex-col sm:flex-row gap-2 pt-2 border-t border-blue-100 dark:border-blue-800/30">
                        <input 
                            type="text" 
                            value={newUpdate}
                            onChange={(e) => setNewUpdate(e.target.value)}
                            placeholder="Send a quick message without status change..." 
                            className="flex-1 px-3 py-3 rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                        />
                        <button 
                            onClick={handleSendUpdate}
                            disabled={sendingUpdate || !newUpdate.trim()}
                            className="bg-blue-600 text-white px-4 py-3 sm:py-2 rounded-lg hover:bg-blue-700 disabled:opacity-50 flex items-center justify-center font-medium shadow-sm active:scale-95 transition-transform"
                        >
                            {sendingUpdate ? '...' : <Send className="w-4 h-4" />}
                        </button>
                    </div>
                </div>

                {/* Info Grid */}
                <div className="grid grid-cols-2 gap-4 sm:gap-6">
                  <div>
                    <div className="flex items-center gap-2 text-gray-500 mb-1">
                      <AlertCircle className="w-4 h-4" />
                      <span className="text-xs uppercase font-semibold">Incident Type</span>
                    </div>
                    <p className="font-medium text-gray-900 dark:text-gray-200">{selectedReport.type}</p>
                  </div>
                  <div>
                    <div className="flex items-center gap-2 text-gray-500 mb-1">
                      <MapPin className="w-4 h-4" />
                      <span className="text-xs uppercase font-semibold">Location</span>
                    </div>
                    <p className="font-medium text-gray-900 dark:text-gray-200">{selectedReport.location}</p>
                  </div>
                  <div>
                    <div className="flex items-center gap-2 text-gray-500 mb-1">
                      <Calendar className="w-4 h-4" />
                      <span className="text-xs uppercase font-semibold">Date Reported</span>
                    </div>
                    <p className="font-medium text-gray-900 dark:text-gray-200">{new Date(selectedReport.createdAt).toLocaleString()}</p>
                  </div>
                </div>

                {/* Description */}
                <div>
                   <h3 className="text-sm font-semibold text-gray-500 uppercase mb-2">Description</h3>
                   <div className="bg-gray-50 dark:bg-gray-800 p-4 rounded-xl text-gray-700 dark:text-gray-300 whitespace-pre-line leading-relaxed text-sm">
                     {selectedReport.description}
                   </div>
                </div>

                {/* Attachments */}
                {selectedReport.attachments.length > 0 && (
                  <div>
                    <h3 className="text-sm font-semibold text-gray-500 uppercase mb-3">Evidence / Attachments</h3>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      {selectedReport.attachments.map((att, i) => (
                        <div key={i} className="border border-gray-200 dark:border-gray-700 rounded-lg p-3 flex items-center gap-3 bg-white dark:bg-gray-800">
                           <div className="w-10 h-10 bg-gray-100 dark:bg-gray-700 rounded-lg flex items-center justify-center text-gray-400 flex-shrink-0">
                             {att.type === 'image' ? <Eye className="w-5 h-5" /> : <MoreHorizontal className="w-5 h-5" />}
                           </div>
                           <div className="overflow-hidden flex-1">
                             <a 
                               href={att.url} 
                               target="_blank" 
                               rel="noopener noreferrer"
                               className="text-sm font-medium truncate text-blue-600 dark:text-blue-400 hover:underline block"
                             >
                               {att.name}
                             </a>
                             <p className="text-xs text-gray-500 uppercase">{att.type}</p>
                           </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

import React, { useState } from 'react';
import { GBVType, Attachment, Language } from '../types';
import { BackendService } from '../services/mockBackend';
import { getTranslation } from '../services/translations';
import { AlertCircle, Camera, Mic, MapPin, Loader2, CheckCircle, FileUp, XCircle, Calendar, Crosshair, Shield } from 'lucide-react';

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB Limit

interface ReportViewProps {
  onReportSubmitted: (code: string) => void;
  lang: Language;
  onSafetyPlanClick: () => void;
}

export const ReportView: React.FC<ReportViewProps> = ({ onReportSubmitted, lang, onSafetyPlanClick }) => {
  const t = getTranslation(lang);

  const [type, setType] = useState<GBVType>(GBVType.PHYSICAL);
  const [location, setLocation] = useState('');
  const [incidentDate, setIncidentDate] = useState('');
  const [description, setDescription] = useState('');
  const [files, setFiles] = useState<Attachment[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [gettingLocation, setGettingLocation] = useState(false);
  const [success, setSuccess] = useState(false);
  const [trackingCode, setTrackingCode] = useState('');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setErrorMsg(null);
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.size > MAX_FILE_SIZE) {
        setErrorMsg(`File "${file.name}" is too large. Maximum size is 5MB.`);
        return;
      }
      const newAttachment: Attachment = {
        name: file.name,
        type: file.type.startsWith('image') ? 'image' : file.type.startsWith('audio') ? 'audio' : 'video',
        url: URL.createObjectURL(file), 
        file: file 
      };
      setFiles([...files, newAttachment]);
    }
  };

  const removeFile = (index: number) => {
    const newFiles = [...files];
    newFiles.splice(index, 1);
    setFiles(newFiles);
  };

  const handleGetGPS = () => {
    if (!navigator.geolocation) {
        alert("Geolocation is not supported by your browser");
        return;
    }
    setGettingLocation(true);
    navigator.geolocation.getCurrentPosition(
        (position) => {
            // Success
            const { latitude, longitude } = position.coords;
            const gpsString = `${latitude.toFixed(5)}, ${longitude.toFixed(5)}`;
            setLocation(prev => prev ? `${prev} (${gpsString})` : gpsString);
            setGettingLocation(false);
        },
        (error) => {
            // Error
            console.error(error);
            alert("Unable to retrieve location. Please type it manually.");
            setGettingLocation(false);
        },
        { enableHighAccuracy: true, timeout: 10000 }
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMsg(null);

    if (!location.trim() || !description.trim()) {
        setErrorMsg("Please provide both a location and a description of the incident.");
        return;
    }

    let anonymousUserId = localStorage.getItem('safevoice_anon_id');
    if (!anonymousUserId) {
      anonymousUserId = crypto.randomUUID();
      localStorage.setItem('safevoice_anon_id', anonymousUserId);
    }

    setIsSubmitting(true);
    try {
      const report = await BackendService.createReport({
        type,
        location,
        description,
        incidentDate: incidentDate || new Date().toISOString(), // Use selected time or now
        attachments: files,
        anonymousUserId
      });
      setTrackingCode(report.trackingCode);
      setSuccess(true);

      setTimeout(() => {
        onReportSubmitted(report.trackingCode);
      }, 3000);
    } catch (error: any) {
      console.error("Submission Error:", error);
      let msg = "An unexpected error occurred. Please try again.";
      if (error instanceof Error) {
          if (error.message.includes("Network") || error.message.includes("fetch")) {
             msg = "Unable to connect to server. Please check your internet connection.";
          }
      }
      setErrorMsg(msg);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (success) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center p-6 animate-fade-in">
        <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mb-4">
          <CheckCircle className="w-10 h-10 text-green-600" />
        </div>
        <h2 className="text-2xl font-bold mb-2 text-gray-800 dark:text-white">Report Received</h2>
        <p className="text-gray-600 dark:text-gray-300 mb-6">Your tracking code is:</p>
        <div className="bg-gray-100 dark:bg-gray-800 p-4 rounded-xl mb-6 border-2 border-dashed border-gray-300 dark:border-gray-600">
          <span className="text-3xl font-mono font-bold text-brand-600 tracking-wider select-all">
            {trackingCode}
          </span>
        </div>
        <p className="text-sm text-gray-500 animate-pulse">Redirecting to tracker...</p>
      </div>
    );
  }

  return (
    <div className="p-4 pb-20 animate-slide-up">
      <h1 className="text-2xl font-bold mb-6 text-brand-700 dark:text-brand-400">{t.report_title}</h1>

      <div className="bg-yellow-50 dark:bg-yellow-900/20 border-l-4 border-yellow-400 p-4 mb-4 rounded-r">
        <div className="flex">
          <AlertCircle className="w-5 h-5 text-yellow-500 mr-2 flex-shrink-0" />
          <p className="text-sm text-yellow-700 dark:text-yellow-200">
            {t.safety_priority}
          </p>
        </div>
      </div>

      <div className="mb-6 flex justify-end">
         <button 
           type="button" 
           onClick={onSafetyPlanClick}
           className="text-sm text-brand-600 dark:text-brand-400 flex items-center hover:underline"
         >
           <Shield className="w-4 h-4 mr-1" />
           {t.not_ready_safety_plan}
         </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5">

        {errorMsg && (
          <div className="bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-300 p-4 rounded-xl text-sm flex items-start animate-fade-in border border-red-100 dark:border-red-800">
            <XCircle className="w-5 h-5 mr-2 flex-shrink-0" />
            <span>{errorMsg}</span>
          </div>
        )}

        {/* INCIDENT TYPE */}
        <div>
          <label className="block text-sm font-medium mb-1">{t.type_incident}</label>
          <select 
            value={type} 
            onChange={(e) => setType(e.target.value as GBVType)}
            className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none"
          >
            {Object.values(GBVType).map(t => (
              <option key={t} value={t}>{t}</option>
            ))}
          </select>
        </div>

        {/* TIME OF INCIDENT */}
        <div>
           <label className="block text-sm font-medium mb-1 flex items-center gap-1">
             <Calendar className="w-4 h-4 text-gray-400" />
             {t.time_incident}
           </label>
           <input 
             type="datetime-local"
             value={incidentDate}
             onChange={(e) => setIncidentDate(e.target.value)}
             className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none"
           />
        </div>

        {/* LOCATION WITH GPS */}
        <div>
          <label className="block text-sm font-medium mb-1">{t.location}</label>
          <div className="flex gap-2">
            <div className="relative flex-1">
                <MapPin className="absolute left-3 top-3.5 w-5 h-5 text-gray-400" />
                <input 
                type="text" 
                placeholder={t.location_placeholder}
                value={location}
                onChange={(e) => setLocation(e.target.value)}
                className="w-full pl-10 p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none"
                required
                />
            </div>
            <button 
                type="button"
                onClick={handleGetGPS}
                disabled={gettingLocation}
                className="bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-200 p-3 rounded-xl hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors flex items-center justify-center min-w-[50px]"
                title={t.use_gps}
            >
                {gettingLocation ? <Loader2 className="animate-spin w-5 h-5"/> : <Crosshair className="w-5 h-5" />}
            </button>
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium mb-1">{t.description}</label>
          <textarea 
            placeholder={t.desc_placeholder}
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            className="w-full p-3 h-32 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none resize-none"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium mb-2">{t.evidence}</label>
          <div className="flex gap-4 mb-4">
             <label className="flex flex-col items-center justify-center w-24 h-24 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400 transition-colors">
                <Camera className="w-6 h-6 text-gray-400 mb-1" />
                <span className="text-xs text-gray-500">{t.photo}</span>
                <input type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
             </label>
             <label className="flex flex-col items-center justify-center w-24 h-24 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400 transition-colors">
                <Mic className="w-6 h-6 text-gray-400 mb-1" />
                <span className="text-xs text-gray-500">{t.audio}</span>
                <input type="file" accept="audio/*" className="hidden" onChange={handleFileChange} />
             </label>
             <label className="flex flex-col items-center justify-center w-24 h-24 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400 transition-colors">
                <FileUp className="w-6 h-6 text-gray-400 mb-1" />
                <span className="text-xs text-gray-500">{t.video}</span>
                <input type="file" accept="video/*" className="hidden" onChange={handleFileChange} />
             </label>
          </div>
          {files.length > 0 && (
            <div className="space-y-2">
              {files.map((f, idx) => (
                <div key={idx} className="flex items-center justify-between text-sm p-2 bg-gray-100 dark:bg-gray-800 rounded-lg">
                  <div className="flex items-center overflow-hidden">
                    <CheckCircle className="w-4 h-4 text-green-500 mr-2 flex-shrink-0" />
                    <span className="truncate">{f.name}</span>
                  </div>
                  <button 
                    type="button" 
                    onClick={() => removeFile(idx)} 
                    className="text-red-500 hover:text-red-700 p-1"
                  >
                      <XCircle className="w-4 h-4" />
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        <button 
          type="submit" 
          disabled={isSubmitting}
          className="w-full bg-brand-600 hover:bg-brand-700 text-white p-4 rounded-xl font-bold shadow-lg shadow-brand-500/30 transition-all active:scale-95 disabled:opacity-70 flex justify-center items-center"
        >
          {isSubmitting ? <Loader2 className="animate-spin w-5 h-5" /> : t.submit_btn}
        </button>
      </form>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppView, Language } from './types';
import { ReportView } from './components/ReportView';
import { TrackView } from './components/TrackView';
import { EducationView } from './components/EducationView';
import { HotlinesView } from './components/HotlinesView';
import { ChatView } from './components/ChatView';
import { SafetyPlanView } from './components/SafetyPlanView';
import { AdminLogin } from './components/AdminLogin';
import { AdminDashboard } from './components/AdminDashboard';
import { PanicButton } from './components/PanicButton';
import { BackendService } from './services/mockBackend';
import { getTranslation } from './services/translations';
import { Home, FilePlus, BookOpen, Phone, Bell, Moon, Sun, UserCircle, MessageCircleHeart, Shield, LogOut, Globe } from 'lucide-react';
import { getToken } from 'firebase/messaging';
import { messaging } from './firebaseConfig';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.HOME);
  const [darkMode, setDarkMode] = useState(false);
  const [lang, setLang] = useState<Language>('en');
  const [lastTrackingCode, setLastTrackingCode] = useState<string>('');
  const [lastKnownStatus, setLastKnownStatus] = useState<string>('');
  const [notifications, setNotifications] = useState<string[]>([]);
  const [logoTaps, setLogoTaps] = useState(0);

  const t = getTranslation(lang);

  // Initialize Dark Mode based on system preference
  useEffect(() => {
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      setDarkMode(true);
    }

    // Load most recent case to watch
    const history = BackendService.getHistory();
    if (history.length > 0) {
        setLastTrackingCode(history[0]);
    }
  }, []);

  // Request Notification Permission (For Admin mainly)
  useEffect(() => {
    if (messaging) {
      const reqPermission = async () => {
        try {
          const permission = await Notification.requestPermission();
          if (permission === 'granted') {
             // Get Token
             const token = await getToken(messaging, { vapidKey: 'BIZ4-6RiZ7u_YlzRPcvBPs9hVXMZkb9eDgVdKuSbonZMSeG1Eo7IOmytAC_Q-DjQK00h3QwwIjLRJ0q0QjldUUs' });
             console.log("FCM Token:", token);
          }
        } catch (e) {
          console.warn("Notification permission denied or failed.");
        }
      };
      reqPermission();
    }
  }, []);

  // Poll for Status Updates on the active case
  useEffect(() => {
    if (!lastTrackingCode) return;

    // For the user side, we still poll simply or could implement onSnapshot in TrackView
    // Keeping simple poll here for notifications
    const checkStatus = async () => {
        try {
            const report = await BackendService.getReportByCode(lastTrackingCode);
            if (report) {
                if (!lastKnownStatus) {
                    setLastKnownStatus(report.status);
                } 
                else if (report.status !== lastKnownStatus) {
                    setLastKnownStatus(report.status);
                    setNotifications(prev => [...prev, `Update: Case ${lastTrackingCode} is now '${report.status}'`]);
                }
            }
        } catch (e) {
            // silent fail
        }
    };

    const interval = setInterval(checkStatus, 10000); // 10s poll for user
    return () => clearInterval(interval);
  }, [lastTrackingCode, lastKnownStatus]);


  // Apply Dark Mode class to HTML
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // Simulate Push Notifications (Education Marketing)
  useEffect(() => {
    const timer = setTimeout(() => {
      setNotifications(prev => [...prev, "New education module available: 'Digital Safety'"]);
    }, 10000);
    return () => clearTimeout(timer);
  }, []);

  // --- QUICK EXIT FUNCTION ---
  const handleQuickExit = () => {
    // Redirect to a harmless site immediately
    window.location.href = "https://www.google.com/search?q=weather+today";
  };

  const handleReportSubmitted = (code: string) => {
    setLastTrackingCode(code);
    setLastKnownStatus(''); // Reset status tracker so we don't get a false alert
    setView(AppView.TRACK);
    setNotifications(prev => [...prev, `Report submitted. Tracking code: ${code}`]);
  };

  // --- HIDDEN ADMIN ACCESS ---
  const handleLogoTap = () => {
    setLogoTaps(prev => {
      const newCount = prev + 1;
      if (newCount >= 7) {
        setView(AppView.ADMIN_LOGIN);
        return 0;
      }
      return newCount;
    });

    // Reset taps if too slow (clear after 2 seconds)
    setTimeout(() => setLogoTaps(0), 2000);
  };

  const toggleLanguage = () => {
    setLang(prev => prev === 'en' ? 'sw' : 'en');
  };

  const NavButton: React.FC<{ target: AppView; icon: React.ReactNode; label: string }> = ({ target, icon, label }) => (
    <button 
      onClick={() => setView(target)}
      className={`flex flex-col items-center justify-center w-full py-3 transition-colors ${
        view === target ? 'text-brand-600 dark:text-brand-400' : 'text-gray-400 dark:text-gray-500 hover:text-gray-600 dark:hover:text-gray-300'
      }`}
    >
      {icon}
      <span className="text-[10px] mt-1 font-medium">{label}</span>
    </button>
  );

  const isAdminView = view === AppView.ADMIN_DASHBOARD;

  return (
    <div className="flex justify-center min-h-screen bg-gray-200 dark:bg-black">
      {/* Mobile Frame Container - Expanded for Admin Dashboard */}
      <div className={`w-full ${isAdminView ? 'max-w-none' : 'max-w-md'} bg-white dark:bg-gray-900 h-[100dvh] relative shadow-2xl overflow-hidden flex flex-col transition-all duration-300`}>

        {/* Panic Button - Visible on non-admin screens */}
        {!isAdminView && view !== AppView.ADMIN_LOGIN && <PanicButton lang={lang} />}

        {/* Header */}
        {view !== AppView.ADMIN_LOGIN && view !== AppView.ADMIN_DASHBOARD && (
          <header className="px-4 py-3 flex justify-between items-center bg-white/80 dark:bg-gray-900/80 backdrop-blur-md sticky top-0 z-20 border-b border-gray-100 dark:border-gray-800">
            <div 
              onClick={handleLogoTap}
              className="flex items-center gap-2 cursor-pointer select-none active:opacity-70 transition-opacity"
            >
              <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-brand-500 to-purple-600 flex items-center justify-center text-white font-bold text-sm">
                SV
              </div>
              <h1 className="font-bold text-lg tracking-tight text-gray-800 dark:text-white hidden sm:block">SafeVoice</h1>
            </div>
            <div className="flex items-center gap-2">
              {/* Language Toggle */}
              <button 
                 onClick={toggleLanguage}
                 className="bg-gray-100 dark:bg-gray-800 text-gray-700 dark:text-gray-200 px-2 py-1.5 rounded-lg text-xs font-bold flex items-center border border-gray-200 dark:border-gray-700 mr-1"
              >
                 <Globe className="w-3 h-3 mr-1" />
                 {lang === 'en' ? 'EN' : 'SW'}
              </button>

              {/* Quick Exit */}
              <button 
                onClick={handleQuickExit}
                className="bg-red-600 hover:bg-red-700 text-white px-3 py-1.5 rounded-full text-xs font-bold flex items-center shadow-sm transition-transform active:scale-95"
                title="Quick Exit"
              >
                <LogOut className="w-3 h-3 mr-1" /> {t.quick_exit}
              </button>

              <button onClick={() => setDarkMode(!darkMode)} className="p-1.5 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors">
                {darkMode ? <Sun className="w-5 h-5 text-yellow-400" /> : <Moon className="w-5 h-5 text-gray-600" />}
              </button>
              <div className="relative">
                 <Bell className="w-5 h-5 text-gray-600 dark:text-gray-300" />
                 {notifications.length > 0 && (
                   <span className="absolute -top-0.5 -right-0.5 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-white dark:border-gray-900"></span>
                 )}
              </div>
            </div>
          </header>
        )}

        {/* Main Content Area */}
        <main className="flex-1 overflow-y-auto no-scrollbar relative">

          {/* Notification Toast */}
          {notifications.length > 0 && view !== AppView.ADMIN_LOGIN && view !== AppView.ADMIN_DASHBOARD && (
            <div className="absolute top-4 left-4 right-4 bg-gray-800 text-white text-sm p-3 rounded-lg shadow-lg z-30 animate-slide-up flex justify-between items-center opacity-95">
               <span 
                 onClick={() => setView(AppView.TRACK)}
                 className="flex-1 cursor-pointer truncate mr-2"
               >
                 {notifications[notifications.length - 1]}
               </span>
               <button onClick={() => setNotifications([])} className="text-xs text-gray-400 hover:text-white whitespace-nowrap">Dismiss</button>
            </div>
          )}

          {view === AppView.HOME && (
            <div className="p-6 animate-fade-in pb-20">
               <div className="mb-8">
                 <h2 className="text-3xl font-bold text-gray-800 dark:text-white mb-2">{t.welcome}</h2>
                 <p className="text-gray-500 dark:text-gray-400">{t.safe_msg}</p>
               </div>

               <div className="grid grid-cols-2 gap-4">
                 <button 
                   onClick={() => setView(AppView.REPORT)}
                   className="col-span-2 bg-gradient-to-r from-brand-500 to-brand-600 text-white p-6 rounded-2xl shadow-lg shadow-brand-500/30 text-left hover:scale-[1.02] transition-transform active:scale-95"
                 >
                   <FilePlus className="w-8 h-8 mb-4 opacity-80" />
                   <h3 className="text-xl font-bold">{t.submit_report}</h3>
                   <p className="text-brand-100 text-sm opacity-90">{t.submit_sub}</p>
                 </button>

                 <button 
                   onClick={() => setView(AppView.TRACK)}
                   className="bg-white dark:bg-gray-800 p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 text-left hover:shadow-md transition-shadow active:scale-95"
                 >
                   <UserCircle className="w-6 h-6 mb-3 text-purple-500" />
                   <h3 className="font-bold dark:text-white">{t.track_case}</h3>
                   <p className="text-xs text-gray-500 mt-1">{t.track_sub}</p>
                 </button>

                 <button 
                   onClick={() => setView(AppView.SAFETY_PLAN)}
                   className="bg-white dark:bg-gray-800 p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 text-left hover:shadow-md transition-shadow active:scale-95"
                 >
                   <Shield className="w-6 h-6 mb-3 text-teal-500" />
                   <h3 className="font-bold dark:text-white">{t.safety_plan}</h3>
                   <p className="text-xs text-gray-500 mt-1">{t.safety_sub}</p>
                 </button>

                 <button 
                   onClick={() => setView(AppView.CHAT)}
                   className="col-span-2 bg-indigo-600 text-white p-5 rounded-2xl shadow-lg flex items-center justify-between hover:bg-indigo-700 active:scale-95 transition-all"
                 >
                    <div>
                      <h3 className="font-bold text-lg">{t.chat_ai}</h3>
                      <p className="text-indigo-200 text-xs">{t.chat_sub}</p>
                    </div>
                    <div className="bg-white/20 p-3 rounded-full">
                      <MessageCircleHeart className="w-5 h-5" />
                    </div>
                 </button>
               </div>
            </div>
          )}

          {view === AppView.REPORT && (
            <ReportView 
              onReportSubmitted={handleReportSubmitted} 
              lang={lang} 
              onSafetyPlanClick={() => setView(AppView.SAFETY_PLAN)}
            />
          )}

          {view === AppView.TRACK && <TrackView initialCode={lastTrackingCode} />}
          {view === AppView.EDUCATION && <EducationView />}
          {view === AppView.HOTLINES && <HotlinesView />}
          {view === AppView.CHAT && <ChatView />}
          {view === AppView.SAFETY_PLAN && <SafetyPlanView lang={lang} />}

          {/* Admin Views */}
          {view === AppView.ADMIN_LOGIN && (
            <AdminLogin 
              onLoginSuccess={() => setView(AppView.ADMIN_DASHBOARD)} 
              onBack={() => setView(AppView.HOME)} 
            />
          )}
          {view === AppView.ADMIN_DASHBOARD && (
            <AdminDashboard onLogout={() => setView(AppView.HOME)} />
          )}

        </main>

        {/* Bottom Navigation (Hidden on Admin Pages) */}
        {view !== AppView.ADMIN_LOGIN && view !== AppView.ADMIN_DASHBOARD && (
          <nav className="bg-white dark:bg-gray-900 border-t border-gray-200 dark:border-gray-800 flex justify-around px-2 pb-safe absolute bottom-0 w-full z-10">
            <NavButton target={AppView.HOME} icon={<Home className="w-6 h-6" />} label={t.nav_home} />
            <NavButton target={AppView.TRACK} icon={<UserCircle className="w-6 h-6" />} label={t.nav_track} />
            <NavButton target={AppView.CHAT} icon={<MessageCircleHeart className="w-6 h-6" />} label={t.nav_chat} />
            <NavButton target={AppView.HOTLINES} icon={<Phone className="w-6 h-6" />} label={t.nav_help} />
          </nav>
        )}
      </div>
    </div>
  );
};

export default App;

export enum AppView {
  HOME = 'home',
  REPORT = 'report',
  TRACK = 'track',
  EDUCATION = 'education',
  HOTLINES = 'hotlines',
  CHAT = 'chat',
  SAFETY_PLAN = 'safety_plan',
  ADMIN_LOGIN = 'admin_login',
  ADMIN_DASHBOARD = 'admin_dashboard',
}

export type Language = 'en' | 'sw';

export enum GBVType {
  PHYSICAL = 'Physical Violence',
  SEXUAL = 'Sexual Violence',
  EMOTIONAL = 'Emotional/Psychological',
  ECONOMIC = 'Economic Abuse',
  HARASSMENT = 'Sexual Harassment',
  OTHER = 'Other',
}

export enum ReportStatus {
  RECEIVED = 'Received',
  ASSIGNED = 'Assigned to Case Worker',
  IN_REVIEW = 'In Review',
  ACTION_TAKEN = 'Action Taken',
  RESOLVED = 'Resolved',
}

export interface Attachment {
  name: string;
  type: 'image' | 'video' | 'audio';
  url: string;
  file?: File;
}

export interface CaseUpdate {
  id: string;
  content: string;
  timestamp: string;
  author: string;
}

export interface Report {
  id: string;
  trackingCode: string;
  type: GBVType;
  location: string;
  description: string;
