/**
 * Trigger: When a report document is updated.
 * Goal: Check if 'assignedTo' changed, then notify the caseworker.
 */
exports.notifyCaseworkerAssignment = functions.firestore
  .document("reports/{reportId}")
  .onUpdate(async (change, context) => {
    const newData = change.after.data();
    const previousData = change.before.data();

    // Check if case was just assigned or reassigned
    if (newData.assignedTo && newData.assignedTo !== previousData.assignedTo) {
      const workerId = newData.assignedTo;
      const reportId = context.params.reportId;
      const trackingCode = newData.trackingCode;

      console.log(`Report ${reportId} assigned to ${workerId}. Fetching worker details...`);

      try {
        // Fetch Caseworker Details
        const workerDoc = await db.collection("caseworkers").doc(workerId).get();

        if (!workerDoc.exists) {
          console.error("Caseworker not found!");
          return null;
        }

        const worker = workerDoc.data();
        const workerEmail = worker.email;
        const workerPhone = worker.phone;

        // 1. Send Email
        const mailOptions = {
          from: `SafeVoice Admin <${GMAIL_EMAIL}>`,
          to: workerEmail,
          subject: `[New Assignment] Case #${trackingCode}`,
          html: `
            <h3>New Case Assignment</h3>
            <p>Hello ${worker.name},</p>
            <p>You have been assigned to a new case.</p>
            <ul>
              <li><strong>Tracking Code:</strong> ${trackingCode}</li>
              <li><strong>Incident Type:</strong> ${newData.type}</li>
              <li><strong>Location:</strong> ${newData.location}</li>
              <li><strong>Date Reported:</strong> ${new Date(newData.createdAt).toLocaleString()}</li>
            </ul>
            <p>Please log in to the admin dashboard to review the evidence and take action.</p>
            <br/>
            <p>SafeVoice Admin Team</p>
          `,
        };

        await transporter.sendMail(mailOptions);
        console.log(`Email sent to ${workerEmail}`);

        // 2. Send SMS (Twilio) - Uncomment to enable
        /*
        await client.messages.create({
           body: `SafeVoice Alert: You have been assigned Case #${trackingCode}. Type: ${newData.type}. Please check dashboard.`,
           from: TWILIO_PHONE,
           to: workerPhone
        });
        console.log(`SMS sent to ${workerPhone}`);
        */

      } catch (error) {
        console.error("Error sending notifications:", error);
      }
    }
    return null;
  });

import React, { useState } from 'react';
import { BackendService } from '../services/mockBackend';
import { Loader2, Lock, ArrowLeft, Users, Cloud } from 'lucide-react';

export const AdminLogin: React.FC<{ onLoginSuccess: () => void, onBack: () => void }> = ({ onLoginSuccess, onBack }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [showCredentials, setShowCredentials] = useState(false);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const success = await BackendService.adminLogin(email, password, rememberMe);
      if (success) {
        onLoginSuccess();
      } else {
        setError("Authentication failed. Check email/password or internet.");
      }
    } catch (e) {
      setError("Login error. Ensure you are connected to the internet.");
    } finally {
      setLoading(false);
    }
  };

  const fillCredentials = (e: string, p: string) => {
    setEmail(e);
    setPassword(p);
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-6 animate-fade-in bg-gray-50 dark:bg-gray-900">
      <button onClick={onBack} className="absolute top-6 left-6 flex items-center text-gray-500 hover:text-gray-800 dark:hover:text-white">
        <ArrowLeft className="w-5 h-5 mr-2" /> Back to App
      </button>

      <div className="w-full max-w-sm bg-white dark:bg-gray-800 rounded-2xl shadow-xl p-8 border border-gray-100 dark:border-gray-700">
        <div className="flex flex-col items-center mb-8">
          <div className="w-14 h-14 bg-brand-100 dark:bg-brand-900/30 rounded-2xl flex items-center justify-center text-brand-600 mb-4">
            <Lock className="w-8 h-8" />
          </div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Admin Portal</h1>
          <div className="flex items-center gap-1 mt-2 text-xs text-brand-600 bg-brand-50 px-2 py-1 rounded-full">
             <Cloud className="w-3 h-3" />
             <span>Firebase Secure Login</span>
          </div>
        </div>

        <form onSubmit={handleLogin} className="space-y-5">
          <div>
            <label className="block text-sm font-bold text-gray-500 uppercase mb-2">Email Address</label>
            <input 
              type="email" 
              value={email}
              onChange={e => setEmail(e.target.value)}
              placeholder="admin@safevoice.org"
              className="w-full p-4 rounded-xl border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 outline-none focus:border-brand-500 focus:ring-2 focus:ring-brand-200 transition-all text-lg"
              required
            />
          </div>
          <div>
            <label className="block text-sm font-bold text-gray-500 uppercase mb-2">Password</label>
            <input 
              type="password" 
              placeholder="••••••••"
              value={password}
              onChange={e => setPassword(e.target.value)}
              className="w-full p-4 rounded-xl border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 outline-none focus:border-brand-500 focus:ring-2 focus:ring-brand-200 transition-all text-lg"
              required
            />
          </div>

          <div className="flex items-center">
            <input
                id="remember-me"
                type="checkbox"
                checked={rememberMe}
                onChange={(e) => setRememberMe(e.target.checked)}
                className="w-4 h-4 text-brand-600 bg-gray-100 border-gray-300 rounded focus:ring-brand-500 dark:focus:ring-brand-600 dark:ring-offset-gray-800 focus:ring-2 dark:bg-gray-700 dark:border-gray-600 cursor-pointer"
            />
            <label htmlFor="remember-me" className="ml-2 text-sm font-medium text-gray-900 dark:text-gray-300 cursor-pointer">Remember me</label>
          </div>

          {error && <p className="text-red-500 text-base font-medium text-center bg-red-50 dark:bg-red-900/20 p-2 rounded-lg">{error}</p>}

          <button 
            type="submit"
            disabled={loading}
            className="w-full bg-gray-900 dark:bg-white text-white dark:text-gray-900 py-4 rounded-xl font-bold text-lg shadow-lg hover:opacity-90 transition-opacity flex justify-center items-center"
          >
            {loading ? <Loader2 className="animate-spin w-6 h-6" /> : 'Sign In'}
          </button>
        </form>

        <div className="mt-8 border-t border-gray-200 dark:border-gray-700 pt-6 flex flex-col gap-4">
          <button 
            onClick={() => setShowCredentials(!showCredentials)}
            className="flex items-center justify-center w-full text-brand-600 text-sm font-medium hover:underline"
