import React, { useState, useEffect } from 'react';
import { GBVType, Attachment, Language } from '../types';
import { BackendService } from '../services/mockBackend';
import { getTranslation } from '../services/translations';
import { AlertCircle, Camera, Mic, MapPin, Loader2, CheckCircle, FileUp, XCircle, Calendar, Crosshair, Shield, ArrowRight } from 'lucide-react';

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB Limit

interface ReportViewProps {
  onReportSubmitted: (code: string) => void;
  lang: Language;
  onSafetyPlanClick: () => void;
}

export const ReportView: React.FC<ReportViewProps> = ({ onReportSubmitted, lang, onSafetyPlanClick }) => {
  const t = getTranslation(lang);

  const [type, setType] = useState<GBVType>(GBVType.PHYSICAL);
  const [location, setLocation] = useState('');
  const [incidentDate, setIncidentDate] = useState('');
  const [description, setDescription] = useState('');
  const [files, setFiles] = useState<Attachment[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [gettingLocation, setGettingLocation] = useState(false);
  const [success, setSuccess] = useState(false);
  const [trackingCode, setTrackingCode] = useState('');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Auto-redirect timer reference to clear it if needed
  const [redirectTimer, setRedirectTimer] = useState<NodeJS.Timeout | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setErrorMsg(null);
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.size > MAX_FILE_SIZE) {
        setErrorMsg(`File "${file.name}" is too large. Maximum size is 5MB.`);
        return;
      }
      const newAttachment: Attachment = {
        name: file.name,
        type: file.type.startsWith('image') ? 'image' : file.type.startsWith('audio') ? 'audio' : 'video',
        url: URL.createObjectURL(file), 
        file: file 
      };
      setFiles([...files, newAttachment]);
    }
  };

  const removeFile = (index: number) => {
    const newFiles = [...files];
    newFiles.splice(index, 1);
    setFiles(newFiles);
  };

  const handleGetGPS = () => {
    if (!navigator.geolocation) {
        alert("Geolocation is not supported by your browser");
        return;
    }
    setGettingLocation(true);
    navigator.geolocation.getCurrentPosition(
        (position) => {
            // Success
            const { latitude, longitude } = position.coords;
            const gpsString = `${latitude.toFixed(5)}, ${longitude.toFixed(5)}`;
            setLocation(prev => prev ? `${prev} (${gpsString})` : gpsString);
            setGettingLocation(false);
        },
        (error) => {
            // Error
            console.error(error);
            alert("Unable to retrieve location. Please type it manually.");
            setGettingLocation(false);
        },
        { enableHighAccuracy: true, timeout: 10000 }
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMsg(null);

    if (!location.trim() || !description.trim()) {
        setErrorMsg("Please provide both a location and a description of the incident.");
        return;
    }

    let anonymousUserId = localStorage.getItem('safevoice_anon_id');
    if (!anonymousUserId) {
      anonymousUserId = crypto.randomUUID();
      localStorage.setItem('safevoice_anon_id', anonymousUserId);
    }

    setIsSubmitting(true);
    try {
      const report = await BackendService.createReport({
        type,
        location,
        description,
        incidentDate: incidentDate || new Date().toISOString(), // Use selected time or now
        attachments: files,
        anonymousUserId
      });
      setTrackingCode(report.trackingCode);
      setSuccess(true);

      // Auto-redirect after 1.5 seconds (reduced from 3s)
      const timer = setTimeout(() => {
        onReportSubmitted(report.trackingCode);
      }, 1500);
      setRedirectTimer(timer);

    } catch (error: any) {
      console.error("Submission Error:", error);
      let msg = "An unexpected error occurred. Please try again.";
      if (error instanceof Error) {
          if (error.message.includes("Network") || error.message.includes("fetch")) {
             msg = "Unable to connect to server. Please check your internet connection.";
          }
      }
      setErrorMsg(msg);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleManualRedirect = () => {
    if (redirectTimer) clearTimeout(redirectTimer);
    onReportSubmitted(trackingCode);
  };

  useEffect(() => {
    return () => {
      if (redirectTimer) clearTimeout(redirectTimer);
    };
  }, [redirectTimer]);

  if (success) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center p-6 animate-fade-in">
        <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mb-4">
          <CheckCircle className="w-10 h-10 text-green-600" />
        </div>
        <h2 className="text-2xl font-bold mb-2 text-gray-800 dark:text-white">Report Received</h2>
        <p className="text-gray-600 dark:text-gray-300 mb-6">Your tracking code is:</p>
        <div className="bg-gray-100 dark:bg-gray-800 p-4 rounded-xl mb-6 border-2 border-dashed border-gray-300 dark:border-gray-600">
          <span className="text-3xl font-mono font-bold text-brand-600 tracking-wider select-all">
            {trackingCode}
          </span>
        </div>

        <button 
          onClick={handleManualRedirect}
          className="bg-brand-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 hover:bg-brand-700 transition-colors shadow-lg"
        >
          Track Case Now <ArrowRight className="w-5 h-5" />
        </button>
        <p className="text-xs text-gray-400 mt-4">Redirecting automatically...</p>
      </div>
    );
  }

  return (
    <div className="p-4 pb-20 animate-slide-up">
      <h1 className="text-2xl font-bold mb-6 text-brand-700 dark:text-brand-400">{t.report_title}</h1>

      <div className="bg-yellow-50 dark:bg-yellow-900/20 border-l-4 border-yellow-400 p-4 mb-4 rounded-r">
        <div className="flex">
          <AlertCircle className="w-5 h-5 text-yellow-500 mr-2 flex-shrink-0" />
          <p className="text-sm text-yellow-700 dark:text-yellow-200">
            {t.safety_priority}
          </p>
        </div>
      </div>

      <div className="mb-6 flex justify-end">
         <button 
           type="button" 
           onClick={onSafetyPlanClick}
           className="text-sm text-brand-600 dark:text-brand-400 flex items-center hover:underline"
         >
           <Shield className="w-4 h-4 mr-1" />
           {t.not_ready_safety_plan}
         </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5">

        {errorMsg && (
          <div className="bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-300 p-4 rounded-xl text-sm flex items-start animate-fade-in border border-red-100 dark:border-red-800">
            <XCircle className="w-5 h-5 mr-2 flex-shrink-0" />
            <span>{errorMsg}</span>
          </div>
        )}

        {/* INCIDENT TYPE */}
        <div>
          <label className="block text-sm font-medium mb-1">{t.type_incident}</label>
          <select 
            value={type} 
            onChange={(e) => setType(e.target.value as GBVType)}
            className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none"
          >
            {Object.values(GBVType).map(t => (
              <option key={t} value={t}>{t}</option>
            ))}
          </select>
        </div>

        {/* TIME OF INCIDENT */}
        <div>
           <label className="block text-sm font-medium mb-1 flex items-center gap-1">
             <Calendar className="w-4 h-4 text-gray-400" />
             {t.time_incident}
           </label>
           <input 
             type="datetime-local"
             value={incidentDate}
             onChange={(e) => setIncidentDate(e.target.value)}
             className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none"
           />
        </div>

        {/* LOCATION WITH GPS */}
        <div>
          <label className="block text-sm font-medium mb-1">{t.location}</label>
          <div className="flex gap-2">
            <div className="relative flex-1">
                <MapPin className="absolute left-3 top-3.5 w-5 h-5 text-gray-400" />
                <input 
                type="text" 
                placeholder={t.location_placeholder}
                value={location}
                onChange={(e) => setLocation(e.target.value)}
                className="w-full pl-10 p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none"
                required
                />
            </div>
            <button 
                type="button"
                onClick={handleGetGPS}
                disabled={gettingLocation}
                className="bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-200 p-3 rounded-xl hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors flex items-center justify-center min-w-[50px]"
                title={t.use_gps}
            >
                {gettingLocation ? <Loader2 className="animate-spin w-5 h-5"/> : <Crosshair className="w-5 h-5" />}
            </button>
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium mb-1">{t.description}</label>
          <textarea 
            placeholder={t.desc_placeholder}
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            className="w-full p-3 h-32 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none resize-none"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium mb-2">{t.evidence}</label>
          <div className="flex gap-4 mb-4">
             <label className="flex flex-col items-center justify-center w-24 h-24 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400 transition-colors">
                <Camera className="w-6 h-6 text-gray-400 mb-1" />
                <span className="text-xs text-gray-500">{t.photo}</span>
                <input type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
             </label>
             <label className="flex flex-col items-center justify-center w-24 h-24 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400 transition-colors">
                <Mic className="w-6 h-6 text-gray-400 mb-1" />
                <span className="text-xs text-gray-500">{t.audio}</span>
                <input type="file" accept="audio/*" className="hidden" onChange={handleFileChange} />
             </label>
             <label className="flex flex-col items-center justify-center w-24 h-24 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400 transition-colors">
                <FileUp className="w-6 h-6 text-gray-400 mb-1" />
                <span className="text-xs text-gray-500">{t.video}</span>
                <input type="file" accept="video/*" className="hidden" onChange={handleFileChange} />
             </label>
          </div>
          {files.length > 0 && (
            <div className="space-y-2">
              {files.map((f, idx) => (
                <div key={idx} className="flex items-center justify-between text-sm p-2 bg-gray-100 dark:bg-gray-800 rounded-lg">
                  <div className="flex items-center overflow-hidden">
                    <CheckCircle className="w-4 h-4 text-green-500 mr-2 flex-shrink-0" />
                    <span className="truncate">{f.name}</span>
                  </div>
                  <button 
                    type="button" 
                    onClick={() => removeFile(idx)} 
                    className="text-red-500 hover:text-red-700 p-1"
                  >
                      <XCircle className="w-4 h-4" />
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        <button 
          type="submit" 
          disabled={isSubmitting}
          className="w-full bg-brand-600 hover:bg-brand-700 text-white p-4 rounded-xl font-bold shadow-lg shadow-brand-500/30 transition-all active:scale-95 disabled:opacity-70 flex justify-center items-center"
        >
          {isSubmitting ? (
             <>
               <Loader2 className="animate-spin w-5 h-5 mr-2" /> 
               {files.length > 0 ? 'Uploading Evidence...' : 'Submitting...'}
             </>
          ) : t.submit_btn}
        </button>
      </form>
    </div>
  );
};

