  // --- REPORTING API (HYBRID: SERVER -> FIRESTORE -> LOCAL) ---

  async createReport(data: any): Promise<Report> {
    // 1. Prepare Base Data
    const trackingCode = `SV-${Math.floor(1000 + Math.random() * 9000)}-${new Date().getFullYear()}`;
    let finalDescription = data.description;
    if (data.incidentDate) {
        finalDescription = `[INCIDENT TIME: ${new Date(data.incidentDate).toLocaleString()}]\n\n${data.description}`;
    }

    const reportBase = {
        trackingCode,
        type: data.type,
        location: data.location,
        description: finalDescription,
        anonymousUserId: data.anonymousUserId || 'anon',
        status: ReportStatus.RECEIVED,
        createdAt: new Date().toISOString(),
        statusHistory: [{ status: ReportStatus.RECEIVED, timestamp: new Date().toISOString() }],
        caseUpdates: []
    };

    // --- STRATEGY 1: SEND TO LOCAL NODE SERVER (If Configured) ---
    const serverUrl = getServerUrl();
    if (serverUrl && navigator.onLine) {
        try {
            const formData = new FormData();
            formData.append('type', data.type);
            formData.append('location', data.location);
            formData.append('description', finalDescription);
            formData.append('anonymousUserId', reportBase.anonymousUserId);
            if(data.incidentDate) formData.append('incidentDate', data.incidentDate);

            if (data.attachments) {
                data.attachments.forEach((att: Attachment) => {
                    if (att.file) formData.append('attachments', att.file);
                });
            }

            // Using fetch with timeout
            const controller = new AbortController();
            const id = setTimeout(() => controller.abort(), 8000); // 8s timeout

            const res = await fetch(`${serverUrl}/api/gbv-report`, {
                method: 'POST',
                body: formData,
                signal: controller.signal
            });
            clearTimeout(id);

            if (res.ok) {
                const json = await res.json();
                this.addToHistory(json.trackingCode);
                // Return a constructed report object (server usually returns simple success msg)
                return { ...reportBase, trackingCode: json.trackingCode, id: json.trackingCode };
            }
        } catch (e) {
            console.warn(`Server at ${serverUrl} unreachable. Falling back to Firebase...`);
        }
    }

    // --- STRATEGY 2: FIREBASE (Cloud) ---
    try {
      if (!navigator.onLine) throw new Error("Offline Mode forced");

      const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => reject(new Error("Network timeout")), 6000)
      );

      const firebaseOperation = async (): Promise<Report> => {
        // Upload Attachments
        const attachmentPromises = (data.attachments || []).map(async (att: Attachment) => {
           if (!att.file) return att;
           try {
               const storageRef = ref(storage, `reports/${Date.now()}_${att.name}`);
               await uploadBytes(storageRef, att.file);
               const downloadUrl = await getDownloadURL(storageRef);
               return { name: att.name, type: att.type, url: downloadUrl };
           } catch (e) {
               return { name: att.name, type: att.type, url: '' };
           }
        });

        const uploadedAttachments = await Promise.all(attachmentPromises);
        const newReport = { ...reportBase, attachments: uploadedAttachments };
        const docRef = await addDoc(collection(db, "reports"), newReport);

        return { id: docRef.id, ...newReport } as Report;
      };

      const result = await Promise.race([firebaseOperation(), timeoutPromise]) as Report;
      this.addToHistory(trackingCode);
      return result;

    } catch (error) {
      console.warn("Firebase submission failed. Switching to Local Storage.", error);

      // --- STRATEGY 3: LOCAL STORAGE (Offline) ---
      const fallbackReport: Report = {
        id: `local-${Date.now()}`,
        ...reportBase,
        attachments: [] 
      };

      const localReports = JSON.parse(localStorage.getItem(STORAGE_KEY_LOCAL_REPORTS) || '[]');
      localReports.unshift(fallbackReport);
      localStorage.setItem(STORAGE_KEY_LOCAL_REPORTS, JSON.stringify(localReports));

      this.addToHistory(trackingCode);
      return fallbackReport;
    }
  },

  async getReportByCode(code: string): Promise<Report | null> {
    // 1. Try Local Storage
    const localReports = JSON.parse(localStorage.getItem(STORAGE_KEY_LOCAL_REPORTS) || '[]');
    const localMatch = localReports.find((r: Report) => r.trackingCode === code);
    if (localMatch) return localMatch;

    // 2. Try Node Server
    const serverUrl = getServerUrl();
    if (serverUrl && navigator.onLine) {
        try {
            const res = await fetch(`${serverUrl}/api/gbv-report/${code}`);
            if (res.ok) return await res.json();
        } catch (e) {}
    }

    // 3. Try Firebase
    try {
      const q = query(collection(db, "reports"), where("trackingCode", "==", code));
      const querySnapshot = await getDocs(q);
      if (!querySnapshot.empty) {
        const docData = querySnapshot.docs[0].data();
        return { id: querySnapshot.docs[0].id, ...docData } as Report;
      }
    } catch (e) {}

    return null;
  },

  // --- ADMIN DASHBOARD SYNC (HYBRID POLLING + LISTENER) ---

  subscribeToReports(callback: (reports: Report[]) => void): () => void {
    const getLocalReports = () => JSON.parse(localStorage.getItem(STORAGE_KEY_LOCAL_REPORTS) || '[]');
    let localReports = getLocalReports();
    let firebaseReports: Report[] = [];
    let serverReports: Report[] = [];

    const mergeAndCallback = () => {
        // Merge strategy: Server > Firebase > Local
        // Use trackingCode as unique key
        const reportMap = new Map<string, Report>();

        [...localReports, ...firebaseReports, ...serverReports].forEach(r => {
             // If duplicate, overwrite with source priority order (Local gets overwritten by Firebase, which gets overwritten by Server)
             if (!reportMap.has(r.trackingCode)) {
                 reportMap.set(r.trackingCode, r);
             } else {
                 // Simple merge: prefer the one with more recent status or updates
                 // For now, let's just assume Server > Firebase
             }
        });

        // Actually, let's simple de-dupe
        const combined = Array.from(reportMap.values());
        combined.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
        callback(combined);
    };

    // 1. Initial Local Load
    mergeAndCallback();

    // 2. Poll Node Server (if configured)
    let serverInterval: any = null;
    const serverUrl = getServerUrl();
    if (serverUrl) {
        const fetchServer = async () => {
            try {
                const token = localStorage.getItem(STORAGE_KEY_SERVER_TOKEN);
                if (!token) return;

                const res = await fetch(`${serverUrl}/api/admin/reports`, {
                    headers: { 'Authorization': `Bearer ${token}` }
                });
                if (res.ok) {
                    serverReports = await res.json();
                    mergeAndCallback();
                }
            } catch (e) {
                console.warn("Server poll failed");
            }
        };
        fetchServer(); // Immediate
        serverInterval = setInterval(fetchServer, 5000); // Every 5s
    }

    // 3. Listen to Firebase
    let unsubscribeFirestore = () => {};
    try {
        const q = query(collection(db, "reports"), orderBy("createdAt", "desc"));
        unsubscribeFirestore = onSnapshot(q, (snapshot) => {
            firebaseReports = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as Report[];
            mergeAndCallback();
        }, (error) => {
            console.warn("Firestore sync error.", error);
        });
    } catch (e) {}

    return () => {
        unsubscribeFirestore();
        if (serverInterval) clearInterval(serverInterval);
    };
  },

  async updateReportStatus(id: string, status: ReportStatus): Promise<void> {
    // Try Server First
    const serverUrl = getServerUrl();
    if (serverUrl) {
        try {
             const token = localStorage.getItem(STORAGE_KEY_SERVER_TOKEN);
             await fetch(`${serverUrl}/api/admin/reports/${id}`, {
                 method: 'PATCH',
                 headers: { 
                     'Content-Type': 'application/json',
                     'Authorization': `Bearer ${token}`
                 },
                 body: JSON.stringify({ status })
             });
             return; // Assume success if no error thrown
        } catch(e) {}
    }

    // Fallback to Firebase/Local logic
    try {
        const reportRef = doc(db, "reports", id);
        const historyItem = { status, timestamp: new Date().toISOString() };
        await updateDoc(reportRef, {
            status: status,
            statusHistory: arrayUnion(historyItem)
        });
    } catch (e) {
        // Fallback Local
        const localReports = JSON.parse(localStorage.getItem(STORAGE_KEY_LOCAL_REPORTS) || '[]');
        const idx = localReports.findIndex((r: Report) => r.id === id);
        if (idx !== -1) {
            localReports[idx].status = status;
            localReports[idx].statusHistory.push({ status, timestamp: new Date().toISOString() });
            localStorage.setItem(STORAGE_KEY_LOCAL_REPORTS, JSON.stringify(localReports));
            return;
        }
        throw e;
    }
  },

  async addCaseUpdate(reportId: string, content: string): Promise<CaseUpdate> {
    const updateItem = { 
      id: Date.now().toString(), 
      content, 
      timestamp: new Date().toISOString(), 
      author: 'Case Worker' 
    };

    // Try Server First
    const serverUrl = getServerUrl();
    if (serverUrl) {
        try {
             const token = localStorage.getItem(STORAGE_KEY_SERVER_TOKEN);
             await fetch(`${serverUrl}/api/admin/reports/${reportId}/message`, {
                 method: 'POST',
                 headers: { 
                     'Content-Type': 'application/json',
                     'Authorization': `Bearer ${token}`
                 },
                 body: JSON.stringify({ content })
             });
             return updateItem;
        } catch(e) {}
    }

    try {
        const reportRef = doc(db, "reports", reportId);
        await updateDoc(reportRef, {
            caseUpdates: arrayUnion(updateItem)
        });
    } catch (e) {
        // Fallback Local
        const localReports = JSON.parse(localStorage.getItem(STORAGE_KEY_LOCAL_REPORTS) || '[]');
        const idx = localReports.findIndex((r: Report) => r.id === reportId);
        if (idx !== -1) {
            if (!localReports[idx].caseUpdates) localReports[idx].caseUpdates = [];
            localReports[idx].caseUpdates.push(updateItem);
            localStorage.setItem(STORAGE_KEY_LOCAL_REPORTS, JSON.stringify(localReports));
            return updateItem;
        }
        throw e;
    }
    return updateItem;
  },

  async assignCaseToWorker(reportId: string, workerId: string, workerName: string): Promise<void> {
    const timestamp = new Date().toISOString();
    const updates: any = {
        assignedTo: workerId,
        assignedToName: workerName,
        assignedAt: timestamp,
        status: ReportStatus.ASSIGNED,
        statusHistory: arrayUnion({ status: ReportStatus.ASSIGNED, timestamp })
    };

    try {
        const reportRef = doc(db, "reports", reportId);
        await updateDoc(reportRef, updates);
    } catch (e) {
         // Fallback Local
         const localReports = JSON.parse(localStorage.getItem(STORAGE_KEY_LOCAL_REPORTS) || '[]');
         const idx = localReports.findIndex((r: Report) => r.id === reportId);
         if (idx !== -1) {
             localReports[idx] = { ...localReports[idx], ...updates };
             localReports[idx].statusHistory.push({ status: ReportStatus.ASSIGNED, timestamp });
             localStorage.setItem(STORAGE_KEY_LOCAL_REPORTS, JSON.stringify(localReports));
             return;
         }
         throw e;
    }
  },

  // --- CASEWORKER & DYNAMIC CONTENT ---
  // (Simplified for brevity: Fetch from Firebase or fallback to Static)

  async addCaseworker(worker: Omit<Caseworker, 'id' | 'createdAt'>): Promise<void> {
    try { await addDoc(collection(db, "caseworkers"), { ...worker, createdAt: new Date().toISOString() }); } catch (e) {}
  },

  async updateCaseworker(id: string, data: Partial<Caseworker>): Promise<void> {
    try { await updateDoc(doc(db, "caseworkers", id), data); } catch (e) {}
  },

  async deleteCaseworker(id: string): Promise<void> {
    try { await deleteDoc(doc(db, "caseworkers", id)); } catch (e) {}
  },

  subscribeToCaseworkers(callback: (workers: Caseworker[]) => void): () => void {
    try {
        const q = query(collection(db, "caseworkers"), orderBy("name", "asc"));
        return onSnapshot(q, (snapshot) => {
            const workers = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as Caseworker[];
            callback(workers);
        }, () => callback([]));
    } catch (e) { callback([]); return () => {}; }
  },

  async getEducationModules(): Promise<EducationModule[]> {
    try {
      const q = query(collection(db, "education_modules"));
      const snapshot = await getDocs(q);
      if (!snapshot.empty) return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as EducationModule));
    } catch (e) {}
    return STATIC_EDUCATION_MODULES; 
  },

  async getHotlines(): Promise<Hotline[]> {
    try {
      const q = query(collection(db, "hotlines"));
      const snapshot = await getDocs(q);
      if (!snapshot.empty) return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Hotline));
    } catch (e) {}
    return STATIC_HOTLINES;
  },

  async getSupportCentres(lat: number, lng: number): Promise<SupportCentre[]> {
    try {
        const q = query(collection(db, "support_centres"));
        const snapshot = await getDocs(q);
        if (!snapshot.empty) return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as SupportCentre));
    } catch (e) {}
    return STATIC_SUPPORT_CENTRES;
  },

  async seedDatabase() {
    try {
        const batch = writeBatch(db);
        const hotlineSnapshot = await getDocs(collection(db, "hotlines"));
        if (hotlineSnapshot.empty) {
            STATIC_HOTLINES.forEach(h => { batch.set(doc(collection(db, "hotlines")), h); });
        }
        const eduSnapshot = await getDocs(collection(db, "education_modules"));
        if (eduSnapshot.empty) {
            STATIC_EDUCATION_MODULES.forEach(e => { batch.set(doc(collection(db, "education_modules")), e); });
        }
        await batch.commit();
        return true;
    } catch (e) { return false; }
  },

  addToHistory(code: string) {
    const history = JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
    if (!history.includes(code)) {
      history.unshift(code);
      localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(history));
    }
  },

  getHistory(): string[] {
    return JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
  },

  async checkConnection(): Promise<boolean> {
    return navigator.onLine; 
  }
};

