export const BackendService = {

  // --- AUTHENTICATION (ADMIN ONLY) ---

  async adminLogin(email: string, password: string, rememberMe: boolean = false): Promise<boolean> {
    let isAuthenticated = false;

    // 1. Try Local Server Auth First (if configured)
    const serverUrl = getServerUrl();
    if (serverUrl) {
        try {
            const res = await fetch(`${serverUrl}/api/admin/login`, {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({ email, password })
            });
            if (res.ok) {
                const data = await res.json();
                localStorage.setItem(STORAGE_KEY_SERVER_TOKEN, data.token);
                isAuthenticated = true; // Mark as success but continue to allow hybrid fallback
            }
        } catch(e) {
            console.warn("Server auth failed, falling back to Firebase/Local check");
        }
    }

    try {
      // 2. Try Real Firebase Login
      const persistenceType = rememberMe ? browserLocalPersistence : browserSessionPersistence;
      await setPersistence(auth, persistenceType);

      await signInWithEmailAndPassword(auth, email, password);
      return true;
    } catch (error) {
      console.warn("Firebase Auth Failed. Checking internal list...");

      // 3. Fallback: Check Demo Credentials directly
      const isValid = VALID_ADMINS.some(admin => admin.email === email && admin.password === password);

      if (isValid || isAuthenticated) {
          localStorage.setItem(STORAGE_KEY_MOCK_ADMIN, 'true');
          return true;
      }
      return false;
    }
  },

  async validateAdminSession(): Promise<boolean> {
    // 1. Check Mock/Server Session
    if (localStorage.getItem(STORAGE_KEY_MOCK_ADMIN) === 'true') {
        return true;
    }

    // 2. Check Real Firebase Session
    return new Promise((resolve) => {
        if (auth.currentUser) {
             auth.currentUser.getIdTokenResult(true) 
                .then(() => resolve(true))
                .catch(() => resolve(false));
             return;
        }

        const unsubscribe = auth.onAuthStateChanged(async (user) => {
            unsubscribe();
            if (user) {
                try {
                    await user.getIdToken(true);
                    resolve(true);
                } catch {
                    resolve(false);
                }
            } else {
                resolve(false);
            }
        });
    });
  },

  async logout(): Promise<void> {
    localStorage.removeItem(STORAGE_KEY_MOCK_ADMIN);
    localStorage.removeItem(STORAGE_KEY_SERVER_TOKEN);
    await auth.signOut();
  },

  // --- REPORTING API (HYBRID: SERVER -> FIRESTORE -> LOCAL) ---

  async createReport(data: any): Promise<Report> {
    // 1. Prepare Base Data
    const trackingCode = `SV-${Math.floor(1000 + Math.random() * 9000)}-${new Date().getFullYear()}`;
    let finalDescription = data.description;
    if (data.incidentDate) {
        finalDescription = `[INCIDENT TIME: ${new Date(data.incidentDate).toLocaleString()}]\n\n${data.description}`;
    }

    const reportBase = {
        trackingCode,
        type: data.type,
        location: data.location,
        description: finalDescription,
        anonymousUserId: data.anonymousUserId || 'anon',
        status: ReportStatus.RECEIVED,
        createdAt: new Date().toISOString(),
        statusHistory: [{ status: ReportStatus.RECEIVED, timestamp: new Date().toISOString() }],
        caseUpdates: []
    };

    // --- STRATEGY: FIREBASE CLOUD FIRESTORE ---
    try {
      if (!navigator.onLine) throw new Error("Offline Mode forced");

      const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => reject(new Error("Network timeout")), 10000)
      );

      const firebaseOperation = async (): Promise<Report> => {
        // Upload Attachments
        const attachmentPromises = (data.attachments || []).map(async (att: Attachment) => {
           if (!att.file) return att;
           try {
               const storageRef = ref(storage, `reports/${Date.now()}_${att.name}`);
               await uploadBytes(storageRef, att.file);
               const downloadUrl = await getDownloadURL(storageRef);
               return { name: att.name, type: att.type, url: downloadUrl };
           } catch (e) {
               return { name: att.name, type: att.type, url: '' };
           }
        });

        const uploadedAttachments = await Promise.all(attachmentPromises);
        const newReport = { ...reportBase, attachments: uploadedAttachments };

        // Save to Firestore
        const docRef = await addDoc(collection(db, "reports"), newReport);

        return { id: docRef.id, ...newReport } as Report;
      };

      const result = await Promise.race([firebaseOperation(), timeoutPromise]) as Report;
      this.addToHistory(trackingCode);
      return result;

    } catch (error) {
      console.warn("Firebase submission failed. Switching to Local Storage.", error);

      // --- FALLBACK: LOCAL STORAGE (Offline) ---
      const fallbackReport: Report = {
        id: `local-${Date.now()}`,
        ...reportBase,
        attachments: [] 
      };

      const localReports = JSON.parse(localStorage.getItem(STORAGE_KEY_LOCAL_REPORTS) || '[]');
      localReports.unshift(fallbackReport);
      localStorage.setItem(STORAGE_KEY_LOCAL_REPORTS, JSON.stringify(localReports));

      this.addToHistory(trackingCode);
      return fallbackReport;
    }
  },

  async getReportByCode(code: string): Promise<Report | null> {
    // 1. Try Local Storage
    const localReports = JSON.parse(localStorage.getItem(STORAGE_KEY_LOCAL_REPORTS) || '[]');
    const localMatch = localReports.find((r: Report) => r.trackingCode === code);
    if (localMatch) return localMatch;

    // 2. Try Firestore
    try {
      const q = query(collection(db, "reports"), where("trackingCode", "==", code));
      const querySnapshot = await getDocs(q);
      if (!querySnapshot.empty) {
        const docData = querySnapshot.docs[0].data();
        return { id: querySnapshot.docs[0].id, ...docData } as Report;
      }
    } catch (e) {}

    return null;
  },

  // --- ADMIN DASHBOARD SYNC (STRICT REAL-TIME) ---

  subscribeToReports(callback: (reports: Report[]) => void): () => void {
    console.log("Initializing Real-time Firestore Stream...");

    // We strictly use Firestore's onSnapshot to ensure we see reports from ALL devices.
    // Local storage reports on this device are NOT merged here to prevent confusion.
    // The Admin Dashboard should reflect the global 'Truth' in the database.

    let unsubscribe = () => {};

    try {
        const q = query(collection(db, "reports"), orderBy("createdAt", "desc"));

        unsubscribe = onSnapshot(q, (snapshot) => {
            const liveReports = snapshot.docs.map(doc => ({
                id: doc.id,
                ...doc.data()
            })) as Report[];

            console.log(`[Firestore Sync] Received ${liveReports.length} reports.`);
            callback(liveReports);
        }, (error) => {
            console.error("🔥 Firestore Listener Error:", error);
            // This will log permission-denied or network errors to the console
        });

    } catch (e) {
        console.error("Failed to setup Firestore listener:", e);
    }

    return unsubscribe;
  },

