  async adminLogin(email: string, password: string, rememberMe: boolean = false): Promise<boolean> {
    try {
      // 1. Try Supabase Auth
      const { data, error } = await supabase.auth.signInWithPassword({
        email,
        password,
      });

      if (!error && data.session) {
        return true;
      }

      // 2. Fallback: Check Demo Credentials directly (Useful for reviewers/demo mode)
