  async validateAdminSession(): Promise<boolean> {
    // 1. Check Mock Session
    if (localStorage.getItem(STORAGE_KEY_MOCK_ADMIN) === 'true') return true;

    // 2. Check Real Supabase Session
    const { data: { session } } = await supabase.auth.getSession();
    return !!session;
  },

