export const BackendService = {

  // --- AUTHENTICATION ---

  async adminLogin(email: string, password: string, rememberMe: boolean = false): Promise<boolean> {
    try {
      // 1. Try Supabase Auth
      const { data, error } = await supabase.auth.signInWithPassword({
        email,
        password,
      });

      if (!error && data.session) {
        return true;
      }

      // 2. Fallback: Check Demo Credentials directly (Useful for reviewers/demo mode)
      console.warn("Supabase Auth failed, checking demo list...");
      const isValid = VALID_ADMINS.some(admin => admin.email === email && admin.password === password);

      if (isValid) {
          localStorage.setItem(STORAGE_KEY_MOCK_ADMIN, 'true');
          return true;
      }
      return false;
    } catch (error) {
      console.error("Login Error:", error);
      return false;
    }
  },

  async validateAdminSession(): Promise<boolean> {
    // 1. Check Mock Session
    if (localStorage.getItem(STORAGE_KEY_MOCK_ADMIN) === 'true') return true;

    // 2. Check Real Supabase Session
    const { data: { session } } = await supabase.auth.getSession();
    return !!session;
  },

  async logout(): Promise<void> {
    localStorage.removeItem(STORAGE_KEY_MOCK_ADMIN);
    await supabase.auth.signOut();
  },

  // --- REPORTING API (SUPABASE) ---

  async createReport(data: any): Promise<Report> {
    const deviceId = localStorage.getItem('safevoice_anon_id') || 'unknown_device';
    const trackingCode = `SV-${Math.floor(1000 + Math.random() * 9000)}-${new Date().getFullYear()}`;

    console.group("🚀 STARTING SUPABASE SUBMISSION");
    console.log("📱 Device ID:", deviceId);
    console.log("🕒 Timestamp:", new Date().toISOString());

    let finalDescription = data.description;
    if (data.incidentDate) {
        finalDescription = `[INCIDENT TIME: ${new Date(data.incidentDate).toLocaleString()}]\n\n${data.description}`;
    }

    try {
      if (!navigator.onLine) throw new Error("Offline Mode forced");

      // 1. Upload Attachments to Supabase Storage
      const uploadedAttachments: Attachment[] = [];

      for (const att of (data.attachments || [])) {
        if (!att.file) continue;
        const fileExt = att.name.split('.').pop();
        const fileName = `${Date.now()}_${Math.random()}.${fileExt}`;
        const filePath = `${fileName}`;

        console.log(`📂 Uploading ${att.name}...`);

        const { error: uploadError } = await supabase.storage
          .from('evidence') // Make sure this bucket exists in Supabase
          .upload(filePath, att.file);

        if (uploadError) {
          console.error("Upload failed:", uploadError);
          continue;
        }

        const { data: { publicUrl } } = supabase.storage.from('evidence').getPublicUrl(filePath);
        uploadedAttachments.push({
            name: att.name,
            type: att.type,
            url: publicUrl
        });
      }

      // 2. Insert to Database
      console.log("🔥 Inserting into 'reports' table...");

      const reportPayload = {
        tracking_code: trackingCode,
        type: data.type,
        location: data.location,
        description: finalDescription,
        anonymous_user_id: data.anonymousUserId || 'anon',
        status: ReportStatus.RECEIVED,
        attachments: uploadedAttachments, // JSONB
        status_history: [{ status: ReportStatus.RECEIVED, timestamp: new Date().toISOString() }],
        case_updates: []
      };

      const { data: insertedData, error: dbError } = await supabase
        .from('reports')
        .insert(reportPayload)
        .select()
        .single();

      if (dbError) throw dbError;

      console.log("✅ SUCCESS! ID:", insertedData.id);
      console.groupEnd();

      this.addToHistory(trackingCode);
      return this.mapSupabaseToReport(insertedData);

    } catch (error: any) {
      console.error("❌ SUPABASE WRITE ERROR:", error);
      console.groupEnd();

      // Fallback: Local Storage
      const fallbackReport: Report = {
        id: `local-${Date.now()}`,
        trackingCode,
        type: data.type,
        location: data.location,
        description: finalDescription,
        anonymousUserId: data.anonymousUserId || 'anon',
        status: ReportStatus.RECEIVED,
        createdAt: new Date().toISOString(),
        attachments: [],
        statusHistory: [],
        caseUpdates: []
      };

      const localReports = JSON.parse(localStorage.getItem(STORAGE_KEY_LOCAL_REPORTS) || '[]');
      localReports.unshift(fallbackReport);
      localStorage.setItem(STORAGE_KEY_LOCAL_REPORTS, JSON.stringify(localReports));
      this.addToHistory(trackingCode);

      return fallbackReport;
    }
  },

  async getReportByCode(code: string): Promise<Report | null> {
    // 1. Try Local
    const localReports = JSON.parse(localStorage.getItem(STORAGE_KEY_LOCAL_REPORTS) || '[]');
    const localMatch = localReports.find((r: Report) => r.trackingCode === code);
    if (localMatch) return localMatch;

    // 2. Try Supabase
    try {
      const { data, error } = await supabase
        .from('reports')
        .select('*')
        .eq('tracking_code', code)
        .single();

      if (error) return null;
      return this.mapSupabaseToReport(data);
    } catch (e) {
      return null;
    }
  },

  // --- ADMIN DASHBOARD SYNC (SUPABASE REALTIME) ---

  subscribeToReports(callback: (reports: Report[]) => void): () => void {
    console.group("📡 SUPABASE REALTIME LISTENER");
    console.log("Subscribing to 'reports' table changes...");

    // 1. Fetch Initial Data
    const fetchInitial = async () => {
      const { data, error } = await supabase
        .from('reports')
        .select(`
          *,
          assigned_to_user:caseworkers!assigned_to (name)
        `)
        .order('created_at', { ascending: false });

      if (data) {
        callback(data.map(this.mapSupabaseToReport));
      }
      if (error) console.error("Initial fetch error:", error);
    };

    fetchInitial();

    // 2. Listen for Changes
    const channel = supabase
      .channel('public:reports')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'reports' }, (payload) => {
        console.log('⚡ Change received!', payload);
        // On any change, re-fetch to get the full joined data (caseworker names)
        // Optimization: In a huge app, update local state based on payload. For now, refetch is safer for joins.
        fetchInitial();
      })
      .subscribe();

    console.groupEnd();

    return () => {
      supabase.removeChannel(channel);
    };
  },

  // --- CASE MANAGEMENT ---

  subscribeToCaseworkers(callback: (workers: Caseworker[]) => void): () => void {
    const fetchWorkers = async () => {
      const { data } = await supabase.from('caseworkers').select('*').order('name');
      if (data) {
        callback(data.map(d => ({
            id: d.id,
            name: d.name,
            phone: d.phone,
            email: d.email,
            createdAt: d.created_at
        })));
      }
    };

    fetchWorkers();

    const channel = supabase
      .channel('public:caseworkers')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'caseworkers' }, () => {
        fetchWorkers();
      })
      .subscribe();

    return () => {
        supabase.removeChannel(channel);
    };
  },

  async addCaseworker(worker: Omit<Caseworker, 'id' | 'createdAt'>): Promise<void> {
    await supabase.from('caseworkers').insert(worker);
  },

  async updateCaseworker(id: string, data: Partial<Caseworker>): Promise<void> {
    await supabase.from('caseworkers').update(data).eq('id', id);
  },

  async deleteCaseworker(id: string): Promise<void> {
    await supabase.from('caseworkers').delete().eq('id', id);
  },

  // --- ASSIGNMENT & STATUS UPDATES ---

  async assignCaseToWorker(reportId: string, workerId: string, workerName: string): Promise<void> {
    const timestamp = new Date().toISOString();

    // 1. Update Database
    const { error } = await supabase
        .from('reports')
        .update({
            assigned_to: workerId,
            status: ReportStatus.ASSIGNED,
            // Append to JSONB arrays is tricky in raw SQL without functions, 
            // so we fetch, push, update or use a Postgres function.
            // Simplified here: We assume the client fetches first, but for concurrency safety:
        })
        .eq('id', reportId);

    if (error) throw error;

    // Also update history/status separately if needed or via a trigger
    // Ideally, a database trigger handles status_history updates.

    // 2. TRIGGER NOTIFICATION (Email/SMS)
    // Since we are client-side, we call a Supabase Edge Function
    try {
        console.log(`🔔 Triggering Notification to ${workerName}...`);
        const { data, error: fnError } = await supabase.functions.invoke('notify-caseworker', {
            body: { reportId, workerId }
        });

        if (fnError) {
            console.warn("Edge function failed, falling back to simulation.");
            // Simulation for demo purposes since we can't deploy Edge Function in this environment
            alert(`[SIMULATION]\nEmail sent to caseworker: ${workerName}\nSMS sent via Twilio.`);
        }
    } catch (e) {
        console.error("Notification failed", e);
    }
  },

  async updateReportStatus(id: string, status: ReportStatus): Promise<void> {
    const { data: current } = await supabase.from('reports').select('status_history').eq('id', id).single();
    const history = current?.status_history || [];
    history.push({ status, timestamp: new Date().toISOString() });

    await supabase.from('reports').update({
        status,
        status_history: history
    }).eq('id', id);
  },

  async addCaseUpdate(reportId: string, content: string): Promise<CaseUpdate> {
    const updateItem = { 
      id: Date.now().toString(), 
      content, 
      timestamp: new Date().toISOString(), 
      author: 'Case Worker' 
    };

    const { data: current } = await supabase.from('reports').select('case_updates').eq('id', reportId).single();
    const updates = current?.case_updates || [];
    updates.push(updateItem);

    await supabase.from('reports').update({ case_updates: updates }).eq('id', reportId);
    return updateItem;
  },

  // --- READ ONLY DATA ---

  async getEducationModules(): Promise<EducationModule[]> {
    return STATIC_EDUCATION_MODULES; 
  },

  async getHotlines(): Promise<Hotline[]> {
    return STATIC_HOTLINES;
  },

  async getSupportCentres(lat: number, lng: number): Promise<SupportCentre[]> {
    return STATIC_SUPPORT_CENTRES;
  },

  async seedDatabase() {
     // No-op for Supabase setup in this context, assuming tables exist
     return true;
  },

  // --- HELPERS ---

  mapSupabaseToReport(row: any): Report {
    // Map snake_case DB fields to camelCase TS interface
    return {
        id: row.id,
        trackingCode: row.tracking_code,
        type: row.type,
        location: row.location,
        description: row.description,
        attachments: row.attachments || [],
        status: row.status as ReportStatus,
        statusHistory: row.status_history || [],
        caseUpdates: row.case_updates || [],
        createdAt: row.created_at,
        anonymousUserId: row.anonymous_user_id,
        assignedTo: row.assigned_to,
        assignedToName: row.assigned_to_user?.name || undefined,
        assignedAt: row.updated_at // Approximated
    };
  },

  addToHistory(code: string) {
    const history = JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
    if (!history.includes(code)) {
      history.unshift(code);
      localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(history));
    }
  },

  getHistory(): string[] {
    return JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
  }
};

import React, { useState, useEffect } from 'react';
import { Caseworker } from '../types';
import { BackendService } from '../services/mockBackend';
import { Plus, User, Phone, Mail, Edit2, Trash2, X, Save, Loader2 } from 'lucide-react';

export const CaseWorkersView: React.FC = () => {
  const [workers, setWorkers] = useState<Caseworker[]>([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingWorker, setEditingWorker] = useState<Caseworker | null>(null);

  // Form State
  const [formData, setFormData] = useState({ name: '', phone: '', email: '' });
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    const unsubscribe = BackendService.subscribeToCaseworkers((data) => {
        setWorkers(data);
        setLoading(false);
    });
    return unsubscribe;
  }, []);

  const handleOpenModal = (worker?: Caseworker) => {
    if (worker) {
        setEditingWorker(worker);
        setFormData({ name: worker.name, phone: worker.phone, email: worker.email });
    } else {
        setEditingWorker(null);
        setFormData({ name: '', phone: '', email: '' });
    }
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true);
    try {
        if (editingWorker) {
            await BackendService.updateCaseworker(editingWorker.id, formData);
        } else {
            await BackendService.addCaseworker(formData);
        }
        setIsModalOpen(false);
    } catch (e) {
        alert("Operation failed.");
    } finally {
        setSubmitting(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (confirm("Are you sure you want to remove this case worker? This cannot be undone.")) {
        await BackendService.deleteCaseworker(id);
    }
  };

  return (
    <div className="p-6 h-full flex flex-col">
      <div className="flex justify-between items-center mb-6">
        <div>
            <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Case Workers</h2>
            <p className="text-sm text-gray-500">Manage staff members who handle cases.</p>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="bg-brand-600 text-white px-4 py-2 rounded-xl flex items-center gap-2 hover:bg-brand-700 transition-colors shadow-sm"
        >
          <Plus className="w-4 h-4" /> Add Worker
        </button>
      </div>

      <div className="flex-1 overflow-y-auto">
        {loading ? (
           <div className="flex justify-center py-10">
             <Loader2 className="w-6 h-6 animate-spin text-gray-400" />
           </div>
        ) : workers.length === 0 ? (
           <div className="text-center py-12 bg-gray-50 dark:bg-gray-800/50 rounded-xl border border-dashed border-gray-300 dark:border-gray-700">
             <User className="w-10 h-10 text-gray-300 mx-auto mb-2" />
             <p className="text-gray-500">No case workers found.</p>
           </div>
        ) : (
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
             {workers.map(worker => (
               <div key={worker.id} className="bg-white dark:bg-gray-800 p-5 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm hover:shadow-md transition-shadow group">
                 <div className="flex justify-between items-start mb-3">
                   <div className="flex items-center gap-3">
                     <div className="w-10 h-10 rounded-full bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 flex items-center justify-center font-bold">
                       {worker.name.charAt(0)}
                     </div>
                     <div>
                       <h3 className="font-bold text-gray-900 dark:text-white">{worker.name}</h3>
                       <p className="text-xs text-gray-400">Added {new Date(worker.createdAt).toLocaleDateString()}</p>
                     </div>
                   </div>
                   <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                     <button onClick={() => handleOpenModal(worker)} className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg">
                       <Edit2 className="w-4 h-4" />
                     </button>
                     <button onClick={() => handleDelete(worker.id)} className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg">
                       <Trash2 className="w-4 h-4" />
                     </button>
                   </div>
                 </div>

                 <div className="space-y-2 mt-4 text-sm">
                   <div className="flex items-center gap-2 text-gray-600 dark:text-gray-400">
                     <Phone className="w-4 h-4" />
                     <span>{worker.phone}</span>
                   </div>
                   <div className="flex items-center gap-2 text-gray-600 dark:text-gray-400">
                     <Mail className="w-4 h-4" />
                     <span>{worker.email}</span>
                   </div>
                 </div>
               </div>
             ))}
           </div>
        )}
      </div>

      {/* Add/Edit Modal */}
      {isModalOpen && (
        <div className="absolute inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
           <div className="bg-white dark:bg-gray-900 w-full max-w-md rounded-2xl shadow-2xl overflow-hidden animate-slide-up">
              <div className="flex justify-between items-center p-4 border-b border-gray-100 dark:border-gray-800">
                <h3 className="font-bold text-lg dark:text-white">{editingWorker ? 'Edit Worker' : 'New Case Worker'}</h3>
                <button onClick={() => setIsModalOpen(false)}><X className="w-5 h-5 text-gray-500" /></button>
              </div>
              <form onSubmit={handleSubmit} className="p-6 space-y-4">
                 <div>
                   <label className="block text-sm font-medium mb-1 dark:text-gray-300">Full Name</label>
                   <input 
                     required
                     type="text" 
                     value={formData.name}
                     onChange={e => setFormData({...formData, name: e.target.value})}
                     className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 outline-none focus:ring-2 focus:ring-brand-500"
                   />
                 </div>
                 <div>
                   <label className="block text-sm font-medium mb-1 dark:text-gray-300">Phone Number</label>
                   <input 
                     required
                     type="tel" 
                     value={formData.phone}
                     onChange={e => setFormData({...formData, phone: e.target.value})}
                     className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 outline-none focus:ring-2 focus:ring-brand-500"
                   />
                 </div>
                 <div>
                   <label className="block text-sm font-medium mb-1 dark:text-gray-300">Email Address</label>
                   <input 
                     required
                     type="email" 
                     value={formData.email}
                     onChange={e => setFormData({...formData, email: e.target.value})}
                     className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 outline-none focus:ring-2 focus:ring-brand-500"
                   />
                 </div>
                 <button 
                   type="submit"
                   disabled={submitting}
                   className="w-full bg-brand-600 text-white py-3 rounded-xl font-bold flex justify-center items-center gap-2 hover:bg-brand-700 disabled:opacity-70 mt-4"
                 >
                   {submitting ? <Loader2 className="animate-spin w-5 h-5" /> : <Save className="w-5 h-5" />}
                   {editingWorker ? 'Update' : 'Save Worker'}
                 </button>
              </form>
           </div>
        </div>
      )}
    </div>
  );
};

