               <button onClick={() => setShowSettings(false)} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full">
                 <X className="w-5 h-5 text-gray-500" />
               </button>
             </div>

             <p className="text-sm text-gray-600 dark:text-gray-300 mb-4">
               To sync reports across devices on the same WiFi, enter the IP address of the computer running <code>npm start</code> or <code>node server.js</code>.
             </p>

             <div className="mb-4">
               <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Local Server URL</label>
               <input 
                 type="text" 
                 placeholder="http://192.168.1.5:3000"
                 value={serverUrl}
