                 className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-600 bg-gray-50 dark:bg-gray-900 text-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand-500 font-mono text-sm"
               />
               <p className="text-[10px] text-gray-400 mt-2"> Leave empty to use Firebase (Cloud) or Offline Mode only.</p>
             </div>

             <div className="flex gap-3">
               <button 
                 onClick={saveServerSettings}
                 className="flex-1 bg-brand-600 hover:bg-brand-700 text-white py-3 rounded-xl font-bold transition-colors"
               >
                 Save & Connect
               </button>
             </div>
          </div>
        </div>
      )}
