import { Report, ReportStatus, EducationModule, Hotline, SupportCentre, CaseUpdate, Attachment, Caseworker } from '../types';

// DEFAULT STRAPI URL (Can be overridden in Admin Login Settings)
const DEFAULT_STRAPI_URL = 'http://localhost:1337';

const getStrapiUrl = () => {
  const stored = localStorage.getItem('safevoice_server_url');
  return stored ? stored.replace(/\/$/, "") : DEFAULT_STRAPI_URL;
};

// HELPER: Map Strapi 'attributes' structure to our flat Types
const mapStrapiReport = (id: string, attrs: any): Report => {
  // Handle attachments mapping from Strapi Media format
  const attachments: Attachment[] = attrs.attachments?.data?.map((file: any) => ({
    name: file.attributes.name,
    type: file.attributes.mime.startsWith('image') ? 'image' : 
          file.attributes.mime.startsWith('video') ? 'video' : 'audio',
    url: `${getStrapiUrl()}${file.attributes.url}`, // Strapi returns relative URLs
    file: undefined
  })) || [];

  return {
    id: id.toString(),
    trackingCode: attrs.trackingCode,
    type: attrs.type,
    location: attrs.location,
    description: attrs.description,
    status: attrs.status,
    anonymousUserId: attrs.anonymousUserId,
    createdAt: attrs.createdAt,
    statusHistory: attrs.statusHistory || [],
    caseUpdates: attrs.caseUpdates || [],
    attachments: attachments,
    assignedTo: attrs.assignedTo?.data?.id,
    assignedToName: attrs.assignedTo?.data?.attributes?.name,
    assignedAt: attrs.assignedAt
  };
};

export const BackendService = {

  // --- AUTHENTICATION (STRAPI) ---

  async adminLogin(identifier: string, password: string, rememberMe: boolean = false): Promise<boolean> {
    try {
      const response = await fetch(`${getStrapiUrl()}/api/auth/local`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ identifier, password }),
      });

      const data = await response.json();

      if (data.jwt) {
        if (rememberMe) {
            localStorage.setItem('strapi_jwt', data.jwt);
            localStorage.setItem('strapi_user', JSON.stringify(data.user));
        } else {
            sessionStorage.setItem('strapi_jwt', data.jwt);
            sessionStorage.setItem('strapi_user', JSON.stringify(data.user));
        }
        return true;
      }
      return false;
    } catch (error) {
      console.error("Strapi Login Error:", error);
      return false;
    }
  },

  async adminRegister(email: string, password: string): Promise<{ success: boolean; message?: string }> {
    try {
      const username = email.split('@')[0]; // Auto-generate username from email

      const response = await fetch(`${getStrapiUrl()}/api/auth/local/register`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, email, password }),
      });

      const data = await response.json();

      if (data.jwt) {
        sessionStorage.setItem('strapi_jwt', data.jwt);
        sessionStorage.setItem('strapi_user', JSON.stringify(data.user));
        return { success: true };
      } else {
        return { 
            success: false, 
            message: data.error?.message || "Registration failed. Email might be taken." 
        };
      }
    } catch (error) {
      return { success: false, message: "Connection to Strapi server failed." };
    }
  },

  async validateAdminSession(): Promise<boolean> {
    const jwt = localStorage.getItem('strapi_jwt') || sessionStorage.getItem('strapi_jwt');
    if (!jwt) return false;

    // Optional: Verify token via /api/users/me
    try {
        const response = await fetch(`${getStrapiUrl()}/api/users/me`, {
            headers: { Authorization: `Bearer ${jwt}` }
        });
        return response.ok;
    } catch {
        return false;
    }
  },

  async logout(): Promise<void> {
    localStorage.removeItem('strapi_jwt');
    localStorage.removeItem('strapi_user');
    sessionStorage.removeItem('strapi_jwt');
    sessionStorage.removeItem('strapi_user');
  },

  getToken(): string | null {
      return localStorage.getItem('strapi_jwt') || sessionStorage.getItem('strapi_jwt');
  },

  // --- REPORTING API (STRAPI UPLOAD & CREATE) ---

  async createReport(data: any): Promise<Report> {
    const trackingCode = `SV-${Math.floor(1000 + Math.random() * 9000)}-${new Date().getFullYear()}`;

    // 1. Upload Files First (If any)
    const uploadedFileIds: number[] = [];

    if (data.attachments && data.attachments.length > 0) {
        const formData = new FormData();
        data.attachments.forEach((att: Attachment) => {
            if (att.file) {
                formData.append('files', att.file, att.name);
            }
        });

        try {
            const uploadRes = await fetch(`${getStrapiUrl()}/api/upload`, {
                method: 'POST',
                body: formData // No Content-Type header, browser sets it for FormData
            });
            const uploadData = await uploadRes.json();
            if (Array.isArray(uploadData)) {
                uploadData.forEach((f: any) => uploadedFileIds.push(f.id));
            }
        } catch (e) {
            console.error("File upload failed", e);
        }
    }

    // 2. Create Report Entry
    let finalDescription = data.description;
    if (data.incidentDate) {
        finalDescription = `[INCIDENT TIME: ${new Date(data.incidentDate).toLocaleString()}]\n\n${data.description}`;
    }

    const payload = {
        data: {
            trackingCode,
            type: data.type,
            location: data.location,
            description: finalDescription,
            status: ReportStatus.RECEIVED,
            anonymousUserId: data.anonymousUserId || 'anon',
            statusHistory: [{ status: ReportStatus.RECEIVED, timestamp: new Date().toISOString() }],
            caseUpdates: [],
            attachments: uploadedFileIds // Link the uploaded files
        }
    };

    const response = await fetch(`${getStrapiUrl()}/api/reports`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
    });

    const resData = await response.json();

    if (!response.ok) {
        throw new Error(resData.error?.message || "Failed to create report");
    }

    // Add locally for history
    this.addToHistory(trackingCode);

    return mapStrapiReport(resData.data.id, resData.data.attributes);
  },

  async getReportByCode(code: string): Promise<Report | null> {
    try {
        const qs = `filters[trackingCode][$eq]=${code}&populate=*`;
        const response = await fetch(`${getStrapiUrl()}/api/reports?${qs}`);
        const resData = await response.json();

        if (resData.data && resData.data.length > 0) {
            return mapStrapiReport(resData.data[0].id, resData.data[0].attributes);
        }
        return null;
    } catch (e) {
        console.error(e);
        return null;
    }
  },

  // --- DASHBOARD (POLLING STRAPI) ---

  subscribeToReports(callback: (reports: Report[]) => void): () => void {
    const fetchReports = async () => {
        const jwt = this.getToken();
        if (!jwt) return;

        try {
            // Fetch latest reports, populate attachments
            const response = await fetch(`${getStrapiUrl()}/api/reports?sort=createdAt:desc&populate=*`, {
                headers: { Authorization: `Bearer ${jwt}` }
            });
            const resData = await response.json();

            if (resData.data) {
                const mapped = resData.data.map((item: any) => mapStrapiReport(item.id, item.attributes));
                callback(mapped);
            }
        } catch (e) {
            console.error("Polling error", e);
        }
    };

    fetchReports(); // Initial
    const interval = setInterval(fetchReports, 5000); // Poll every 5s (Strapi has no native realtime socket by default)
    return () => clearInterval(interval);
  },

  async updateReportStatus(id: string, status: ReportStatus): Promise<void> {
    const jwt = this.getToken();

    // Get current history to append
    const currentReport = await this.getReportById(id); // Helper needed
    const newHistory = [...(currentReport?.statusHistory || []), { status, timestamp: new Date().toISOString() }];

    await fetch(`${getStrapiUrl()}/api/reports/${id}`, {
        method: 'PUT',
        headers: { 
            'Content-Type': 'application/json',
            Authorization: `Bearer ${jwt}`
        },
        body: JSON.stringify({
            data: {
                status,
                statusHistory: newHistory
            }
        })
    });
  },

  async addCaseUpdate(reportId: string, content: string): Promise<CaseUpdate> {
    const jwt = this.getToken();
    const updateItem = { 
        id: Date.now().toString(), 
        content, 
        timestamp: new Date().toISOString(), 
        author: 'Case Worker' 
    };

    const currentReport = await this.getReportById(reportId);
    const newUpdates = [...(currentReport?.caseUpdates || []), updateItem];

    await fetch(`${getStrapiUrl()}/api/reports/${reportId}`, {
        method: 'PUT',
        headers: { 
            'Content-Type': 'application/json',
            Authorization: `Bearer ${jwt}`
        },
        body: JSON.stringify({
            data: { caseUpdates: newUpdates }
        })
    });
    return updateItem;
  },

  async assignCaseToWorker(reportId: string, workerId: string, workerName: string): Promise<void> {
    const jwt = this.getToken();
    const timestamp = new Date().toISOString();

    const currentReport = await this.getReportById(reportId);
    const newHistory = [...(currentReport?.statusHistory || []), { status: ReportStatus.ASSIGNED, timestamp }];

    await fetch(`${getStrapiUrl()}/api/reports/${reportId}`, {
        method: 'PUT',
        headers: { 
            'Content-Type': 'application/json',
            Authorization: `Bearer ${jwt}`
        },
        body: JSON.stringify({
            data: {
                assignedTo: workerId, // Assuming relation field
                assignedToName: workerName, // Keep flat for ease, or use relation logic
                assignedAt: timestamp,
                status: ReportStatus.ASSIGNED,
                statusHistory: newHistory
            }
        })
    });
  },

  // Helper to get raw object for updates
  async getReportById(id: string): Promise<Report | null> {
    const jwt = this.getToken();
    try {
        const response = await fetch(`${getStrapiUrl()}/api/reports/${id}?populate=*`, {
            headers: { Authorization: `Bearer ${jwt}` }
        });
        const resData = await response.json();
        return resData.data ? mapStrapiReport(resData.data.id, resData.data.attributes) : null;
    } catch { return null; }
  },

  // --- CASEWORKERS ---

  async addCaseworker(worker: Omit<Caseworker, 'id' | 'createdAt'>): Promise<void> {
    const jwt = this.getToken();
    await fetch(`${getStrapiUrl()}/api/caseworkers`, {
        method: 'POST',
        headers: { 
            'Content-Type': 'application/json',
            Authorization: `Bearer ${jwt}`
        },
        body: JSON.stringify({ data: worker })
    });
  },

  async updateCaseworker(id: string, data: Partial<Caseworker>): Promise<void> {
    const jwt = this.getToken();
    await fetch(`${getStrapiUrl()}/api/caseworkers/${id}`, {
        method: 'PUT',
        headers: { 
            'Content-Type': 'application/json',
            Authorization: `Bearer ${jwt}`
        },
        body: JSON.stringify({ data })
    });
  },

  async deleteCaseworker(id: string): Promise<void> {
    const jwt = this.getToken();
    await fetch(`${getStrapiUrl()}/api/caseworkers/${id}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${jwt}` }
    });
  },

  subscribeToCaseworkers(callback: (workers: Caseworker[]) => void): () => void {
    const fetchWorkers = async () => {
        const jwt = this.getToken();
        if (!jwt) return;
        try {
            const response = await fetch(`${getStrapiUrl()}/api/caseworkers`, {
                headers: { Authorization: `Bearer ${jwt}` }
            });
            const resData = await response.json();
            if (resData.data) {
                const mapped = resData.data.map((item: any) => ({
                    id: item.id.toString(),
                    ...item.attributes
                }));
                callback(mapped);
            }
        } catch {}
    };
    fetchWorkers();
    const interval = setInterval(fetchWorkers, 10000);
    return () => clearInterval(interval);
  },

  // --- STATIC / FALLBACKS ---

