import React, { useState, useEffect } from 'react';
import { BackendService } from '../services/mockBackend';
import { Loader2, Lock, ArrowLeft, Cloud, Settings, X, Wifi, CheckCircle2, AlertCircle } from 'lucide-react';

export const AdminLogin: React.FC<{ onLoginSuccess: () => void, onBack: () => void }> = ({ onLoginSuccess, onBack }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [isRegistering, setIsRegistering] = useState(false);

  // Server Config State
  const [showSettings, setShowSettings] = useState(false);
  const [serverUrl, setServerUrl] = useState('');

  useEffect(() => {
    setServerUrl(localStorage.getItem('safevoice_server_url') || 'http://localhost:1337');
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      if (isRegistering) {
        // Validation
        if (password !== confirmPassword) {
            setError("Passwords do not match.");
            setLoading(false);
            return;
        }

        // REGISTER FLOW (Optimized: Auto-logins on success)
        const result = await BackendService.adminRegister(email, password);
        if (result.success) {
           onLoginSuccess(); // Directly enter dashboard
        } else {
           setError(result.message || "Registration failed.");
        }
      } else {
        // LOGIN FLOW
        const success = await BackendService.adminLogin(email, password, rememberMe);
        if (success) {
          onLoginSuccess();
        } else {
          setError("Authentication failed. Check credentials or ensure you are an authorized admin.");
        }
      }
    } catch (e) {
      setError("Operation failed. Ensure you are connected to the network.");
    } finally {
      setLoading(false);
    }
  };

  const saveServerSettings = () => {
    if (serverUrl) {
      // Remove trailing slash
      const cleanUrl = serverUrl.replace(/\/$/, "");
      localStorage.setItem('safevoice_server_url', cleanUrl);
      alert(`Strapi Server configured to: ${cleanUrl}`);
    } else {
      localStorage.removeItem('safevoice_server_url');
      alert("Server configuration cleared.");
    }
    setShowSettings(false);
  };

  const passwordsMatch = password && confirmPassword && password === confirmPassword;

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-6 animate-fade-in bg-gray-50 dark:bg-gray-900 relative">
      <button onClick={onBack} className="absolute top-6 left-6 flex items-center text-gray-500 hover:text-gray-800 dark:hover:text-white">
        <ArrowLeft className="w-5 h-5 mr-2" /> Back to App
      </button>

      <button 
        onClick={() => setShowSettings(true)} 
        className="absolute top-6 right-6 text-gray-400 hover:text-brand-600 transition-colors p-2"
        title="Server Settings"
      >
        <Settings className="w-6 h-6" />
      </button>

      <div className="w-full max-w-sm bg-white dark:bg-gray-800 rounded-2xl shadow-xl p-8 border border-gray-100 dark:border-gray-700">
        <div className="flex flex-col items-center mb-8">
          <div className="w-14 h-14 bg-brand-100 dark:bg-brand-900/30 rounded-2xl flex items-center justify-center text-brand-600 mb-4">
            <Lock className="w-8 h-8" />
          </div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">{isRegistering ? 'Create Admin Account' : 'Admin Portal'}</h1>
          <div className="flex items-center gap-1 mt-2 text-xs text-brand-600 bg-brand-50 px-2 py-1 rounded-full">
             <Cloud className="w-3 h-3" />
             <span>Strapi CMS Access</span>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          <div>
            <label className="block text-sm font-bold text-gray-500 uppercase mb-2">Email Address</label>
            <input 
              type="email" 
              value={email}
              onChange={e => setEmail(e.target.value)}
              placeholder="admin@safevoice.org"
              className="w-full p-4 rounded-xl border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 outline-none focus:border-brand-500 focus:ring-2 focus:ring-brand-200 transition-all text-lg"
              required
            />
          </div>
          <div>
            <label className="block text-sm font-bold text-gray-500 uppercase mb-2">Password</label>
            <input 
              type="password" 
              placeholder="••••••••"
              value={password}
              onChange={e => setPassword(e.target.value)}
              className="w-full p-4 rounded-xl border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 outline-none focus:border-brand-500 focus:ring-2 focus:ring-brand-200 transition-all text-lg"
              required
              minLength={6}
            />
          </div>

          {isRegistering && (
             <div className="animate-slide-up">
               <label className="block text-sm font-bold text-gray-500 uppercase mb-2">Confirm Password</label>
               <div className="relative">
                 <input 
                   type="password" 
                   placeholder="••••••••"
                   value={confirmPassword}
                   onChange={e => setConfirmPassword(e.target.value)}
                   className={`w-full p-4 rounded-xl border ${passwordsMatch ? 'border-green-500 focus:border-green-500 focus:ring-green-200' : 'border-gray-300 dark:border-gray-600 focus:border-brand-500 focus:ring-brand-200'} bg-white dark:bg-gray-700 outline-none focus:ring-2 transition-all text-lg pr-12`}
                   required
                   minLength={6}
                 />
                 {confirmPassword && (
                    <div className="absolute right-4 top-4">
                        {passwordsMatch ? (
                            <CheckCircle2 className="w-6 h-6 text-green-500" />
                        ) : (
                            <AlertCircle className="w-6 h-6 text-red-400" />
                        )}
                    </div>
                 )}
               </div>
             </div>
          )}

          <div className="flex items-center">
                <input
                    id="remember-me"
                    type="checkbox"
                    checked={rememberMe}
                    onChange={(e) => setRememberMe(e.target.checked)}
                    className="w-4 h-4 text-brand-600 bg-gray-100 border-gray-300 rounded focus:ring-brand-500 dark:focus:ring-brand-600 dark:ring-offset-gray-800 focus:ring-2 dark:bg-gray-700 dark:border-gray-600 cursor-pointer"
                />
                <label htmlFor="remember-me" className="ml-2 text-sm font-medium text-gray-900 dark:text-gray-300 cursor-pointer">Remember me</label>
          </div>

          {error && <p className="text-red-500 text-base font-medium text-center bg-red-50 dark:bg-red-900/20 p-2 rounded-lg border border-red-100 dark:border-red-900">{error}</p>}

          <button 
            type="submit"
            disabled={loading || (isRegistering && !passwordsMatch)}
            className="w-full bg-gray-900 dark:bg-white text-white dark:text-gray-900 py-4 rounded-xl font-bold text-lg shadow-lg hover:opacity-90 transition-opacity flex justify-center items-center disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {loading ? <Loader2 className="animate-spin w-6 h-6" /> : (isRegistering ? 'Register & Login' : 'Sign In')}
          </button>
        </form>

        <div className="mt-6 text-center">
            <button 
                type="button"
                onClick={() => { setIsRegistering(!isRegistering); setError(''); setConfirmPassword(''); }}
                className="text-brand-600 hover:text-brand-800 text-sm font-semibold hover:underline"
            >
                {isRegistering ? 'Already have an account? Sign In' : 'New Admin? Create Account'}
            </button>
        </div>
      </div>

      {/* Server Config Modal */}
      {showSettings && (
        <div className="absolute inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in">
          <div className="bg-white dark:bg-gray-800 w-full max-w-md rounded-2xl shadow-2xl overflow-hidden p-6">
             <div className="flex justify-between items-center mb-4">
               <h3 className="font-bold text-xl dark:text-white flex items-center gap-2">
                 <Wifi className="w-5 h-5 text-brand-600" /> Strapi Config
               </h3>
               <button onClick={() => setShowSettings(false)} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full">
                 <X className="w-5 h-5 text-gray-500" />
               </button>
             </div>

             <p className="text-sm text-gray-600 dark:text-gray-300 mb-4">
               Enter the URL of your deployed Strapi CMS instance. Defaults to localhost.
             </p>

             <div className="mb-4">
               <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Strapi Server URL</label>
               <input 
                 type="text" 
                 placeholder="http://localhost:1337"
                 value={serverUrl}
                 onChange={(e) => setServerUrl(e.target.value)}
                 className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-600 bg-gray-50 dark:bg-gray-900 text-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand-500 font-mono text-sm"
               />
             </div>

             <div className="flex gap-3">
               <button 
                 onClick={saveServerSettings}
                 className="flex-1 bg-brand-600 hover:bg-brand-700 text-white py-3 rounded-xl font-bold transition-colors"
               >
                 Save & Connect
               </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

import { Report, ReportStatus, EducationModule, Hotline, SupportCentre, CaseUpdate, Attachment, Caseworker } from '../types';
