import { Report, ReportStatus, EducationModule, Hotline, SupportCentre, CaseUpdate, Attachment, Caseworker } from '../types';
import { Client, Account, Databases, Storage, ID, Query, Permission, Role } from 'appwrite';

// APPWRITE CONFIGURATION
const PROJECT_ID = '6932991f001974451b3e';
const ENDPOINT = 'https://tor.cloud.appwrite.io/v1';
const DATABASE_ID = 'safevoice_db';
const REPORTS_COL = 'reports';
const CASEWORKERS_COL = 'caseworkers';
const BUCKET_ID = '6932a0db0029060bf585'; 

// Initialize Appwrite
const client = new Client()
    .setEndpoint(ENDPOINT)
    .setProject(PROJECT_ID);

const account = new Account(client);
const databases = new Databases(client);
const storage = new Storage(client);

// 5 PRE-DEFINED ADMINS
const ADMIN_LIST = [
    { email: 'admin@safevoice.org', name: 'System Admin' },
    { email: 'manager@safevoice.org', name: 'Case Manager' },
    { email: 'supervisor@safevoice.org', name: 'Field Supervisor' },
    { email: 'coord@safevoice.org', name: 'Coordinator' },
    { email: 'director@safevoice.org', name: 'Director' }
];
const DEFAULT_PASS = 'password123';

// HELPER: Map Appwrite Document (snake_case) to Report Type (camelCase)
const mapDocumentToReport = (doc: any): Report => {
    // Map Attachment IDs to URLs
    const attachments: Attachment[] = (doc.attachment_ids || []).map((fileId: string) => {
        try {
            return {
                name: 'Attachment', 
                type: 'image', 
                url: storage.getFileView(BUCKET_ID, fileId).href,
                file: undefined
            };
        } catch (e) {
            return { name: 'Error', type: 'image', url: '', file: undefined };
        }
    });

    return {
        id: doc.$id,
        trackingCode: doc.tracking_code,
        type: doc.type,
        location: doc.location,
        description: doc.description,
        status: doc.status as ReportStatus,
        anonymousUserId: doc.anonymous_user_id,
        createdAt: doc.$createdAt,
        statusHistory: doc.status_history ? JSON.parse(doc.status_history) : [],
        caseUpdates: doc.case_updates ? JSON.parse(doc.case_updates) : [],
        attachments: attachments,
        assignedTo: doc.assigned_to,
        assignedToName: doc.assigned_to_name,
        assignedAt: doc.$updatedAt 
    };
};

export const BackendService = {

    // --- AUTHENTICATION ---

    async adminLogin(email: string, password: string, rememberMe: boolean = false): Promise<boolean> {
        try {
            // Check if already logged in
            try {
                await account.get();
                return true;
            } catch {}

            await account.createEmailPasswordSession(email, password);
            return true;
        } catch (error) {
            console.error("Appwrite Login Error:", error);
            return false;
        }
    },

    // Create the 5 requested admin accounts
    async seedAdmins(): Promise<{ success: boolean; message: string }> {
        let createdCount = 0;
        let errors = [];
        try {
            for (const admin of ADMIN_LIST) {
                try {
                    await account.create(ID.unique(), admin.email, DEFAULT_PASS, admin.name);
                    createdCount++;
                } catch (e: any) {
                    if (e.code === 409) console.log(`${admin.email} already exists.`);
                    else errors.push(`${admin.email}: ${e.message}`);
                }
            }
            return { 
                success: true, 
                message: `Process complete. Created ${createdCount} new admins. Default password: ${DEFAULT_PASS}. Errors: ${errors.length}` 
            };
