        const trackingCode = `SV-${Math.floor(1000 + Math.random() * 9000)}-${new Date().getFullYear()}`;
        let finalDescription = data.description;
        if (data.incidentDate) {
            finalDescription = `[INCIDENT TIME: ${new Date(data.incidentDate).toLocaleString()}]\n\n${data.description}`;
        }

        try {
            // 1. Ensure Anonymous Session for submission
            try {
                await account.get();
            } catch {
                await account.createAnonymousSession();
            }

            // 2. Upload Attachments
            const attachmentIds: string[] = [];
            if (data.attachments && data.attachments.length > 0) {
                for (const att of data.attachments) {
                    if (att.file) {
                        try {
                            const file = await storage.createFile(BUCKET_ID, ID.unique(), att.file);
                            attachmentIds.push(file.$id);
                        } catch (uploadError) {
                            console.error("Failed to upload file", uploadError);
                        }
                    }
                }
            }

            // 3. Create Document (using snake_case attributes as requested)
            const payload = {
                tracking_code: trackingCode,
                type: data.type,
                location: data.location,
                description: finalDescription,
                status: ReportStatus.RECEIVED,
                anonymous_user_id: data.anonymousUserId || 'anon',
                status_history: JSON.stringify([{ status: ReportStatus.RECEIVED, timestamp: new Date().toISOString() }]),
                case_updates: JSON.stringify([]),
                attachment_ids: attachmentIds,
                assigned_to: null,
                assigned_to_name: null
            };

            const doc = await databases.createDocument(
                DATABASE_ID,
                REPORTS_COL,
                ID.unique(),
                payload,
                [
                    Permission.read(Role.any()), // Allow user to track later via code
                    Permission.update(Role.users()), // Admins can update
                    Permission.read(Role.users()), 
                ]
            );

            this.addToHistory(trackingCode);
            return mapDocumentToReport(doc);

        } catch (error: any) {
            console.error("Appwrite Create Report Error:", error);
            throw new Error(error.message || "Failed to submit report via Appwrite");
        }
    },

