            // 2. Upload Attachments
            const attachmentIds: string[] = [];
            if (data.attachments && data.attachments.length > 0) {
                for (const att of data.attachments) {
                    if (att.file) {
                        try {
                            const file = await storage.createFile(BUCKET_ID, ID.unique(), att.file);
                            attachmentIds.push(file.$id);
                        } catch (uploadError) {
                            console.error("Failed to upload file", uploadError);
                            // We continue even if file upload fails, to ensure report is submitted
                        }
                    }
                }
            }

            // 3. Create Document (using snake_case attributes as requested)
            const payload = {
                tracking_code: trackingCode,
                type: data.type,
                location: data.location,
                description: finalDescription,
                status: ReportStatus.RECEIVED,
                anonymous_user_id: data.anonymousUserId || 'anon',
                status_history: JSON.stringify([{ status: ReportStatus.RECEIVED, timestamp: new Date().toISOString() }]),
                case_updates: JSON.stringify([]),
                attachment_ids: attachmentIds,
                assigned_to: null,
                assigned_to_name: null
            };

            const doc = await databases.createDocument(
                DATABASE_ID,
                REPORTS_COL,
                ID.unique(),
                payload,
                [
                    Permission.read(Role.any()), // Allow user to track later via code
                    Permission.update(Role.users()), // Admins can update
                    Permission.read(Role.users()), 
                ]
            );

            this.addToHistory(trackingCode);
            return mapDocumentToReport(doc);

        } catch (error: any) {
            console.error("Appwrite Create Report Error:", error);
            // Throw specific error for UI to handle
            if (error instanceof AppwriteException) {
                if (error.code === 0) {
                     throw new Error("Connection failed. Please add this domain to Appwrite Platforms.");
                }
                throw new Error(`Server Error: ${error.message}`);
            }
            throw new Error(error.message || "Failed to submit report via Appwrite");
        }
    },

    async getReportByCode(code: string): Promise<Report | null> {
        try {
            const response = await databases.listDocuments(
                DATABASE_ID,
                REPORTS_COL,
                [Query.equal('tracking_code', code)]
            );
            if (response.documents.length > 0) {
                return mapDocumentToReport(response.documents[0]);
            }
            return null;
        } catch (e) {
            console.error("Fetch Error", e);
            return null;
        }
    },

    // --- REALTIME DASHBOARD ---

    subscribeToReports(callback: (reports: Report[]) => void): () => void {
        let allReports: Report[] = [];

        // 1. Initial Fetch
        const fetchInitial = async () => {
            try {
                const res = await databases.listDocuments(
                    DATABASE_ID, 
                    REPORTS_COL, 
                    [Query.orderDesc('$createdAt')]
                );
                allReports = res.documents.map(mapDocumentToReport);
                callback(allReports);
            } catch (e) {
                console.error("Initial fetch failed", e);
            }
        };

        fetchInitial();

        // 2. Realtime Subscription
        try {
            const unsubscribe = client.subscribe(
                `databases.${DATABASE_ID}.collections.${REPORTS_COL}.documents`,
                (response) => {
                    const eventType = response.events[0];
                    const payload = response.payload as any;
                    const r = mapDocumentToReport(payload);

                    if (eventType.includes('create')) {
                        allReports = [r, ...allReports];
                    } else if (eventType.includes('update')) {
                        allReports = allReports.map(ex => ex.id === r.id ? r : ex);
                    } else if (eventType.includes('delete')) {
                        allReports = allReports.filter(ex => ex.id !== r.id);
                    }
                    callback([...allReports]);
                }
            );
            return unsubscribe;
        } catch (e) {
            console.warn("Realtime not available");
            return () => {};
        }
    },

    // --- ADMIN ACTIONS ---

    async updateReportStatus(id: string, status: ReportStatus): Promise<void> {
        // Fetch current to append history
        const currentDoc = await databases.getDocument(DATABASE_ID, REPORTS_COL, id);
        const history = currentDoc.status_history ? JSON.parse(currentDoc.status_history) : [];
        history.push({ status, timestamp: new Date().toISOString() });

        await databases.updateDocument(DATABASE_ID, REPORTS_COL, id, {
            status,
            status_history: JSON.stringify(history)
        });
    },

    async addCaseUpdate(reportId: string, content: string): Promise<CaseUpdate> {
        const updateItem = {
            id: Date.now().toString(),
            content,
            timestamp: new Date().toISOString(),
            author: 'Case Worker'
        };

        const currentDoc = await databases.getDocument(DATABASE_ID, REPORTS_COL, reportId);
        const updates = currentDoc.case_updates ? JSON.parse(currentDoc.case_updates) : [];
        updates.push(updateItem);

        await databases.updateDocument(DATABASE_ID, REPORTS_COL, reportId, {
            case_updates: JSON.stringify(updates)
        });

        return updateItem;
    },

    async assignCaseToWorker(reportId: string, workerId: string, workerName: string): Promise<void> {
        const timestamp = new Date().toISOString();

        // Update Document
        const currentDoc = await databases.getDocument(DATABASE_ID, REPORTS_COL, reportId);
        const history = currentDoc.status_history ? JSON.parse(currentDoc.status_history) : [];
        history.push({ status: ReportStatus.ASSIGNED, timestamp });

        await databases.updateDocument(DATABASE_ID, REPORTS_COL, reportId, {
            assigned_to: workerId,
            assigned_to_name: workerName,
            status: ReportStatus.ASSIGNED,
            status_history: JSON.stringify(history)
        });

        // Trigger Notification (simulated as Appwrite Function log)
        console.log(`[Appwrite Function Mock] Email sent to worker ${workerName} regarding report ${reportId}`);
    },

    // --- CASEWORKERS ---

    subscribeToCaseworkers(callback: (workers: Caseworker[]) => void): () => void {
        const fetchWorkers = async () => {
            try {
                const res = await databases.listDocuments(DATABASE_ID, CASEWORKERS_COL);
                const mapped = res.documents.map((d: any) => ({
                    id: d.$id,
                    name: d.name,
                    phone: d.phone,
                    email: d.email,
                    createdAt: d.$createdAt
                }));
                callback(mapped);
            } catch (e) {
                console.error("Failed to fetch workers", e);
            }
        };

        fetchWorkers();

        const unsubscribe = client.subscribe(
            `databases.${DATABASE_ID}.collections.${CASEWORKERS_COL}.documents`,
            () => fetchWorkers() // Refresh full list on any change
        );
        return unsubscribe;
    },

    async addCaseworker(worker: Omit<Caseworker, 'id' | 'createdAt'>): Promise<void> {
        await databases.createDocument(DATABASE_ID, CASEWORKERS_COL, ID.unique(), worker);
    },

    async updateCaseworker(id: string, data: Partial<Caseworker>): Promise<void> {
        await databases.updateDocument(DATABASE_ID, CASEWORKERS_COL, id, data);
    },

    async deleteCaseworker(id: string): Promise<void> {
        await databases.deleteDocument(DATABASE_ID, CASEWORKERS_COL, id);
    },

    // --- STATIC DATA / UTILS ---

    async getEducationModules(): Promise<EducationModule[]> {
        return [
            { id: '1', title: 'What is GBV?', description: 'Understanding the basics.', imageUrl: 'https://images.unsplash.com/photo-1573164713988-8665fc963095?auto=format&fit=crop&q=80&w=1000', content: `Gender-Based Violence (GBV) refers to harmful acts...` },
            { id: '2', title: 'Warning Signs', description: 'Early signs of abuse.', imageUrl: 'https://images.unsplash.com/photo-1590650516494-0c8e4a4dd67e?auto=format&fit=crop&q=80&w=1000', content: `Abuse isn't always physical...` },
            { id: '3', title: 'Legal Rights', description: 'Protection under law.', imageUrl: 'https://images.unsplash.com/photo-1589829085413-56de8ae18c73?auto=format&fit=crop&q=80&w=1000', content: `In Kenya, you have rights...` }
        ];
    },

    async getHotlines(): Promise<Hotline[]> {
        return [
            { id: '1', name: 'National GBV Helpline', number: '1195', category: 'Emergency' },
            { id: '2', name: 'Police Emergency', number: '999', category: 'Emergency' },
            { id: '3', name: 'FIDA Kenya (Legal Aid)', number: '0800720501', category: 'Legal' },
            { id: '4', name: 'Childline Kenya', number: '116', category: 'Emergency' },
            { id: '5', name: 'LVCT Health', number: '1190', category: 'Counseling' },
        ];
    },

    async getSupportCentres(lat: number, lng: number): Promise<SupportCentre[]> {
        return [
            { id: '1', name: 'GVRC - Nairobi Women\'s Hospital', address: 'Hurlingham, Nairobi', type: 'Medical', distance: '2.5 km' },
            { id: '2', name: 'Kenyatta National Hospital', address: 'Upper Hill', type: 'Medical', distance: '4.0 km' },
            { id: '3', name: 'MSF Lavender House', address: 'Mathare, Nairobi', type: 'Medical', distance: '6.2 km' }
        ];
    },

    async seedDatabase() {
        return (await this.seedAdmins()).success;
    },

    addToHistory(code: string) {
        const STORAGE_KEY_HISTORY = 'safevoice_report_history';
        const history = JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
        if (!history.includes(code)) {
            history.unshift(code);
            localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(history));
        }
    },

    getHistory(): string[] {
        const STORAGE_KEY_HISTORY = 'safevoice_report_history';
        return JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
    },

    async checkConnection(): Promise<{success: boolean, message?: string}> {
        try {
            // Lightest network check: try to list files with a limit of 1, or just check account
            // Checking account is safer as it verifies the Project ID validity too
            await account.getSession('current').catch(() => {
                // Ignore if not logged in, we just want to see if the network request 'reached' Appwrite
                // If it reached, it returns 401 (which is fine), if network failed, it throws Error
            });
            return { success: true };
        } catch (e: any) {
             // Appwrite throws an error object. Code 0 usually means Network Error / CORS
             if (e.code === 0 || e.message?.includes('Network')) {
                 return { success: false, message: "Network Error: Could not connect to Appwrite. Check your internet or CORS settings." };
             }
             if (e.code === 404 || e.code === 400) {
                 return { success: true }; // Connected, just not logged in or invalid ID, but server is reachable
             }
             return { success: false, message: e.message };
        }
    }
};

import React, { useState, useEffect } from 'react';
import { GBVType, Attachment, Language } from '../types';
import { BackendService } from '../services/mockBackend';
import { getTranslation } from '../services/translations';
import { AlertCircle, Camera, Mic, MapPin, Loader2, CheckCircle, FileUp, XCircle, Calendar, Crosshair, Shield, ArrowRight } from 'lucide-react';

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB Limit

interface ReportViewProps {
  onReportSubmitted: (code: string) => void;
  lang: Language;
  onSafetyPlanClick: () => void;
}

export const ReportView: React.FC<ReportViewProps> = ({ onReportSubmitted, lang, onSafetyPlanClick }) => {
  const t = getTranslation(lang);

  const [type, setType] = useState<GBVType>(GBVType.PHYSICAL);
  const [location, setLocation] = useState('');
  const [incidentDate, setIncidentDate] = useState('');
  const [description, setDescription] = useState('');
  const [files, setFiles] = useState<Attachment[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [gettingLocation, setGettingLocation] = useState(false);
  const [success, setSuccess] = useState(false);
  const [trackingCode, setTrackingCode] = useState('');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Auto-redirect timer reference to clear it if needed
  const [redirectTimer, setRedirectTimer] = useState<ReturnType<typeof setTimeout> | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setErrorMsg(null);
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.size > MAX_FILE_SIZE) {
        setErrorMsg(`File "${file.name}" is too large. Maximum size is 5MB.`);
        return;
      }
      const newAttachment: Attachment = {
        name: file.name,
        type: file.type.startsWith('image') ? 'image' : file.type.startsWith('audio') ? 'audio' : 'video',
        url: URL.createObjectURL(file), 
        file: file 
      };
      setFiles([...files, newAttachment]);
    }
  };

  const removeFile = (index: number) => {
    const newFiles = [...files];
    newFiles.splice(index, 1);
    setFiles(newFiles);
  };

  const handleGetGPS = () => {
    if (!navigator.geolocation) {
        alert("Geolocation is not supported by your browser");
        return;
    }
    setGettingLocation(true);
    navigator.geolocation.getCurrentPosition(
        (position) => {
            // Success
            const { latitude, longitude } = position.coords;
            const gpsString = `${latitude.toFixed(5)}, ${longitude.toFixed(5)}`;
            setLocation(prev => prev ? `${prev} (${gpsString})` : gpsString);
            setGettingLocation(false);
        },
        (error) => {
            // Error
            console.error(error);
            alert("Unable to retrieve location. Please type it manually.");
            setGettingLocation(false);
        },
        { enableHighAccuracy: true, timeout: 10000 }
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMsg(null);

    if (!location.trim() || !description.trim()) {
        setErrorMsg("Please provide both a location and a description of the incident.");
        return;
    }

    let anonymousUserId = localStorage.getItem('safevoice_anon_id');
    if (!anonymousUserId) {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
          anonymousUserId = crypto.randomUUID();
      } else {
          // Fallback UUID for insecure contexts
          anonymousUserId = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
            var r = Math.random() * 16 | 0, v = c === 'x' ? r : (r & 0x3 | 0x8);
            return v.toString(16);
          });
      }
      localStorage.setItem('safevoice_anon_id', anonymousUserId);
    }

    setIsSubmitting(true);
    try {
      const report = await BackendService.createReport({
        type,
        location,
        description,
        incidentDate: incidentDate || new Date().toISOString(), // Use selected time or now
        attachments: files,
        anonymousUserId
      });
      setTrackingCode(report.trackingCode);
      setSuccess(true);

      // Auto-redirect after 1.5 seconds (reduced from 3s)
      const timer = setTimeout(() => {
        onReportSubmitted(report.trackingCode);
      }, 1500);
      setRedirectTimer(timer);

    } catch (error: any) {
      console.error("Submission Error Details:", error);
      // Directly show the error message to help debug connection issues
      setErrorMsg(error.message || "An unexpected error occurred.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleManualRedirect = () => {
    if (redirectTimer) clearTimeout(redirectTimer);
    onReportSubmitted(trackingCode);
  };

  useEffect(() => {
    return () => {
      if (redirectTimer) clearTimeout(redirectTimer);
    };
  }, [redirectTimer]);

  if (success) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center p-6 animate-fade-in">
        <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mb-4">
          <CheckCircle className="w-10 h-10 text-green-600" />
        </div>
        <h2 className="text-2xl font-bold mb-2 text-gray-800 dark:text-white">Report Received</h2>
        <p className="text-gray-600 dark:text-gray-300 mb-6">Your tracking code is:</p>
        <div className="bg-gray-100 dark:bg-gray-800 p-4 rounded-xl mb-6 border-2 border-dashed border-gray-300 dark:border-gray-600">
          <span className="text-3xl font-mono font-bold text-brand-600 tracking-wider select-all">
            {trackingCode}
          </span>
        </div>

        <button 
          onClick={handleManualRedirect}
          className="bg-brand-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 hover:bg-brand-700 transition-colors shadow-lg"
        >
          Track Case Now <ArrowRight className="w-5 h-5" />
        </button>
        <p className="text-xs text-gray-400 mt-4">Redirecting automatically...</p>
      </div>
    );
  }

  return (
    <div className="p-4 pb-20 animate-slide-up">
      <h1 className="text-2xl font-bold mb-6 text-brand-700 dark:text-brand-400">{t.report_title}</h1>

      <div className="bg-yellow-50 dark:bg-yellow-900/20 border-l-4 border-yellow-400 p-4 mb-4 rounded-r">
        <div className="flex">
          <AlertCircle className="w-5 h-5 text-yellow-500 mr-2 flex-shrink-0" />
          <p className="text-sm text-yellow-700 dark:text-yellow-200">
            {t.safety_priority}
          </p>
        </div>
      </div>

      <div className="mb-6 flex justify-end">
         <button 
           type="button" 
           onClick={onSafetyPlanClick}
           className="text-sm text-brand-600 dark:text-brand-400 flex items-center hover:underline"
         >
           <Shield className="w-4 h-4 mr-1" />
           {t.not_ready_safety_plan}
         </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5">

        {errorMsg && (
          <div className="bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-300 p-4 rounded-xl text-sm flex flex-col items-start animate-fade-in border border-red-100 dark:border-red-800 break-words w-full">
            <div className="flex items-center mb-1 font-bold">
               <XCircle className="w-5 h-5 mr-2 flex-shrink-0" />
               <span>Submission Failed</span>
            </div>
            <span className="text-xs sm:text-sm">{errorMsg}</span>
          </div>
        )}

        {/* INCIDENT TYPE */}
        <div>
          <label className="block text-sm font-medium mb-1">{t.type_incident}</label>
          <select 
            value={type} 
            onChange={(e) => setType(e.target.value as GBVType)}
            className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none"
          >
            {Object.values(GBVType).map(t => (
              <option key={t} value={t}>{t}</option>
            ))}
          </select>
        </div>

        {/* TIME OF INCIDENT */}
        <div>
           <label className="block text-sm font-medium mb-1 flex items-center gap-1">
             <Calendar className="w-4 h-4 text-gray-400" />
             {t.time_incident}
           </label>
           <input 
             type="datetime-local"
             value={incidentDate}
             onChange={(e) => setIncidentDate(e.target.value)}
             className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none"
           />
        </div>

        {/* LOCATION WITH GPS */}
        <div>
          <label className="block text-sm font-medium mb-1">{t.location}</label>
          <div className="flex gap-2">
            <div className="relative flex-1">
                <MapPin className="absolute left-3 top-3.5 w-5 h-5 text-gray-400" />
                <input 
                type="text" 
                placeholder={t.location_placeholder}
                value={location}
                onChange={(e) => setLocation(e.target.value)}
                className="w-full pl-10 p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none"
                required
                />
            </div>
            <button 
                type="button"
                onClick={handleGetGPS}
                disabled={gettingLocation}
                className="bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-200 p-3 rounded-xl hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors flex items-center justify-center min-w-[50px]"
                title={t.use_gps}
            >
                {gettingLocation ? <Loader2 className="animate-spin w-5 h-5"/> : <Crosshair className="w-5 h-5" />}
            </button>
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium mb-1">{t.description}</label>
          <textarea 
            placeholder={t.desc_placeholder}
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            className="w-full p-3 h-32 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none resize-none"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium mb-2">{t.evidence}</label>
          <div className="flex gap-4 mb-4">
             <label className="flex flex-col items-center justify-center w-24 h-24 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400 transition-colors">
                <Camera className="w-6 h-6 text-gray-400 mb-1" />
                <span className="text-xs text-gray-500">{t.photo}</span>
                <input type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
             </label>
             <label className="flex flex-col items-center justify-center w-24 h-24 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400 transition-colors">
                <Mic className="w-6 h-6 text-gray-400 mb-1" />
                <span className="text-xs text-gray-500">{t.audio}</span>
                <input type="file" accept="audio/*" className="hidden" onChange={handleFileChange} />
             </label>
             <label className="flex flex-col items-center justify-center w-24 h-24 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400 transition-colors">
                <FileUp className="w-6 h-6 text-gray-400 mb-1" />
                <span className="text-xs text-gray-500">{t.video}</span>
                <input type="file" accept="video/*" className="hidden" onChange={handleFileChange} />
             </label>
          </div>
          {files.length > 0 && (
            <div className="space-y-2">
              {files.map((f, idx) => (
                <div key={idx} className="flex items-center justify-between text-sm p-2 bg-gray-100 dark:bg-gray-800 rounded-lg">
                  <div className="flex items-center overflow-hidden">
                    <CheckCircle className="w-4 h-4 text-green-500 mr-2 flex-shrink-0" />
                    <span className="truncate">{f.name}</span>
                  </div>
                  <button 
                    type="button" 
                    onClick={() => removeFile(idx)} 
                    className="text-red-500 hover:text-red-700 p-1"
                  >
                      <XCircle className="w-4 h-4" />
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        <button 
          type="submit" 
          disabled={isSubmitting}
          className="w-full bg-brand-600 hover:bg-brand-700 text-white p-4 rounded-xl font-bold shadow-lg shadow-brand-500/30 transition-all active:scale-95 disabled:opacity-70 flex justify-center items-center"
        >
          {isSubmitting ? (
             <>
               <Loader2 className="animate-spin w-5 h-5 mr-2" /> 
               {files.length > 0 ? 'Uploading Evidence...' : 'Submitting...'}
             </>
          ) : t.submit_btn}
        </button>
      </form>
    </div>
  );
};

