// HELPER: Map Appwrite Document (snake_case) to Report Type (camelCase)
const mapDocumentToReport = (doc: any): Report => {
    // Map Attachment IDs to URLs
    const attachments: Attachment[] = (doc.attachment_ids || []).map((fileId: string) => {
