                        timestamp: new Date().toISOString(), 
                        author: 'System (Offline)' 
                    }],
                    attachments: data.attachments || [],
                    assignedTo: undefined
                };

                const offlineReports = JSON.parse(localStorage.getItem(OFFLINE_REPORTS_KEY) || '[]');
                offlineReports.push(offlineReport);
                localStorage.setItem(OFFLINE_REPORTS_KEY, JSON.stringify(offlineReports));

                this.addToHistory(trackingCode);
                return offlineReport;
            }

            throw error;
        }
    },

    async getReportByCode(code: string): Promise<Report | null> {
        // 1. Check Offline Storage First
        const offlineReports = JSON.parse(localStorage.getItem(OFFLINE_REPORTS_KEY) || '[]');
        const localMatch = offlineReports.find((r: any) => r.trackingCode === code);
        if (localMatch) {
            return localMatch;
        }

        // 2. Check Online
        try {
            const response = await databases.listDocuments(
                CONFIG.databaseId,
                CONFIG.collectionId,
                [Query.equal('tracking_code', code)]
            );
            if (response.documents.length > 0) {
                return mapDocumentToReport(response.documents[0]);
            }
            return null;
        } catch (e) {
            console.error("Fetch Error", e);
            return null;
        }
    },

    // --- REALTIME DASHBOARD ---

    subscribeToReports(callback: (reports: Report[]) => void): () => void {
        let allReports: Report[] = [];

        const fetchInitial = async () => {
            try {
                const res = await databases.listDocuments(
                    CONFIG.databaseId, 
                    CONFIG.collectionId, 
                    [Query.orderDesc('$createdAt')]
                );
                allReports = res.documents.map(mapDocumentToReport);
                callback(allReports);
            } catch (e) {
                console.error("Initial fetch failed", e);
                callback([]);
            }
        };

        fetchInitial();

        try {
            const unsubscribe = client.subscribe(
                `databases.${CONFIG.databaseId}.collections.${CONFIG.collectionId}.documents`,
                (response) => {
                    const eventType = response.events[0];
                    const payload = response.payload as any;
                    const r = mapDocumentToReport(payload);

                    if (eventType.includes('create')) {
                        allReports = [r, ...allReports];
                    } else if (eventType.includes('update')) {
                        allReports = allReports.map(ex => ex.id === r.id ? r : ex);
                    } else if (eventType.includes('delete')) {
                        allReports = allReports.filter(ex => ex.id !== r.id);
                    }
                    callback([...allReports]);
                }
            );
            return unsubscribe;
        } catch (e) {
            console.warn("Realtime not available");
            return () => {};
        }
    },

    // --- ADMIN ACTIONS ---

    async updateReportStatus(id: string, status: ReportStatus): Promise<void> {
        const currentDoc = await databases.getDocument(CONFIG.databaseId, CONFIG.collectionId, id);
        const history = currentDoc.status_history ? JSON.parse(currentDoc.status_history) : [];
        history.push({ status, timestamp: new Date().toISOString() });

        await databases.updateDocument(CONFIG.databaseId, CONFIG.collectionId, id, {
            status,
            status_history: JSON.stringify(history)
        });
    },

    async addCaseUpdate(reportId: string, content: string): Promise<CaseUpdate> {
        const updateItem = {
            id: Date.now().toString(),
            content,
            timestamp: new Date().toISOString(),
            author: 'Case Worker'
        };

        const currentDoc = await databases.getDocument(CONFIG.databaseId, CONFIG.collectionId, reportId);
        const updates = currentDoc.case_updates ? JSON.parse(currentDoc.case_updates) : [];
        updates.push(updateItem);

        await databases.updateDocument(CONFIG.databaseId, CONFIG.collectionId, reportId, {
            case_updates: JSON.stringify(updates)
        });

        return updateItem;
    },

    async assignCaseToWorker(reportId: string, workerId: string, workerName: string): Promise<void> {
        const timestamp = new Date().toISOString();

        const currentDoc = await databases.getDocument(CONFIG.databaseId, CONFIG.collectionId, reportId);
        const history = currentDoc.status_history ? JSON.parse(currentDoc.status_history) : [];
        history.push({ status: ReportStatus.ASSIGNED, timestamp });

        await databases.updateDocument(CONFIG.databaseId, CONFIG.collectionId, reportId, {
            assigned_to: workerId,
            assigned_to_name: workerName,
            status: ReportStatus.ASSIGNED,
            status_history: JSON.stringify(history)
        });
    },

    // --- CASEWORKERS ---

    subscribeToCaseworkers(callback: (workers: Caseworker[]) => void): () => void {
        const fetchWorkers = async () => {
            try {
                const res = await databases.listDocuments(CONFIG.databaseId, CASEWORKERS_COL);
                const mapped = res.documents.map((d: any) => ({
                    id: d.$id,
                    name: d.name,
                    phone: d.phone,
                    email: d.email,
                    createdAt: d.$createdAt
                }));
                callback(mapped);
            } catch (e) {
                console.error("Failed to fetch workers", e);
            }
        };

        fetchWorkers();

        const unsubscribe = client.subscribe(
            `databases.${CONFIG.databaseId}.collections.${CASEWORKERS_COL}.documents`,
            () => fetchWorkers()
        );
        return unsubscribe;
    },

    async addCaseworker(worker: Omit<Caseworker, 'id' | 'createdAt'>): Promise<void> {
        await databases.createDocument(CONFIG.databaseId, CASEWORKERS_COL, ID.unique(), worker);
    },

    async updateCaseworker(id: string, data: Partial<Caseworker>): Promise<void> {
        await databases.updateDocument(CONFIG.databaseId, CASEWORKERS_COL, id, data);
    },

    async deleteCaseworker(id: string): Promise<void> {
        await databases.deleteDocument(CONFIG.databaseId, CASEWORKERS_COL, id);
    },

    // --- STATIC DATA / UTILS ---

    async getEducationModules(): Promise<EducationModule[]> {
        return [
            { id: '1', title: 'What is GBV?', description: 'Understanding the basics.', imageUrl: 'https://images.unsplash.com/photo-1573164713988-8665fc963095?auto=format&fit=crop&q=80&w=1000', content: `Gender-Based Violence (GBV) refers to harmful acts...` },
            { id: '2', title: 'Warning Signs', description: 'Early signs of abuse.', imageUrl: 'https://images.unsplash.com/photo-1590650516494-0c8e4a4dd67e?auto=format&fit=crop&q=80&w=1000', content: `Abuse isn't always physical...` },
            { id: '3', title: 'Legal Rights', description: 'Protection under law.', imageUrl: 'https://images.unsplash.com/photo-1589829085413-56de8ae18c73?auto=format&fit=crop&q=80&w=1000', content: `In Kenya, you have rights...` }
        ];
    },

    async getHotlines(): Promise<Hotline[]> {
        return [
            { id: '1', name: 'National GBV Helpline', number: '1195', category: 'Emergency' },
            { id: '2', name: 'Police Emergency', number: '999', category: 'Emergency' },
            { id: '3', name: 'FIDA Kenya (Legal Aid)', number: '0800720501', category: 'Legal' },
            { id: '4', name: 'Childline Kenya', number: '116', category: 'Emergency' },
            { id: '5', name: 'LVCT Health', number: '1190', category: 'Counseling' },
        ];
    },

    async getSupportCentres(lat: number, lng: number): Promise<SupportCentre[]> {
        return [
            { id: '1', name: 'GVRC - Nairobi Women\'s Hospital', address: 'Hurlingham, Nairobi', type: 'Medical', distance: '2.5 km' },
            { id: '2', name: 'Kenyatta National Hospital', address: 'Upper Hill', type: 'Medical', distance: '4.0 km' },
            { id: '3', name: 'MSF Lavender House', address: 'Mathare, Nairobi', type: 'Medical', distance: '6.2 km' }
        ];
    },

    async seedDatabase() {
        return (await this.seedAdmins()).success;
    },

    addToHistory(code: string) {
        const STORAGE_KEY_HISTORY = 'safevoice_report_history';
        const history = JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
        if (!history.includes(code)) {
            history.unshift(code);
            localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(history));
        }
    },

    getHistory(): string[] {
        const STORAGE_KEY_HISTORY = 'safevoice_report_history';
        return JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
    },

    // DEEP CHECK: Validates not just reachability, but correct IDs and Permissions
    async checkConnection(): Promise<{success: boolean, message?: string}> {
        try {
            // 1. Basic Reachability
            await account.getSession('current').catch(() => {});

            // 2. Deep Validation: Attempt to list documents
            // This confirms Database ID + Collection ID + Read Permissions
            await databases.listDocuments(
                CONFIG.databaseId, 
                CONFIG.collectionId, 
                [Query.limit(1)]
            );

            return { success: true };
        } catch (e: any) {
             console.error("Connection Check Failed:", e);

             if (e.message === 'Failed to fetch' || e.code === 0) {
                 return { success: false, message: "Network Error: 'Failed to fetch'. Check CORS in Appwrite Platforms." };
             }
             if (e.code === 404) {
                 return { success: false, message: `Collection or Database Not Found. Double check IDs.` };
             }
             if (e.code === 401) {
                 return { success: false, message: "Permission Denied. Please set 'Role: Any' (Read/Create) in Collection Settings." };
             }
             return { success: false, message: `Error ${e.code}: ${e.message}` };
        }
    }
};

