import { Report, ReportStatus, EducationModule, Hotline, SupportCentre, CaseUpdate, Attachment, Caseworker, AppwriteConfig } from '../types';
import { Client, Account, Databases, Storage, ID, Query, Permission, Role, AppwriteException } from 'appwrite';

// DEFAULT CONFIGURATION (Overridden by LocalStorage)
let CONFIG: AppwriteConfig = {
    endpoint: 'https://cloud.appwrite.io/v1',
    projectId: '6932991f001974451b3e', // Confirmed User ID
    databaseId: '693299e200093768e9bd', // Confirmed User ID
    collectionId: 'reports', // Confirmed via URL
    bucketId: '6932a0db0029060bf585' 
};

const CASEWORKERS_COL = 'caseworkers';
const OFFLINE_REPORTS_KEY = 'safevoice_offline_reports';
const CONFIG_KEY = 'safevoice_appwrite_config';

// Load Config from LocalStorage if exists
const savedConfig = localStorage.getItem(CONFIG_KEY);
if (savedConfig) {
    try {
        const parsed = JSON.parse(savedConfig);
        CONFIG = { ...CONFIG, ...parsed };
    } catch (e) {
        console.error("Failed to load saved config", e);
    }
}

// Initialize Appwrite
const client = new Client()
    .setEndpoint(CONFIG.endpoint)
    .setProject(CONFIG.projectId);

const account = new Account(client);
const databases = new Databases(client);
const storage = new Storage(client);

// 5 PRE-DEFINED ADMINS
const ADMIN_LIST = [
    { email: 'admin@safevoice.org', name: 'System Admin' },
    { email: 'manager@safevoice.org', name: 'Case Manager' },
    { email: 'supervisor@safevoice.org', name: 'Field Supervisor' },
    { email: 'coord@safevoice.org', name: 'Coordinator' },
    { email: 'director@safevoice.org', name: 'Director' }
];
const DEFAULT_PASS = 'password123';

// HELPER: Map Appwrite Document (snake_case) to Report Type (camelCase)
const mapDocumentToReport = (doc: any): Report => {
    // Map Attachment IDs to URLs
    const attachments: Attachment[] = (doc.attachment_ids || []).map((fileId: string) => {
        try {
            return {
                name: 'Attachment', 
                type: 'image', 
                url: storage.getFileView(CONFIG.bucketId, fileId).href,
                file: undefined
            };
        } catch (e) {
            return { name: 'Error', type: 'image', url: '', file: undefined };
        }
    });

    return {
        id: doc.$id,
        trackingCode: doc.tracking_code,
        type: doc.type,
        location: doc.location,
        description: doc.description,
        status: doc.status as ReportStatus,
        anonymousUserId: doc.anonymous_user_id,
        createdAt: doc.$createdAt,
        statusHistory: doc.status_history ? JSON.parse(doc.status_history) : [],
        caseUpdates: doc.case_updates ? JSON.parse(doc.case_updates) : [],
        attachments: attachments,
        assignedTo: doc.assigned_to,
        assignedToName: doc.assigned_to_name,
        assignedAt: doc.$updatedAt 
    };
};

export const BackendService = {

    // --- CONFIGURATION MANAGEMENT ---

    getConfig(): AppwriteConfig {
        return { ...CONFIG };
    },

    saveConfig(newConfig: AppwriteConfig) {
        CONFIG = { ...CONFIG, ...newConfig };
        localStorage.setItem(CONFIG_KEY, JSON.stringify(CONFIG));

        // Re-initialize client settings
        client.setEndpoint(CONFIG.endpoint).setProject(CONFIG.projectId);
    },

    // --- AUTHENTICATION ---

    async adminLogin(email: string, password: string, rememberMe: boolean = false): Promise<boolean> {
        try {
            // Check if already logged in
            try {
                await account.get();
                return true;
            } catch {}

            await account.createEmailPasswordSession(email, password);
            return true;
        } catch (error) {
            console.error("Appwrite Login Error:", error);
            return false;
        }
    },

    // Create the 5 requested admin accounts
    async seedAdmins(): Promise<{ success: boolean; message: string }> {
        let createdCount = 0;
        let errors = [];
        try {
            for (const admin of ADMIN_LIST) {
                try {
                    await account.create(ID.unique(), admin.email, DEFAULT_PASS, admin.name);
                    createdCount++;
                } catch (e: any) {
                    if (e.code === 409) console.log(`${admin.email} already exists.`);
                    else errors.push(`${admin.email}: ${e.message}`);
                }
            }
            return { 
                success: true, 
                message: `Process complete. Created ${createdCount} new admins. Default password: ${DEFAULT_PASS}. Errors: ${errors.length}` 
            };
        } catch (e) {
            return { success: false, message: "Failed to seed admins." };
        }
    },

    async validateAdminSession(): Promise<boolean> {
        try {
            await account.get();
            return true;
        } catch {
            return false;
        }
    },

    async logout(): Promise<void> {
        try {
            await account.deleteSession('current');
        } catch {}
    },

    // --- REPORTING ---

    async createReport(data: any): Promise<Report> {
        const trackingCode = `SV-${Math.floor(1000 + Math.random() * 9000)}-${new Date().getFullYear()}`;
        let finalDescription = data.description;
        if (data.incidentDate) {
            finalDescription = `[INCIDENT TIME: ${new Date(data.incidentDate).toLocaleString()}]\n\n${data.description}`;
        }

        try {
            // 1. Ensure Anonymous Session
            try {
                await account.get();
            } catch (sessionError) {
                await account.createAnonymousSession();
            }

            // 2. Upload Attachments (Only if online)
            const attachmentIds: string[] = [];

            if (data.attachments && data.attachments.length > 0) {
                for (const att of data.attachments) {
                    if (att.file) {
                        try {
                            const file = await storage.createFile(CONFIG.bucketId, ID.unique(), att.file);
                            attachmentIds.push(file.$id);
                        } catch (uploadError) {
                            console.error("Failed to upload file, proceeding with report", uploadError);
                        }
                    }
                }
            }

            // 3. Create Document
            const payload = {
                tracking_code: trackingCode,
                type: data.type,
                location: data.location,
                description: finalDescription,
                status: ReportStatus.RECEIVED,
                anonymous_user_id: data.anonymousUserId || 'anon',
                status_history: JSON.stringify([{ status: ReportStatus.RECEIVED, timestamp: new Date().toISOString() }]),
                case_updates: JSON.stringify([]),
                attachment_ids: attachmentIds,
                assigned_to: null,
                assigned_to_name: null
            };

            const doc = await databases.createDocument(
                CONFIG.databaseId,
                CONFIG.collectionId,
                ID.unique(),
                payload,
                [
                    Permission.read(Role.any()), 
                    Permission.update(Role.users()),
                    Permission.read(Role.users()), 
                ]
            );

            this.addToHistory(trackingCode);
            return mapDocumentToReport(doc);

        } catch (error: any) {
            console.warn("Appwrite error during submission:", error);

            // Explicit error handling for Schema mismatch
            if (error.code === 400 && error.message.includes('Attribute not found')) {
                throw new Error(`Schema Error: ${error.message}. Please add this attribute in Appwrite Console.`);
            }
            if (error.code === 404) {
                 throw new Error(`Collection '${CONFIG.collectionId}' not found. Check Config.`);
            }
            if (error.code === 401) {
                 throw new Error(`Permission Denied. Set 'Role: Any' to Create/Read in Console.`);
            }

            // Fallback to OFFLINE mode only for network errors
            if (error.message === 'Failed to fetch' || error.code === 0) {
                const offlineReport: Report = {
                    id: 'local_' + Date.now(),
                    trackingCode,
                    type: data.type,
                    location: data.location,
                    description: finalDescription,
                    status: ReportStatus.RECEIVED,
                    anonymousUserId: data.anonymousUserId || 'anon',
                    createdAt: new Date().toISOString(),
                    statusHistory: [{ status: ReportStatus.RECEIVED, timestamp: new Date().toISOString() }],
                    caseUpdates: [{ 
                        id: '1', 
                        content: 'Report saved to device (Network Error). Will sync when online.', 
                        timestamp: new Date().toISOString(), 
                        author: 'System (Offline)' 
                    }],
                    attachments: data.attachments || [],
                    assignedTo: undefined
                };

                const offlineReports = JSON.parse(localStorage.getItem(OFFLINE_REPORTS_KEY) || '[]');
                offlineReports.push(offlineReport);
                localStorage.setItem(OFFLINE_REPORTS_KEY, JSON.stringify(offlineReports));

                this.addToHistory(trackingCode);
                return offlineReport;
            }

            throw error;
        }
    },

    async getReportByCode(code: string): Promise<Report | null> {
        // 1. Check Offline Storage First
        const offlineReports = JSON.parse(localStorage.getItem(OFFLINE_REPORTS_KEY) || '[]');
        const localMatch = offlineReports.find((r: any) => r.trackingCode === code);
        if (localMatch) {
            return localMatch;
        }

        // 2. Check Online
        try {
            const response = await databases.listDocuments(
                CONFIG.databaseId,
                CONFIG.collectionId,
                [Query.equal('tracking_code', code)]
            );
            if (response.documents.length > 0) {
                return mapDocumentToReport(response.documents[0]);
            }
            return null;
        } catch (e) {
            console.error("Fetch Error", e);
            return null;
        }
    },

    // --- REALTIME DASHBOARD ---

    subscribeToReports(callback: (reports: Report[]) => void): () => void {
        let allReports: Report[] = [];

        const fetchInitial = async () => {
            try {
                const res = await databases.listDocuments(
                    CONFIG.databaseId, 
                    CONFIG.collectionId, 
                    [Query.orderDesc('$createdAt')]
                );
                allReports = res.documents.map(mapDocumentToReport);
                callback(allReports);
            } catch (e) {
                console.error("Initial fetch failed", e);
                callback([]);
            }
        };

        fetchInitial();

        try {
            const unsubscribe = client.subscribe(
                `databases.${CONFIG.databaseId}.collections.${CONFIG.collectionId}.documents`,
                (response) => {
                    const eventType = response.events[0];
                    const payload = response.payload as any;
                    const r = mapDocumentToReport(payload);

                    if (eventType.includes('create')) {
                        allReports = [r, ...allReports];
                    } else if (eventType.includes('update')) {
                        allReports = allReports.map(ex => ex.id === r.id ? r : ex);
                    } else if (eventType.includes('delete')) {
                        allReports = allReports.filter(ex => ex.id !== r.id);
                    }
                    callback([...allReports]);
                }
            );
            return unsubscribe;
        } catch (e) {
            console.warn("Realtime not available");
            return () => {};
        }
    },

    // --- ADMIN ACTIONS ---

    async updateReportStatus(id: string, status: ReportStatus): Promise<void> {
        const currentDoc = await databases.getDocument(CONFIG.databaseId, CONFIG.collectionId, id);
        const history = currentDoc.status_history ? JSON.parse(currentDoc.status_history) : [];
        history.push({ status, timestamp: new Date().toISOString() });

        await databases.updateDocument(CONFIG.databaseId, CONFIG.collectionId, id, {
            status,
            status_history: JSON.stringify(history)
        });
    },

    async addCaseUpdate(reportId: string, content: string): Promise<CaseUpdate> {
        const updateItem = {
            id: Date.now().toString(),
            content,
            timestamp: new Date().toISOString(),
            author: 'Case Worker'
        };

        const currentDoc = await databases.getDocument(CONFIG.databaseId, CONFIG.collectionId, reportId);
        const updates = currentDoc.case_updates ? JSON.parse(currentDoc.case_updates) : [];
        updates.push(updateItem);

        await databases.updateDocument(CONFIG.databaseId, CONFIG.collectionId, reportId, {
            case_updates: JSON.stringify(updates)
        });

        return updateItem;
    },

    async assignCaseToWorker(reportId: string, workerId: string, workerName: string): Promise<void> {
        const timestamp = new Date().toISOString();

        const currentDoc = await databases.getDocument(CONFIG.databaseId, CONFIG.collectionId, reportId);
        const history = currentDoc.status_history ? JSON.parse(currentDoc.status_history) : [];
        history.push({ status: ReportStatus.ASSIGNED, timestamp });

        await databases.updateDocument(CONFIG.databaseId, CONFIG.collectionId, reportId, {
            assigned_to: workerId,
            assigned_to_name: workerName,
            status: ReportStatus.ASSIGNED,
            status_history: JSON.stringify(history)
        });
    },

    // --- CASEWORKERS ---

    subscribeToCaseworkers(callback: (workers: Caseworker[]) => void): () => void {
        const fetchWorkers = async () => {
            try {
                const res = await databases.listDocuments(CONFIG.databaseId, CASEWORKERS_COL);
                const mapped = res.documents.map((d: any) => ({
                    id: d.$id,
                    name: d.name,
                    phone: d.phone,
                    email: d.email,
                    createdAt: d.$createdAt
                }));
                callback(mapped);
            } catch (e) {
                console.error("Failed to fetch workers", e);
            }
        };

        fetchWorkers();

        const unsubscribe = client.subscribe(
            `databases.${CONFIG.databaseId}.collections.${CASEWORKERS_COL}.documents`,
            () => fetchWorkers()
        );
        return unsubscribe;
    },

    async addCaseworker(worker: Omit<Caseworker, 'id' | 'createdAt'>): Promise<void> {
        await databases.createDocument(CONFIG.databaseId, CASEWORKERS_COL, ID.unique(), worker);
    },

    async updateCaseworker(id: string, data: Partial<Caseworker>): Promise<void> {
        await databases.updateDocument(CONFIG.databaseId, CASEWORKERS_COL, id, data);
    },

    async deleteCaseworker(id: string): Promise<void> {
        await databases.deleteDocument(CONFIG.databaseId, CASEWORKERS_COL, id);
    },

    // --- STATIC DATA / UTILS ---

    async getEducationModules(): Promise<EducationModule[]> {
        return [
            { id: '1', title: 'What is GBV?', description: 'Understanding the basics.', imageUrl: 'https://images.unsplash.com/photo-1573164713988-8665fc963095?auto=format&fit=crop&q=80&w=1000', content: `Gender-Based Violence (GBV) refers to harmful acts...` },
            { id: '2', title: 'Warning Signs', description: 'Early signs of abuse.', imageUrl: 'https://images.unsplash.com/photo-1590650516494-0c8e4a4dd67e?auto=format&fit=crop&q=80&w=1000', content: `Abuse isn't always physical...` },
            { id: '3', title: 'Legal Rights', description: 'Protection under law.', imageUrl: 'https://images.unsplash.com/photo-1589829085413-56de8ae18c73?auto=format&fit=crop&q=80&w=1000', content: `In Kenya, you have rights...` }
        ];
    },

    async getHotlines(): Promise<Hotline[]> {
        return [
            { id: '1', name: 'National GBV Helpline', number: '1195', category: 'Emergency' },
            { id: '2', name: 'Police Emergency', number: '999', category: 'Emergency' },
            { id: '3', name: 'FIDA Kenya (Legal Aid)', number: '0800720501', category: 'Legal' },
            { id: '4', name: 'Childline Kenya', number: '116', category: 'Emergency' },
            { id: '5', name: 'LVCT Health', number: '1190', category: 'Counseling' },
        ];
    },

    async getSupportCentres(lat: number, lng: number): Promise<SupportCentre[]> {
        return [
            { id: '1', name: 'GVRC - Nairobi Women\'s Hospital', address: 'Hurlingham, Nairobi', type: 'Medical', distance: '2.5 km' },
            { id: '2', name: 'Kenyatta National Hospital', address: 'Upper Hill', type: 'Medical', distance: '4.0 km' },
            { id: '3', name: 'MSF Lavender House', address: 'Mathare, Nairobi', type: 'Medical', distance: '6.2 km' }
        ];
    },

    async seedDatabase() {
        return (await this.seedAdmins()).success;
    },

    addToHistory(code: string) {
        const STORAGE_KEY_HISTORY = 'safevoice_report_history';
        const history = JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
        if (!history.includes(code)) {
            history.unshift(code);
            localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(history));
        }
    },

    getHistory(): string[] {
        const STORAGE_KEY_HISTORY = 'safevoice_report_history';
        return JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
    },

    // DEEP CHECK: Validates not just reachability, but correct IDs and Permissions
    async checkConnection(): Promise<{success: boolean, message?: string}> {
        try {
            // 1. Basic Reachability - Detect Network Error early
            try {
                await account.getSession('current');
            } catch (e: any) {
                // Ignore 401 (just means not logged in, which is fine for connectivity check)
                // But rethrow Network Errors immediately to avoid masking them with downstream errors
                if (e.message === 'Failed to fetch' || e.code === 0) {
                    throw e;
                }
            }

            // 2. Deep Validation: Attempt to list documents
            // This confirms Database ID + Collection ID + Read Permissions
            await databases.listDocuments(
                CONFIG.databaseId, 
                CONFIG.collectionId, 
                [Query.limit(1)]
            );

            return { success: true };
        } catch (e: any) {
             console.error("Connection Check Failed:", e);

             if (e.message === 'Failed to fetch' || e.code === 0) {
                 return { success: false, message: "Network Error: 'Failed to fetch' (CORS). Add this domain to Appwrite Console > Platforms." };
             }
             if (e.code === 404) {
                 return { success: false, message: `Collection or Database Not Found. Double check IDs.` };
             }
             if (e.code === 401) {
                 return { success: false, message: "Permission Denied. Please set 'Role: Any' (Read/Create) in Collection Settings." };
             }
             return { success: false, message: `Error ${e.code}: ${e.message}` };
        }
    }
};

import React, { useState, useEffect } from 'react';
import { GBVType, Attachment, Language } from '../types';
import { BackendService } from '../services/mockBackend';
import { getTranslation } from '../services/translations';
import { AlertCircle, Camera, Mic, MapPin, Loader2, CheckCircle, FileUp, XCircle, Calendar, Crosshair, Shield, ArrowRight, EyeOff, Info, CloudSun, Eye } from 'lucide-react';

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB Limit

interface ReportViewProps {
  onReportSubmitted: (code: string) => void;
  lang: Language;
  onSafetyPlanClick: () => void;
}

export const ReportView: React.FC<ReportViewProps> = ({ onReportSubmitted, lang, onSafetyPlanClick }) => {
  const t = getTranslation(lang);

  const [type, setType] = useState<GBVType>(GBVType.PHYSICAL);
  const [location, setLocation] = useState('');
  const [incidentDate, setIncidentDate] = useState('');
  const [description, setDescription] = useState('');
  const [files, setFiles] = useState<Attachment[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [gettingLocation, setGettingLocation] = useState(false);
  const [success, setSuccess] = useState(false);
  const [trackingCode, setTrackingCode] = useState('');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Incognito Mode: If true, ID is not saved to device
  const [isIncognito, setIsIncognito] = useState(false);

  // Camouflage Mode: Hides the screen with a fake weather app
  const [isCamouflaged, setIsCamouflaged] = useState(false);

  // Auto-redirect timer reference to clear it if needed
  const [redirectTimer, setRedirectTimer] = useState<ReturnType<typeof setTimeout> | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setErrorMsg(null);
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.size > MAX_FILE_SIZE) {
        setErrorMsg(`File "${file.name}" is too large. Maximum size is 5MB.`);
        return;
      }
      const newAttachment: Attachment = {
        name: file.name,
        type: file.type.startsWith('image') ? 'image' : file.type.startsWith('audio') ? 'audio' : 'video',
        url: URL.createObjectURL(file), 
        file: file 
      };
      setFiles([...files, newAttachment]);
    }
  };

  const removeFile = (index: number) => {
    const newFiles = [...files];
    newFiles.splice(index, 1);
    setFiles(newFiles);
  };

  const handleGetGPS = () => {
    if (!navigator.geolocation) {
        alert("Geolocation is not supported by your browser");
        return;
    }
    setGettingLocation(true);
    navigator.geolocation.getCurrentPosition(
        (position) => {
            // Success
            const { latitude, longitude } = position.coords;
            const gpsString = `${latitude.toFixed(5)}, ${longitude.toFixed(5)}`;
            setLocation(prev => prev ? `${prev} (${gpsString})` : gpsString);
            setGettingLocation(false);
        },
        (error) => {
            // Error
            console.error(error);
            alert("Unable to retrieve location. Please type it manually.");
            setGettingLocation(false);
        },
        { enableHighAccuracy: true, timeout: 10000 }
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMsg(null);

    if (!location.trim() || !description.trim()) {
        setErrorMsg("Please provide both a location and a description of the incident.");
        return;
    }

    // GENERATE ID
    let anonymousUserId = '';

    // If NOT incognito, try to get existing ID or save new one
    if (!isIncognito) {
       anonymousUserId = localStorage.getItem('safevoice_anon_id') || '';
    }

    if (!anonymousUserId) {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
          anonymousUserId = crypto.randomUUID();
      } else {
          // Fallback UUID for insecure contexts
          anonymousUserId = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
            var r = Math.random() * 16 | 0, v = c === 'x' ? r : (r & 0x3 | 0x8);
            return v.toString(16);
          });
      }
      // ONLY save if NOT incognito
      if (!isIncognito) {
         localStorage.setItem('safevoice_anon_id', anonymousUserId);
      }
    }

    setIsSubmitting(true);
    try {
      const report = await BackendService.createReport({
        type,
        location,
        description,
        incidentDate: incidentDate || new Date().toISOString(), // Use selected time or now
        attachments: files,
        anonymousUserId
      });
      setTrackingCode(report.trackingCode);
      setSuccess(true);

      // Auto-redirect after 2.5 seconds (slightly longer so they see the code)
      const timer = setTimeout(() => {
        onReportSubmitted(report.trackingCode);
      }, 2500);
      setRedirectTimer(timer);

    } catch (error: any) {
      console.error("Submission Error Details:", error);
      // Directly show the error message to help debug connection issues
      setErrorMsg(error.message || "An unexpected error occurred.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleManualRedirect = () => {
    if (redirectTimer) clearTimeout(redirectTimer);
    onReportSubmitted(trackingCode);
  };

  useEffect(() => {
    return () => {
      if (redirectTimer) clearTimeout(redirectTimer);
    };
  }, [redirectTimer]);

  // --- CAMOUFLAGE SCREEN ---
  if (isCamouflaged) {
    return (
        <div 
          className="fixed inset-0 z-[100] bg-blue-400 flex flex-col items-center justify-center text-white cursor-pointer select-none"
