                    </div>
                    <div className="text-center">
                        <span className="block text-4xl font-bold opacity-75">18°</span>
                        <span className="text-sm opacity-60 uppercase tracking-widest">Low</span>
                    </div>
                </div>
            </div>
            <p className="absolute bottom-8 text-xs opacity-40 font-mono">Double tap screen to unlock</p>
        </div>
    );
  }

  if (success) {
    return (
