import { getTranslation } from './services/translations';
import { Home, FilePlus, BookOpen, Phone, Bell, Moon, Sun, UserCircle, MessageCircleHeart, Shield, LogOut, Globe, WifiOff, Settings } from 'lucide-react';
import { getToken } from 'firebase/messaging';
import { messaging } from './firebaseConfig';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.HOME);
  const [darkMode, setDarkMode] = useState(false);
  const [lang, setLang] = useState<Language>('en');
  const [lastTrackingCode, setLastTrackingCode] = useState<string>('');
  const [lastKnownStatus, setLastKnownStatus] = useState<string>('');
  const [notifications, setNotifications] = useState<string[]>([]);
  const [logoTaps, setLogoTaps] = useState(0);
  const [connectionError, setConnectionError] = useState<string | null>(null);
  const [showConfig, setShowConfig] = useState(false);

  const t = getTranslation(lang);

  // Initialize Dark Mode based on system preference
  useEffect(() => {
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      setDarkMode(true);
    }

    // Load most recent case to watch
    const history = BackendService.getHistory();
    if (history.length > 0) {
        setLastTrackingCode(history[0]);
    }

    // Check Backend Connection on Startup
    BackendService.checkConnection().then(result => {
        if (!result.success) {
            setConnectionError(result.message || "Cannot connect to server.");
        }
    });

  }, []);

  // Request Notification Permission (For Admin mainly)
  useEffect(() => {
    if (messaging) {
      const reqPermission = async () => {
        try {
          const permission = await Notification.requestPermission();
          if (permission === 'granted') {
             // Get Token
             const token = await getToken(messaging, { vapidKey: 'BIZ4-6RiZ7u_YlzRPcvBPs9hVXMZkb9eDgVdKuSbonZMSeG1Eo7IOmytAC_Q-DjQK00h3QwwIjLRJ0q0QjldUUs' });
             console.log("FCM Token:", token);
          }
        } catch (e) {
          console.warn("Notification permission denied or failed.");
        }
      };
      reqPermission();
    }
  }, []);

  // Poll for Status Updates on the active case
  useEffect(() => {
    if (!lastTrackingCode) return;

    // For the user side, we still poll simply or could implement onSnapshot in TrackView
    // Keeping simple poll here for notifications
    const checkStatus = async () => {
        try {
            const report = await BackendService.getReportByCode(lastTrackingCode);
            if (report) {
                if (!lastKnownStatus) {
                    setLastKnownStatus(report.status);
                } 
                else if (report.status !== lastKnownStatus) {
                    setLastKnownStatus(report.status);
                    setNotifications(prev => [...prev, `Update: Case ${lastTrackingCode} is now '${report.status}'`]);
                }
            }
        } catch (e) {
            // silent fail
        }
    };

    const interval = setInterval(checkStatus, 10000); // 10s poll for user
    return () => clearInterval(interval);
  }, [lastTrackingCode, lastKnownStatus]);


  // Apply Dark Mode class to HTML
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // Simulate Push Notifications (Education Marketing)
  useEffect(() => {
    const timer = setTimeout(() => {
      setNotifications(prev => [...prev, "New education module available: 'Digital Safety'"]);
    }, 10000);
    return () => clearTimeout(timer);
  }, []);

  // --- QUICK EXIT FUNCTION ---
