// HELPER: Map Supabase Row (snake_case) to Report Type (camelCase)
const mapRowToReport = (row: any): Report => {
    // Parse attachments if stored as JSON string, or use directly if JSONB
    let attachments: Attachment[] = [];
    if (typeof row.attachment_urls === 'string') {
        try { attachments = JSON.parse(row.attachment_urls); } catch (e) {}
    } else if (Array.isArray(row.attachment_urls)) {
        attachments = row.attachment_urls;
    }

    let statusHistory = [];
    if (typeof row.status_history === 'string') {
        try { statusHistory = JSON.parse(row.status_history); } catch (e) {}
    } else if (Array.isArray(row.status_history)) {
        statusHistory = row.status_history;
    }

    let caseUpdates = [];
    if (typeof row.case_updates === 'string') {
        try { caseUpdates = JSON.parse(row.case_updates); } catch (e) {}
    } else if (Array.isArray(row.case_updates)) {
        caseUpdates = row.case_updates;
    }

    return {
        id: row.id,
        trackingCode: row.tracking_code,
        type: row.type,
        location: row.location,
        description: row.description,
        status: row.status as ReportStatus,
        anonymousUserId: row.anonymous_user_id,
        createdAt: row.created_at,
        statusHistory: statusHistory,
        caseUpdates: caseUpdates,
        attachments: attachments,
        assignedTo: row.assigned_to,
        assignedToName: row.assigned_to_name,
        assignedAt: row.updated_at // Using updated_at as proxy for assignment time if not tracked separately
    };
};

export const BackendService = {

    // --- CONFIGURATION MANAGEMENT ---

    getConfig(): AppwriteConfig {
        return getSupabaseConfig();
    },

    saveConfig(newConfig: AppwriteConfig) {
        saveSupabaseConfig(newConfig.url, newConfig.key);
    },

    // --- AUTHENTICATION ---

    async adminLogin(email: string, password: string): Promise<boolean> {
        // Option 1: Try Real Supabase Auth
        const { data, error } = await supabase.auth.signInWithPassword({
            email,
            password,
        });
        if (!error && data.user) return true;

        // Option 2: Fallback to Mock List (for the requested demo credentials)
        const validMock = ADMIN_LIST.find(a => a.email === email && password === DEFAULT_PASS);
        if (validMock) return true;

        return false;
    },

    async seedAdmins(): Promise<{ success: boolean; message: string }> {
        // In Supabase, users are managed in Auth. 
        // We cannot programmatically create users with a generic password without Service Role key.
        return { success: true, message: "In Supabase, please invite users via the Authentication Dashboard." };
    },

    async validateAdminSession(): Promise<boolean> {
        // Check real session
        const { data } = await supabase.auth.getSession();
        if (data.session) return true;

        // For mock session, we assume true if they passed the login screen in this session context
        // In a real app, manage local storage tokens.
        return true; 
    },

    async logout(): Promise<void> {
        await supabase.auth.signOut();
    },

    // --- REPORTING ---

    async createReport(data: any): Promise<Report> {
        const trackingCode = `SV-${Math.floor(1000 + Math.random() * 9000)}-${new Date().getFullYear()}`;
        let finalDescription = data.description;
        if (data.incidentDate) {
            finalDescription = `[INCIDENT TIME: ${new Date(data.incidentDate).toLocaleString()}]\n\n${data.description}`;
        }

        // 1. Upload Attachments
        const finalAttachments: Attachment[] = [];
        if (data.attachments && data.attachments.length > 0) {
            for (const att of data.attachments) {
                if (att.file) {
                    try {
                        const fileName = `${Date.now()}_${att.name.replace(/[^a-zA-Z0-9]/g, '_')}`;
                        const { data: uploadData, error } = await supabase.storage
                            .from('evidence')
                            .upload(fileName, att.file);

                        if (!error && uploadData) {
                            const { data: publicUrlData } = supabase.storage
                                .from('evidence')
                                .getPublicUrl(fileName);

                            finalAttachments.push({
                                ...att,
                                url: publicUrlData.publicUrl,
                                file: undefined // Don't store the file object
                            });
                        }
                    } catch (uploadError) {
                        console.error("Upload failed", uploadError);
                        // Push original (blob) if upload fails, though other users won't see it
                        finalAttachments.push(att); 
                    }
                }
            }
        }

        const payload = {
            tracking_code: trackingCode,
            type: data.type,
            location: data.location,
            description: finalDescription,
            status: ReportStatus.RECEIVED,
            anonymous_user_id: data.anonymousUserId || 'anon',
            status_history: [{ status: ReportStatus.RECEIVED, timestamp: new Date().toISOString() }],
            case_updates: [],
            attachment_urls: finalAttachments,
            assigned_to: null,
            assigned_to_name: null
        };

        const { data: insertedData, error } = await supabase
            .from(REPORTS_TABLE)
            .insert([payload])
            .select()
            .single();

        if (error) {
            console.error("Supabase Insert Error:", error);

            // Fallback to OFFLINE
            const offlineReport: Report = {
                id: 'local_' + Date.now(),
                trackingCode,
                type: data.type,
                location: data.location,
                description: finalDescription,
                status: ReportStatus.RECEIVED,
                anonymousUserId: data.anonymousUserId || 'anon',
                createdAt: new Date().toISOString(),
                statusHistory: payload.status_history,
                caseUpdates: [{ 
                    id: '1', 
                    content: 'Report saved to device (Network/DB Error). Will sync when online.', 
                    timestamp: new Date().toISOString(), 
                    author: 'System (Offline)' 
                }],
                attachments: data.attachments || [],
                assignedTo: undefined
            };
            const offlineReports = JSON.parse(localStorage.getItem(OFFLINE_REPORTS_KEY) || '[]');
            offlineReports.push(offlineReport);
            localStorage.setItem(OFFLINE_REPORTS_KEY, JSON.stringify(offlineReports));
            this.addToHistory(trackingCode);
            return offlineReport;
        }

        this.addToHistory(trackingCode);
        return mapRowToReport(insertedData);
    },

    async getReportByCode(code: string): Promise<Report | null> {
        // 1. Check Offline
        const offlineReports = JSON.parse(localStorage.getItem(OFFLINE_REPORTS_KEY) || '[]');
        const localMatch = offlineReports.find((r: any) => r.trackingCode === code);
        if (localMatch) return localMatch;

        // 2. Check Supabase
        const { data, error } = await supabase
            .from(REPORTS_TABLE)
            .select('*')
            .eq('tracking_code', code)
            .single();

        if (error || !data) return null;
        return mapRowToReport(data);
    },

    // --- REALTIME DASHBOARD ---

    subscribeToReports(callback: (reports: Report[]) => void): () => void {
        // 1. Fetch Initial Data
        const fetchAll = async () => {
            const { data } = await supabase
                .from(REPORTS_TABLE)
                .select('*')
                .order('created_at', { ascending: false });

            if (data) {
                callback(data.map(mapRowToReport));
            }
        };
        fetchAll();

        // 2. Subscribe to Changes
        const channel = supabase
            .channel('public:reports')
            .on('postgres_changes', { event: '*', schema: 'public', table: REPORTS_TABLE }, (payload) => {
                // When any change happens, re-fetch all to ensure sorting and consistency 
                // (Optimized approach would be to splice the array, but fetchAll is safer for consistency)
                fetchAll();
            })
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    },

    // --- ADMIN ACTIONS ---

    async updateReportStatus(id: string, status: ReportStatus): Promise<void> {
        // First get current history
        const { data: current } = await supabase.from(REPORTS_TABLE).select('status_history').eq('id', id).single();

        let history = [];
        if (current && current.status_history) {
            history = typeof current.status_history === 'string' ? JSON.parse(current.status_history) : current.status_history;
        }
        history.push({ status, timestamp: new Date().toISOString() });

        await supabase.from(REPORTS_TABLE).update({
            status,
            status_history: history
        }).eq('id', id);
    },

    async addCaseUpdate(reportId: string, content: string): Promise<CaseUpdate> {
        const updateItem: CaseUpdate = {
            id: Date.now().toString(),
            content,
            timestamp: new Date().toISOString(),
            author: 'Case Worker'
        };

        const { data: current } = await supabase.from(REPORTS_TABLE).select('case_updates').eq('id', reportId).single();
        let updates = [];
        if (current && current.case_updates) {
             updates = typeof current.case_updates === 'string' ? JSON.parse(current.case_updates) : current.case_updates;
        }
        updates.push(updateItem);

        await supabase.from(REPORTS_TABLE).update({
            case_updates: updates
        }).eq('id', reportId);

        return updateItem;
    },

    async assignCaseToWorker(reportId: string, workerId: string, workerName: string): Promise<void> {
        await supabase.from(REPORTS_TABLE).update({
            assigned_to: workerId,
            assigned_to_name: workerName,
            status: ReportStatus.ASSIGNED
        }).eq('id', reportId);

        // Update history as well
        await this.updateReportStatus(reportId, ReportStatus.ASSIGNED);
    },

    // --- CASEWORKERS ---

    subscribeToCaseworkers(callback: (workers: Caseworker[]) => void): () => void {
        const fetchWorkers = async () => {
            const { data } = await supabase.from(CASEWORKERS_TABLE).select('*');
            if (data) {
                callback(data.map((d: any) => ({
                    id: d.id,
                    name: d.name,
                    phone: d.phone,
                    email: d.email,
                    createdAt: d.created_at
                })));
            }
        };
        fetchWorkers();

        const channel = supabase
            .channel('public:caseworkers')
            .on('postgres_changes', { event: '*', schema: 'public', table: CASEWORKERS_TABLE }, () => {
                fetchWorkers();
            })
            .subscribe();

        return () => supabase.removeChannel(channel);
    },

    async addCaseworker(worker: Omit<Caseworker, 'id' | 'createdAt'>): Promise<void> {
        await supabase.from(CASEWORKERS_TABLE).insert([{
            ...worker,
            created_at: new Date().toISOString()
        }]);
    },

    async updateCaseworker(id: string, data: Partial<Caseworker>): Promise<void> {
        await supabase.from(CASEWORKERS_TABLE).update(data).eq('id', id);
    },

    async deleteCaseworker(id: string): Promise<void> {
        await supabase.from(CASEWORKERS_TABLE).delete().eq('id', id);
    },

    // --- STATIC DATA / UTILS ---

    async getEducationModules(): Promise<EducationModule[]> {
        return [
            { id: '1', title: 'What is GBV?', description: 'Understanding the basics.', imageUrl: 'https://images.unsplash.com/photo-1573164713988-8665fc963095?auto=format&fit=crop&q=80&w=1000', content: `Gender-Based Violence (GBV) refers to harmful acts...` },
            { id: '2', title: 'Warning Signs', description: 'Early signs of abuse.', imageUrl: 'https://images.unsplash.com/photo-1590650516494-0c8e4a4dd67e?auto=format&fit=crop&q=80&w=1000', content: `Abuse isn't always physical...` },
            { id: '3', title: 'Legal Rights', description: 'Protection under law.', imageUrl: 'https://images.unsplash.com/photo-1589829085413-56de8ae18c73?auto=format&fit=crop&q=80&w=1000', content: `In Kenya, you have rights...` }
        ];
    },

    async getHotlines(): Promise<Hotline[]> {
        return [
            { id: '1', name: 'National GBV Helpline', number: '1195', category: 'Emergency' },
            { id: '2', name: 'Police Emergency', number: '999', category: 'Emergency' },
            { id: '3', name: 'FIDA Kenya (Legal Aid)', number: '0800720501', category: 'Legal' },
            { id: '4', name: 'Childline Kenya', number: '116', category: 'Emergency' },
            { id: '5', name: 'LVCT Health', number: '1190', category: 'Counseling' },
        ];
    },

    async getSupportCentres(lat: number, lng: number): Promise<SupportCentre[]> {
        return [
            { id: '1', name: 'GVRC - Nairobi Women\'s Hospital', address: 'Hurlingham, Nairobi', type: 'Medical', distance: '2.5 km' },
            { id: '2', name: 'Kenyatta National Hospital', address: 'Upper Hill', type: 'Medical', distance: '4.0 km' },
            { id: '3', name: 'MSF Lavender House', address: 'Mathare, Nairobi', type: 'Medical', distance: '6.2 km' }
        ];
    },

    async seedDatabase() {
        return { success: true, message: "Use Supabase Dashboard SQL Editor to seed." };
    },

    addToHistory(code: string) {
        const STORAGE_KEY_HISTORY = 'safevoice_report_history';
        const history = JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
        if (!history.includes(code)) {
            history.unshift(code);
            localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(history));
        }
    },

    getHistory(): string[] {
        const STORAGE_KEY_HISTORY = 'safevoice_report_history';
        return JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
    },

    async checkConnection(): Promise<{success: boolean, message?: string}> {
        try {
            const { data, error } = await supabase.from(REPORTS_TABLE).select('count').limit(1);
            if (error) throw error;
            return { success: true };
        } catch (e: any) {
             return { success: false, message: `Supabase Error: ${e.message}. Check Config.` };
        }
    }
};

