export const GeminiService = {

  // --- CHAT API ---

  createChat(): Chat | null {
    if (ai) {
      try {
        return ai.chats.create({
          model: 'gemini-2.5-flash',
          config: {
            tools: [{ googleSearch: {} }], // ENABLED INTERNET ACCESS for real answers
            systemInstruction: `You are SafeVoice AI, an advanced Crisis Response Specialist.
            - MISSION: Provide immediate, accurate, and life-saving information to victims of Gender-Based Violence (GBV).
            - CAPABILITIES: You have access to Google Search. Use it to find open shelters, legal aid contacts, and hospital hours in the user's location if asked.
            - TONE: Empathetic, calm, direct, and authoritative on safety matters.
            - SAFETY FIRST: If a user is in danger, prioritize getting them to physical safety (Police, Hospital, Safe House).
            - LOCAL CONTEXT: Assume the context is Kenya unless specified otherwise (Ref: 1195 Helpline, Gender Desks).
            - FORMAT: Use bullet points for steps. Keep it readable on mobile.`
          }
        });
      } catch (e) {
        console.error("Failed to create chat session", e);
        return null;
      }
    }
    return null;
  },

  // Fallback for when the Chat object isn't available or fails
  getOfflineResponse(userText: string): string {
    const lowerInput = userText.toLowerCase();

    // 1. Check for specific keywords
    const keys = Object.keys(CHAT_KEYWORDS).sort((a, b) => b.length - a.length);
    for (const key of keys) {
      if (lowerInput.includes(key)) {
        return CHAT_KEYWORDS[key];
      }
    }

    // 2. Rotate through generic helpful messages if no keyword matches
    const randomIndex = Math.floor(Math.random() * FALLBACK_RESPONSES.length);
    return FALLBACK_RESPONSES[randomIndex];
  },

  // --- CONTENT GENERATION API ---

  async generateQuizForTopic(topic: string): Promise<QuizQuestion[]> {
    if (ai) {
      try {
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash',
          contents: `Create a simple 3-question multiple choice quiz about "${topic}" related to Gender Based Violence awareness. Return JSON only.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: { type: Type.ARRAY, items: { type: Type.STRING } },
                  correctIndex: { type: Type.INTEGER }
                }
              }
            }
          }
        });
        if (response.text) return JSON.parse(response.text);
      } catch (error) {
        // Fall through to offline
      }
    }
    return LOCAL_QUIZ_DB[topic] || LOCAL_QUIZ_DB["What is GBV?"];
  },

  async generateSafetyPlan(inputs: any): Promise<string> {
    if (ai) {
      try {
        const prompt = `Create a tactical safety plan for a victim. Context: ${JSON.stringify(inputs)}. 
        Format: Markdown. 5 Steps. Bold verbs.`;
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash',
          contents: prompt,
        });
        if (response.text) return response.text;
      } catch (error) {
        // Fall through
      }
    }

    // Simple Offline Plan Generator
    return `### Safety Plan (Offline Mode)

    **1. Emergency Contacts:**
    - Memorize 1195 (National Helpline).

    **2. Safe Word:**
    - Pick a word like "Blueberry". Tell your ${inputs.hasChildren ? 'children' : 'neighbors'} to call for help when they hear it.

    **3. Escape Route:**
    - Identify the safest exit (door/window) that is not blocked.

    **4. Essentials Bag:**
    - Pack ID, ${inputs.accessToMoney === 'No access' ? 'hidden cash' : 'bank cards'}, and medicines. Hide it near the door.

    **5. Technology:**
    - Delete this app history if your phone is monitored.`;
  },

  // --- MAPS GROUNDING / SAFE PLACE FINDER ---

  async findNearbyPlaces(lat: number, lng: number): Promise<SupportCentre[]> {
    if (!ai) return [];

    try {
      // Using Gemini with Google Maps Tool
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: "Find the 5 nearest locations for: 'Gender Violence Recovery Centre', 'Police Station', and 'Hospital'.",
        config: {
          tools: [{ googleMaps: {} }],
          toolConfig: {
            retrievalConfig: {
              latLng: {
                latitude: lat,
                longitude: lng
              }
            }
          }
        },
      });

      // Extract Structured Data from Grounding Chunks
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      const places: SupportCentre[] = [];

      if (chunks) {
        chunks.forEach((chunk: any, index: number) => {
          if (chunk.web && chunk.web.uri && chunk.web.title) {
            // Basic classification based on title keywords
            let type = "Support";
            const lowerTitle = chunk.web.title.toLowerCase();
            if (lowerTitle.includes("police")) type = "Police";
            else if (lowerTitle.includes("hospital") || lowerTitle.includes("medical")) type = "Medical";
            else if (lowerTitle.includes("shelter") || lowerTitle.includes("safe")) type = "Shelter";

            places.push({
              id: `gm_${index}`,
              name: chunk.web.title,
              address: "Tap navigate for directions", // Maps grounding often gives URI, not always text address in chunk
              type: type,
              distance: "Nearby", // Grounding finds nearby by default
              // We use the URI provided by grounding for accurate navigation
              mapUri: chunk.web.uri 
            });
          }
        });
      }

      return places;

    } catch (e) {
      console.error("Gemini Maps Error:", e);
      return [];
    }
  }
};

import React, { useState, useEffect } from 'react';
import { Hotline, SupportCentre } from '../types';
import { BackendService } from '../services/mockBackend';
import { GeminiService } from '../services/geminiService';
import { Phone, MapPin, ExternalLink, Navigation, Loader2, Map as MapIcon, Compass } from 'lucide-react';

export const HotlinesView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'hotlines' | 'centres'>('hotlines');
  const [hotlines, setHotlines] = useState<Hotline[]>([]);
  const [centres, setCentres] = useState<SupportCentre[]>([]);
  const [loadingCentres, setLoadingCentres] = useState(false);
  const [userLocation, setUserLocation] = useState<{lat: number, lng: number} | null>(null);
  const [locationError, setLocationError] = useState('');
  const [isOnlineSearch, setIsOnlineSearch] = useState(false);

  useEffect(() => {
    BackendService.getHotlines().then(setHotlines);
    // Initial load default
    BackendService.getSupportCentres(0, 0).then(setCentres);
  }, []);

  const handleLocateAndFetch = () => {
    setLoadingCentres(true);
    setLocationError('');
    setIsOnlineSearch(false);

    if (!navigator.geolocation) {
      setLocationError('Geolocation is not supported by your browser/device.');
      setLoadingCentres(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        setUserLocation({ lat: latitude, lng: longitude });

        // 1. Try Online Real-time Search (Gemini Maps)
        if (navigator.onLine) {
           try {
             const onlineResults = await GeminiService.findNearbyPlaces(latitude, longitude);
             if (onlineResults.length > 0) {
                setCentres(onlineResults);
                setIsOnlineSearch(true);
                setLoadingCentres(false);
                return;
             }
           } catch (e) {
             console.log("Online search failed, sticking to local db");
           }
        }

        // 2. Fallback to Local Database if offline or API fails
        const localResults = await BackendService.getSupportCentres(latitude, longitude);
        setCentres(localResults);
        setLoadingCentres(false);
      },
      (err) => {
        console.error(err);
        setLocationError('Unable to retrieve your location. Please check GPS settings.');
        setLoadingCentres(false);
      },
      { timeout: 10000, enableHighAccuracy: true }
    );
  };

  // Trigger location fetch when entering centres tab
  useEffect(() => {
    if (activeTab === 'centres' && !userLocation) {
      handleLocateAndFetch();
    }
  }, [activeTab]);

  return (
    <div className="p-4 pb-20 animate-slide-up h-full flex flex-col">
      <h1 className="text-2xl font-bold mb-6 text-brand-700 dark:text-brand-400">Help & Support</h1>

      <div className="flex p-1 bg-gray-200 dark:bg-gray-800 rounded-xl mb-6">
        <button 
          onClick={() => setActiveTab('hotlines')}
          className={`flex-1 py-2 rounded-lg text-sm font-medium transition-all ${
            activeTab === 'hotlines' ? 'bg-white dark:bg-gray-700 text-brand-600 shadow-sm' : 'text-gray-500'
          }`}
        >
          Hotlines
        </button>
        <button 
          onClick={() => setActiveTab('centres')}
          className={`flex-1 py-2 rounded-lg text-sm font-medium transition-all ${
            activeTab === 'centres' ? 'bg-white dark:bg-gray-700 text-brand-600 shadow-sm' : 'text-gray-500'
          }`}
        >
          Find Shelters
        </button>
      </div>

      <div className="flex-1 overflow-y-auto space-y-4 no-scrollbar">
        {activeTab === 'hotlines' ? (
          hotlines.map(hotline => (
            <div key={hotline.id} className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 flex items-center justify-between">
              <div>
                <span className={`text-xs px-2 py-1 rounded-full ${
                  hotline.category === 'Emergency' ? 'bg-red-100 text-red-700' : 'bg-blue-100 text-blue-700'
                }`}>
                  {hotline.category}
                </span>
                <h3 className="font-bold text-lg mt-1">{hotline.number}</h3>
                <p className="text-sm text-gray-500">{hotline.name}</p>
              </div>
              <a href={`tel:${hotline.number}`} className="bg-green-500 hover:bg-green-600 text-white p-3 rounded-full shadow-lg transition-transform active:scale-90">
                <Phone className="w-5 h-5" />
              </a>
            </div>
          ))
        ) : (
          <>
            {/* Visual Map Embed (Only works if Online, otherwise show placeholder) */}
            <div className="w-full h-56 bg-gray-200 dark:bg-gray-700 rounded-2xl mb-4 relative overflow-hidden shadow-inner border border-gray-300 dark:border-gray-600">
               {userLocation && navigator.onLine ? (
                 <iframe 
                   width="100%" 
                   height="100%" 
                   frameBorder="0" 
                   style={{ border: 0 }}
                   src={`https://maps.google.com/maps?q=${userLocation.lat},${userLocation.lng}&z=14&output=embed`}
                   allowFullScreen
                   title="User Location Map"
                 ></iframe>
               ) : (
                 <div className="absolute inset-0 flex items-center justify-center flex-col text-gray-400 bg-gray-100 dark:bg-gray-800">
                    {loadingCentres ? (
                       <Loader2 className="w-8 h-8 mb-2 animate-spin text-brand-500" />
                    ) : (
                       <MapIcon className="w-8 h-8 mb-2" />
                    )}
                    <span className="text-xs text-center px-4">
                      {loadingCentres 
                        ? 'Locating Safe Places...' 
                        : (userLocation ? 'Map unavailable offline (List Below)' : 'Tap Refresh to find nearby help')
                      }
                    </span>
                 </div>
               )}
            </div>

            <div className="flex justify-between items-center mb-2">
               <div className="flex items-center gap-2">
                 <h3 className="font-bold text-gray-700 dark:text-gray-200">Nearby Support</h3>
                 {isOnlineSearch && <span className="text-[10px] bg-green-100 text-green-700 px-2 py-0.5 rounded-full font-bold flex items-center gap-1"><Compass className="w-3 h-3"/> Live GPS</span>}
               </div>
               <button 
                 onClick={handleLocateAndFetch} 
                 className="text-xs text-brand-600 flex items-center bg-brand-50 dark:bg-brand-900/20 px-2 py-1 rounded hover:bg-brand-100"
               >
                 <Navigation className="w-3 h-3 mr-1" /> Refresh GPS
               </button>
            </div>

            {locationError && (
              <p className="text-xs text-red-500 mb-2">{locationError}</p>
            )}

            {centres.map((centre, idx) => (
              <div key={centre.id || idx} className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 animate-fade-in">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-bold text-gray-900 dark:text-white max-w-[80%]">{centre.name}</h3>
                  <span className={`text-xs text-white px-2 py-1 rounded font-bold ${
                      centre.type === 'Police' ? 'bg-blue-600' : 
                      centre.type === 'Medical' ? 'bg-red-500' : 'bg-brand-500'
                  }`}>
                    {centre.type}
                  </span>
                </div>
                <p className="text-sm text-gray-500 mb-3">{centre.address}</p>
                <div className="flex gap-2">
                   {/* 
                     Navigation Link:
                     - If 'mapUri' exists (from Google Maps Grounding), use it directly.
                     - Otherwise construct a Google Maps Directions URL.
                   */}
                   <a 
                     href={(centre as any).mapUri || `https://www.google.com/maps/dir/?api=1&destination=${encodeURIComponent(centre.name + ' ' + centre.address)}`}
                     target="_blank" 
                     rel="noopener noreferrer"
                     className="flex-1 py-3 bg-brand-50 dark:bg-brand-900/20 text-brand-700 dark:text-brand-300 rounded-lg text-sm font-bold flex items-center justify-center gap-2 hover:bg-brand-100 dark:hover:bg-brand-900/40 transition-colors"
                   >
                     <Navigation className="w-4 h-4" /> Get Directions
                   </a>
                </div>
              </div>
            ))}
          </>
        )}
      </div>
    </div>
  );
};

