const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB Limit

interface ReportViewProps {
  onReportSubmitted: (code: string) => void;
  lang: Language;
  onSafetyPlanClick: () => void;
}

export const ReportView: React.FC<ReportViewProps> = ({ onReportSubmitted, lang, onSafetyPlanClick }) => {
  const t = getTranslation(lang);

  const [type, setType] = useState<GBVType>(GBVType.PHYSICAL);
  const [location, setLocation] = useState('');
  const [incidentDate, setIncidentDate] = useState('');
  const [description, setDescription] = useState('');
  const [files, setFiles] = useState<Attachment[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [gettingLocation, setGettingLocation] = useState(false);
  const [success, setSuccess] = useState(false);
  const [trackingCode, setTrackingCode] = useState('');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Incognito Mode: If true, ID is not saved to device
  const [isIncognito, setIsIncognito] = useState(false);

  // Camouflage Mode: Hides the screen with a fake weather app
  const [isCamouflaged, setIsCamouflaged] = useState(false);

  // Auto-redirect timer reference to clear it if needed
  const [redirectTimer, setRedirectTimer] = useState<ReturnType<typeof setTimeout> | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setErrorMsg(null);
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.size > MAX_FILE_SIZE) {
        setErrorMsg(`File "${file.name}" is too large. Maximum size is 5MB.`);
        return;
      }
      const newAttachment: Attachment = {
        name: file.name,
        type: file.type.startsWith('image') ? 'image' : file.type.startsWith('audio') ? 'audio' : 'video',
        url: URL.createObjectURL(file), 
        file: file 
      };
      setFiles([...files, newAttachment]);
    }
  };

  const removeFile = (index: number) => {
    const newFiles = [...files];
    newFiles.splice(index, 1);
    setFiles(newFiles);
  };

  const handleGetGPS = () => {
    if (!navigator.geolocation) {
        alert("Geolocation is not supported by your browser");
        return;
    }
    setGettingLocation(true);
    navigator.geolocation.getCurrentPosition(
        (position) => {
            // Success
            const { latitude, longitude } = position.coords;
            const gpsString = `${latitude.toFixed(6)}, ${longitude.toFixed(6)}`;
            // Generate a Google Maps link. This is much better for responders than just text.
            const mapLink = `https://maps.google.com/?q=${latitude},${longitude}`;
            setLocation(mapLink);
            setGettingLocation(false);
        },
        (error) => {
            // Error
            console.error(error);
            alert("Unable to retrieve location. Please type it manually.");
            setGettingLocation(false);
        },
        { enableHighAccuracy: true, timeout: 10000 }
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMsg(null);

    if (!location.trim() || !description.trim()) {
        setErrorMsg("Please provide both a location and a description of the incident.");
        return;
    }

    // GENERATE ID
    let anonymousUserId = '';

    // If NOT incognito, try to get existing ID or save new one
    if (!isIncognito) {
       anonymousUserId = localStorage.getItem('safevoice_anon_id') || '';
    }

    if (!anonymousUserId) {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
          anonymousUserId = crypto.randomUUID();
      } else {
          // Fallback UUID for insecure contexts
          anonymousUserId = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
            var r = Math.random() * 16 | 0, v = c === 'x' ? r : (r & 0x3 | 0x8);
            return v.toString(16);
          });
      }
      // ONLY save if NOT incognito
      if (!isIncognito) {
         localStorage.setItem('safevoice_anon_id', anonymousUserId);
      }
    }

    setIsSubmitting(true);
    try {
      const report = await BackendService.createReport({
        type,
        location,
        description,
        incidentDate: incidentDate || new Date().toISOString(), // Use selected time or now
        attachments: files,
        anonymousUserId
      });
      setTrackingCode(report.trackingCode);
      setSuccess(true);

      // Auto-redirect after 2.5 seconds (slightly longer so they see the code)
      const timer = setTimeout(() => {
        onReportSubmitted(report.trackingCode);
      }, 2500);
      setRedirectTimer(timer);

    } catch (error: any) {
      console.error("Submission Error Details:", error);
      // Directly show the error message to help debug connection issues
      setErrorMsg(error.message || "An unexpected error occurred.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleManualRedirect = () => {
    if (redirectTimer) clearTimeout(redirectTimer);
    onReportSubmitted(trackingCode);
  };

  useEffect(() => {
    return () => {
      if (redirectTimer) clearTimeout(redirectTimer);
    };
  }, [redirectTimer]);

  // --- CAMOUFLAGE SCREEN ---
  if (isCamouflaged) {
    return (
        <div 
          className="fixed inset-0 z-[100] bg-blue-400 flex flex-col items-center justify-center text-white cursor-pointer select-none"
          onDoubleClick={() => setIsCamouflaged(false)}
        >
            <CloudSun className="w-24 h-24 mb-4 text-yellow-300" />
            <div className="text-center">
                <h1 className="text-8xl font-thin tracking-tighter">10:42</h1>
                <p className="text-2xl mt-2 font-medium">Tue, Oct 24</p>
                <div className="mt-12 flex gap-12 justify-center">
                    <div className="text-center">
                        <span className="block text-4xl font-bold">24°</span>
                        <span className="text-sm opacity-80 uppercase tracking-widest">High</span>
                    </div>
                    <div className="text-center">
                        <span className="block text-4xl font-bold opacity-75">18°</span>
                        <span className="text-sm opacity-60 uppercase tracking-widest">Low</span>
                    </div>
                </div>
            </div>
            <p className="absolute bottom-8 text-xs opacity-40 font-mono">Double tap screen to unlock</p>
        </div>
    );
  }

  if (success) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center p-6 animate-fade-in">
        <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mb-4">
          <CheckCircle className="w-10 h-10 text-green-600" />
        </div>
        <h2 className="text-2xl font-bold mb-2 text-gray-800 dark:text-white">Report Received</h2>
        <p className="text-gray-600 dark:text-gray-300 mb-6">Your tracking code is:</p>
        <div className="bg-gray-100 dark:bg-gray-800 p-4 rounded-xl mb-6 border-2 border-dashed border-gray-300 dark:border-gray-600">
          <span className="text-3xl font-mono font-bold text-brand-600 tracking-wider select-all">
            {trackingCode}
          </span>
        </div>

        <div className="bg-yellow-50 dark:bg-yellow-900/20 p-3 rounded-lg mb-6 text-xs text-yellow-800 dark:text-yellow-200">
           {isIncognito 
             ? "⚠ You used Incognito Mode. You MUST save this code now. It will not be saved on this device."
             : "This code has been saved to your history."
           }
        </div>

        <button 
          onClick={handleManualRedirect}
          className="bg-brand-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 hover:bg-brand-700 transition-colors shadow-lg"
        >
          Track Case Now <ArrowRight className="w-5 h-5" />
        </button>
        <p className="text-xs text-gray-400 mt-4">Redirecting automatically...</p>
      </div>
    );
  }

  return (
    <div className="p-4 pb-20 animate-slide-up relative">
      <div className="flex justify-between items-start mb-6">
        <h1 className="text-2xl font-bold text-brand-700 dark:text-brand-400">{t.report_title}</h1>

        {/* Safety Actions */}
        <div className="flex gap-2">
            <button 
                onClick={() => setIsCamouflaged(true)}
                className="bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-200 px-3 py-2 rounded-lg text-xs font-bold flex items-center gap-1 hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors"
                title="Mask Screen (Fake Weather App)"
            >
                <Eye className="w-4 h-4" /> Hide Screen
            </button>
        </div>
      </div>

      <div className="bg-yellow-50 dark:bg-yellow-900/20 border-l-4 border-yellow-400 p-4 mb-4 rounded-r">
        <div className="flex">
          <AlertCircle className="w-5 h-5 text-yellow-500 mr-2 flex-shrink-0" />
          <p className="text-sm text-yellow-700 dark:text-yellow-200">
            {t.safety_priority}
          </p>
        </div>
      </div>

      <div className="mb-6 flex justify-end">
         <button 
           type="button" 
           onClick={onSafetyPlanClick}
           className="text-sm text-brand-600 dark:text-brand-400 flex items-center hover:underline"
         >
           <Shield className="w-4 h-4 mr-1" />
           {t.not_ready_safety_plan}
         </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5">

        {/* PRIVACY TOGGLE */}
        <div className={`p-4 rounded-xl border-2 transition-colors cursor-pointer flex items-center gap-3 ${isIncognito ? 'bg-gray-800 border-gray-600 text-white' : 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-300'}`} onClick={() => setIsIncognito(!isIncognito)}>
           <div className={`w-10 h-10 rounded-full flex items-center justify-center ${isIncognito ? 'bg-gray-700 text-white' : 'bg-gray-100 dark:bg-gray-700 text-gray-400'}`}>
              <EyeOff className="w-5 h-5" />
           </div>
           <div className="flex-1">
              <h3 className="font-bold text-sm">Incognito Mode</h3>
              <p className="text-xs opacity-80">
                {isIncognito 
                  ? "Maximum Privacy. ID not saved on this device." 
                  : "Standard. ID saved for easy tracking."}
              </p>
           </div>
           <div className={`w-10 h-6 rounded-full relative transition-colors ${isIncognito ? 'bg-green-500' : 'bg-gray-300 dark:bg-gray-600'}`}>
              <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-all shadow-sm ${isIncognito ? 'left-5' : 'left-1'}`}></div>
           </div>
        </div>

        {errorMsg && (
          <div className="bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-300 p-4 rounded-xl text-sm flex flex-col items-start animate-fade-in border border-red-100 dark:border-red-800 break-words w-full">
            <div className="flex items-center mb-1 font-bold">
               <XCircle className="w-5 h-5 mr-2 flex-shrink-0" />
               <span>Submission Failed</span>
            </div>
            <span className="text-xs sm:text-sm">{errorMsg}</span>
          </div>
        )}

        {/* INCIDENT TYPE */}
        <div>
          <label className="block text-sm font-medium mb-1">{t.type_incident}</label>
          <select 
            value={type} 
            onChange={(e) => setType(e.target.value as GBVType)}
            className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none"
          >
            {Object.values(GBVType).map(t => (
              <option key={t} value={t}>{t}</option>
            ))}
          </select>
        </div>

        {/* TIME OF INCIDENT */}
        <div>
           <label className="block text-sm font-medium mb-1 flex items-center gap-1">
             <Calendar className="w-4 h-4 text-gray-400" />
             {t.time_incident}
           </label>
           <input 
             type="datetime-local"
             value={incidentDate}
             onChange={(e) => setIncidentDate(e.target.value)}
             className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none"
           />
        </div>

        {/* LOCATION WITH GPS */}
        <div>
          <label className="block text-sm font-medium mb-1">{t.location}</label>
          <div className="flex gap-2">
            <div className="relative flex-1">
                <MapPin className="absolute left-3 top-3.5 w-5 h-5 text-gray-400" />
                <input 
                type="text" 
                placeholder={t.location_placeholder}
                value={location}
                onChange={(e) => setLocation(e.target.value)}
                className="w-full pl-10 p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none"
                required
                />
            </div>
            <button 
                type="button"
                onClick={handleGetGPS}
                disabled={gettingLocation}
                className="bg-brand-600 text-white p-3 rounded-xl hover:bg-brand-700 transition-colors flex items-center justify-center min-w-[50px] shadow-sm active:scale-95"
                title={t.use_gps}
            >
                {gettingLocation ? <Loader2 className="animate-spin w-5 h-5"/> : <Crosshair className="w-5 h-5" />}
            </button>
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium mb-1">{t.description}</label>
          <textarea 
            placeholder={t.desc_placeholder}
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            className="w-full p-3 h-32 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 focus:ring-2 focus:ring-brand-500 outline-none resize-none"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium mb-2">{t.evidence}</label>
          <div className="flex gap-4 mb-4">
             <label className="flex flex-col items-center justify-center w-24 h-24 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400 transition-colors">
                <Camera className="w-6 h-6 text-gray-400 mb-1" />
                <span className="text-xs text-gray-500">{t.photo}</span>
                <input type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
             </label>
             <label className="flex flex-col items-center justify-center w-24 h-24 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400 transition-colors">
                <Mic className="w-6 h-6 text-gray-400 mb-1" />
                <span className="text-xs text-gray-500">{t.audio}</span>
                <input type="file" accept="audio/*" className="hidden" onChange={handleFileChange} />
             </label>
             <label className="flex flex-col items-center justify-center w-24 h-24 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400 transition-colors">
                <FileUp className="w-6 h-6 text-gray-400 mb-1" />
                <span className="text-xs text-gray-500">{t.video}</span>
                <input type="file" accept="video/*" className="hidden" onChange={handleFileChange} />
             </label>
          </div>
          {files.length > 0 && (
            <div className="space-y-2">
              {files.map((f, idx) => (
                <div key={idx} className="flex items-center justify-between text-sm p-2 bg-gray-100 dark:bg-gray-800 rounded-lg">
                  <div className="flex items-center overflow-hidden">
                    <CheckCircle className="w-4 h-4 text-green-500 mr-2 flex-shrink-0" />
                    <span className="truncate">{f.name}</span>
                  </div>
                  <button 
                    type="button" 
                    onClick={() => removeFile(idx)} 
                    className="text-red-500 hover:text-red-700 p-1"
                  >
                      <XCircle className="w-4 h-4" />
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        <button 
          type="submit" 
          disabled={isSubmitting}
          className="w-full bg-brand-600 hover:bg-brand-700 text-white p-4 rounded-xl font-bold shadow-lg shadow-brand-500/30 transition-all active:scale-95 disabled:opacity-70 flex justify-center items-center"
        >
          {isSubmitting ? (
             <>
               <Loader2 className="animate-spin w-5 h-5 mr-2" /> 
               {files.length > 0 ? 'Uploading Evidence...' : 'Submitting...'}
             </>
          ) : t.submit_btn}
        </button>
      </form>
    </div>
  );
};

export enum AppView {
  HOME = 'home',
  REPORT = 'report',
  TRACK = 'track',
  EDUCATION = 'education',
  HOTLINES = 'hotlines',
  CHAT = 'chat',
  SAFETY_PLAN = 'safety_plan',
  ADMIN_LOGIN = 'admin_login',
  ADMIN_DASHBOARD = 'admin_dashboard',
}

export type Language = 'en' | 'sw';

export enum GBVType {
  PHYSICAL = 'Physical Violence',
  SEXUAL = 'Sexual Violence',
  EMOTIONAL = 'Emotional/Psychological',
  ECONOMIC = 'Economic Abuse',
  HARASSMENT = 'Sexual Harassment',
  OTHER = 'Other',
}

export enum ReportStatus {
  RECEIVED = 'submitted',
  ASSIGNED = 'assigned',
  IN_REVIEW = 'in_review',
  ACTION_TAKEN = 'action_taken',
  RESOLVED = 'resolved',
}

export interface AppwriteConfig {
  url: string;
  key: string;
}

export interface Attachment {
  name: string;
  type: 'image' | 'video' | 'audio';
  url: string;
  file?: File;
}

export interface CaseUpdate {
  id: string;
  content: string;
  timestamp: string;
  author: string;
}

export interface Report {
  id: string;
  trackingCode: string;
  type: GBVType;
  location: string;
  description: string;
  attachments: Attachment[];
  status: ReportStatus;
  statusHistory: { status: ReportStatus; timestamp: string }[];
  caseUpdates: CaseUpdate[];
  createdAt: string;
  anonymousUserId: string;

  // Assignment Fields
  assignedTo?: string; // ID of caseworker
  assignedToName?: string; // Name of caseworker
  assignedAt?: string; // ISO Timestamp
}

export interface Caseworker {
  id: string;
  name: string;
  phone: string;
  email: string;
  createdAt: string;
}

export interface EducationModule {
  id: string;
  title: string;
  description: string;
  content: string;
  imageUrl: string;
  quiz?: QuizQuestion[];
}

export interface QuizQuestion {
  question: string;
  options: string[];
  correctIndex: number;
}

export interface Hotline {
  id: string;
  name: string;
  number: string;
  category: 'Emergency' | 'Legal' | 'Medical' | 'Counseling';
  location?: { lat: number; lng: number };
}

export interface SupportCentre {
  id: string;
  name: string;
  address: string;
  distance: string;
  type: string;
  mapUri?: string;
}

import React, { useState, useEffect } from 'react';
import { Hotline, SupportCentre } from '../types';
import { BackendService } from '../services/mockBackend';
import { GeminiService } from '../services/geminiService';
import { Phone, MapPin, ExternalLink, Navigation, Loader2, Map as MapIcon, Compass } from 'lucide-react';

export const HotlinesView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'hotlines' | 'centres'>('hotlines');
  const [hotlines, setHotlines] = useState<Hotline[]>([]);
  const [centres, setCentres] = useState<SupportCentre[]>([]);
  const [loadingCentres, setLoadingCentres] = useState(false);
  const [userLocation, setUserLocation] = useState<{lat: number, lng: number} | null>(null);
  const [locationError, setLocationError] = useState('');
  const [isOnlineSearch, setIsOnlineSearch] = useState(false);

  useEffect(() => {
    BackendService.getHotlines().then(setHotlines);
    // Initial load default
    BackendService.getSupportCentres(0, 0).then(setCentres);
  }, []);

  const handleLocateAndFetch = () => {
    setLoadingCentres(true);
    setLocationError('');
    setIsOnlineSearch(false);

    if (!navigator.geolocation) {
      setLocationError('Geolocation is not supported by your browser/device.');
      setLoadingCentres(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        setUserLocation({ lat: latitude, lng: longitude });

        // 1. Try Online Real-time Search (Gemini Maps)
        if (navigator.onLine) {
           try {
             const onlineResults = await GeminiService.findNearbyPlaces(latitude, longitude);
             if (onlineResults.length > 0) {
                setCentres(onlineResults);
                setIsOnlineSearch(true);
                setLoadingCentres(false);
                return;
             }
           } catch (e) {
             console.log("Online search failed, sticking to local db");
           }
        }

        // 2. Fallback to Local Database if offline or API fails
        const localResults = await BackendService.getSupportCentres(latitude, longitude);
        setCentres(localResults);
        setLoadingCentres(false);
      },
      (err) => {
        console.error(err);
        setLocationError('Unable to retrieve your location. Please check GPS settings.');
        setLoadingCentres(false);
      },
      { timeout: 10000, enableHighAccuracy: true }
    );
  };

  // Trigger location fetch when entering centres tab
  useEffect(() => {
    if (activeTab === 'centres' && !userLocation) {
      handleLocateAndFetch();
    }
  }, [activeTab]);

  return (
    <div className="p-4 pb-20 animate-slide-up h-full flex flex-col">
      <h1 className="text-2xl font-bold mb-6 text-brand-700 dark:text-brand-400">Help & Support</h1>

      <div className="flex p-1 bg-gray-200 dark:bg-gray-800 rounded-xl mb-6">
        <button 
          onClick={() => setActiveTab('hotlines')}
          className={`flex-1 py-2 rounded-lg text-sm font-medium transition-all ${
            activeTab === 'hotlines' ? 'bg-white dark:bg-gray-700 text-brand-600 shadow-sm' : 'text-gray-500'
          }`}
        >
          Hotlines
        </button>
        <button 
          onClick={() => setActiveTab('centres')}
          className={`flex-1 py-2 rounded-lg text-sm font-medium transition-all ${
            activeTab === 'centres' ? 'bg-white dark:bg-gray-700 text-brand-600 shadow-sm' : 'text-gray-500'
          }`}
        >
          Find Shelters
        </button>
      </div>

      <div className="flex-1 overflow-y-auto space-y-4 no-scrollbar">
        {activeTab === 'hotlines' ? (
          hotlines.map(hotline => (
            <div key={hotline.id} className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 flex items-center justify-between">
              <div>
                <span className={`text-xs px-2 py-1 rounded-full ${
                  hotline.category === 'Emergency' ? 'bg-red-100 text-red-700' : 'bg-blue-100 text-blue-700'
                }`}>
                  {hotline.category}
                </span>
                <h3 className="font-bold text-lg mt-1">{hotline.number}</h3>
                <p className="text-sm text-gray-500">{hotline.name}</p>
              </div>
              <a href={`tel:${hotline.number}`} className="bg-green-500 hover:bg-green-600 text-white p-3 rounded-full shadow-lg transition-transform active:scale-90">
                <Phone className="w-5 h-5" />
              </a>
            </div>
          ))
        ) : (
          <>
            {/* Visual Map Embed (Only works if Online, otherwise show placeholder) */}
            <div className="w-full h-56 bg-gray-200 dark:bg-gray-700 rounded-2xl mb-4 relative overflow-hidden shadow-inner border border-gray-300 dark:border-gray-600">
               {userLocation && navigator.onLine ? (
                 <iframe 
                   width="100%" 
                   height="100%" 
                   frameBorder="0" 
                   style={{ border: 0 }}
                   src={`https://maps.google.com/maps?q=${userLocation.lat},${userLocation.lng}&z=14&output=embed`}
                   allowFullScreen
                   title="User Location Map"
                 ></iframe>
               ) : (
                 <div className="absolute inset-0 flex items-center justify-center flex-col text-gray-400 bg-gray-100 dark:bg-gray-800">
                    {loadingCentres ? (
                       <Loader2 className="w-8 h-8 mb-2 animate-spin text-brand-500" />
                    ) : (
                       <MapIcon className="w-8 h-8 mb-2" />
                    )}
                    <span className="text-xs text-center px-4">
                      {loadingCentres 
                        ? 'Locating Safe Places...' 
                        : (userLocation ? 'Map unavailable offline (List Below)' : 'Tap Refresh to find nearby help')
                      }
                    </span>
                 </div>
               )}
            </div>

            <div className="flex justify-between items-center mb-2">
               <div className="flex items-center gap-2">
                 <h3 className="font-bold text-gray-700 dark:text-gray-200">Nearby Support</h3>
                 {isOnlineSearch && <span className="text-[10px] bg-green-100 text-green-700 px-2 py-0.5 rounded-full font-bold flex items-center gap-1"><Compass className="w-3 h-3"/> Live GPS</span>}
               </div>
               <button 
                 onClick={handleLocateAndFetch} 
                 className="text-xs text-brand-600 flex items-center bg-brand-50 dark:bg-brand-900/20 px-2 py-1 rounded hover:bg-brand-100"
               >
                 <Navigation className="w-3 h-3 mr-1" /> Refresh GPS
               </button>
            </div>

            {locationError && (
              <p className="text-xs text-red-500 mb-2">{locationError}</p>
            )}

            {centres.map((centre, idx) => (
              <div key={centre.id || idx} className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 animate-fade-in">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-bold text-gray-900 dark:text-white max-w-[80%]">{centre.name}</h3>
                  <span className={`text-xs text-white px-2 py-1 rounded font-bold ${
                      centre.type === 'Police' ? 'bg-blue-600' : 
                      centre.type === 'Medical' ? 'bg-red-500' : 'bg-brand-500'
                  }`}>
                    {centre.type}
                  </span>
                </div>
                <p className="text-sm text-gray-500 mb-3">{centre.address}</p>
                <div className="flex gap-2">
                   {/* 
                     Navigation Link:
                     - If 'mapUri' exists (from Google Maps Grounding), use it directly.
                     - Otherwise construct a Google Maps Directions URL.
                   */}
                   <a 
                     href={centre.mapUri || `https://www.google.com/maps/dir/?api=1&destination=${encodeURIComponent(centre.name + ' ' + centre.address)}`}
                     target="_blank" 
                     rel="noopener noreferrer"
