            { id: '4', name: 'Police Gender Desk - Kilimani', address: 'Kilimani, Nairobi', type: 'Police', lat: -1.2885, lng: 36.7845 },
            { id: '5', name: 'Coast Gen. Hospital GBV Centre', address: 'Mombasa', type: 'Medical', lat: -4.0547, lng: 39.6636 },
            { id: '6', name: 'Moi Teaching Referral Hospital', address: 'Eldoret', type: 'Medical', lat: 0.5143, lng: 35.2698 },
            { id: '7', name: 'Kisumu County Hospital GVRC', address: 'Kisumu', type: 'Medical', lat: -0.1022, lng: 34.7617 }
        ];

        // Calculate distances and sort
        const sorted = ALL_CENTRES.map(c => ({
            ...c,
            distVal: getDistanceFromLatLonInKm(lat, lng, c.lat, c.lng)
        })).sort((a, b) => a.distVal - b.distVal);

        // Map to SupportCentre interface
        return sorted.map(c => ({
            id: c.id,
            name: c.name,
            address: c.address,
            type: c.type,
            distance: c.distVal < 1 ? `${(c.distVal * 1000).toFixed(0)} m` : `${c.distVal.toFixed(1)} km`,
            // If distance is huge (>500km), it might be irrelevant, but we return sorted list anyway.
            // In a real app, we might filter: .filter(c => c.distVal < 50)
        })).slice(0, 5); // Return top 5 closest
    },

    async seedDatabase() {
        return { success: true, message: "Use Supabase Dashboard SQL Editor to seed." };
    },

    addToHistory(code: string) {
        const STORAGE_KEY_HISTORY = 'safevoice_report_history';
        const history = JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
        if (!history.includes(code)) {
            history.unshift(code);
            localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(history));
        }
    },

    getHistory(): string[] {
        const STORAGE_KEY_HISTORY = 'safevoice_report_history';
        return JSON.parse(localStorage.getItem(STORAGE_KEY_HISTORY) || '[]');
    },

    async checkConnection(): Promise<{success: boolean, message?: string}> {
        try {
            const { data, error } = await supabase.from(REPORTS_TABLE).select('count').limit(1);
            if (error) throw error;
            return { success: true };
        } catch (e: any) {
             return { success: false, message: `Supabase Error: ${e.message}. Check Config.` };
        }
    }
};

