import { GBVType, Attachment, Language } from '../types';
import { BackendService } from '../services/mockBackend';
import { getTranslation } from '../services/translations';
import { AlertCircle, Camera, Mic, MapPin, Loader2, CheckCircle, FileUp, XCircle, Calendar, Crosshair, Shield, ArrowRight, EyeOff, Info, CloudSun, Eye, Phone } from 'lucide-react';

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB Limit

interface ReportViewProps {
  onReportSubmitted: (code: string) => void;
  lang: Language;
  onSafetyPlanClick: () => void;
}

export const ReportView: React.FC<ReportViewProps> = ({ onReportSubmitted, lang, onSafetyPlanClick }) => {
  const t = getTranslation(lang);

  const [type, setType] = useState<GBVType>(GBVType.PHYSICAL);
  const [location, setLocation] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [incidentDate, setIncidentDate] = useState('');
  const [description, setDescription] = useState('');
  const [files, setFiles] = useState<Attachment[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [gettingLocation, setGettingLocation] = useState(false);
  const [success, setSuccess] = useState(false);
  const [trackingCode, setTrackingCode] = useState('');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isIncognito, setIsIncognito] = useState(false);
  const [isCamouflaged, setIsCamouflaged] = useState(false);
  const [redirectTimer, setRedirectTimer] = useState<ReturnType<typeof setTimeout> | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setErrorMsg(null);
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.size > MAX_FILE_SIZE) {
        setErrorMsg(`File "${file.name}" is too large. Maximum size is 5MB.`);
        return;
      }
      const newAttachment: Attachment = {
        name: file.name,
        type: file.type.startsWith('image') ? 'image' : file.type.startsWith('audio') ? 'audio' : 'video',
        url: URL.createObjectURL(file), 
        file: file 
      };
      setFiles([...files, newAttachment]);
    }
  };

  const removeFile = (index: number) => {
    const newFiles = [...files];
    newFiles.splice(index, 1);
    setFiles(newFiles);
  };

  const handleGetGPS = () => {
    if (!navigator.geolocation) {
        alert("Geolocation is not supported by your browser");
        return;
    }
    setGettingLocation(true);
    navigator.geolocation.getCurrentPosition(
        (position) => {
            const { latitude, longitude } = position.coords;
            const mapLink = `https://maps.google.com/?q=${latitude},${longitude}`;
            setLocation(mapLink);
            setGettingLocation(false);
        },
        (error) => {
            console.error(error);
            alert("Unable to retrieve location. Please type it manually.");
            setGettingLocation(false);
        },
        { enableHighAccuracy: true, timeout: 10000 }
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMsg(null);

    if (!location.trim() || !description.trim()) {
        setErrorMsg("Please provide both a location and a description.");
        return;
    }

    let anonymousUserId = '';
    if (!isIncognito) {
       anonymousUserId = localStorage.getItem('safevoice_anon_id') || '';
    }

    if (!anonymousUserId) {
      anonymousUserId = crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).substring(7);
      if (!isIncognito) {
         localStorage.setItem('safevoice_anon_id', anonymousUserId);
      }
    }

    setIsSubmitting(true);
    try {
      const report = await BackendService.createReport({
        type,
        location,
        phoneNumber,
        description,
        incidentDate: incidentDate || new Date().toISOString(),
        attachments: files,
        anonymousUserId
      });
      setTrackingCode(report.trackingCode);
      setSuccess(true);

      const timer = setTimeout(() => {
        onReportSubmitted(report.trackingCode);
      }, 3000);
      setRedirectTimer(timer);

    } catch (error: any) {
      setErrorMsg(error.message || "An unexpected error occurred.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleManualRedirect = () => {
    if (redirectTimer) clearTimeout(redirectTimer);
    onReportSubmitted(trackingCode);
  };

  if (isCamouflaged) {
    return (
        <div className="fixed inset-0 z-[100] bg-blue-400 flex flex-col items-center justify-center text-white cursor-pointer select-none" onDoubleClick={() => setIsCamouflaged(false)}>
            <CloudSun className="w-24 h-24 mb-4 text-yellow-300" />
            <div className="text-center">
                <h1 className="text-8xl font-thin tracking-tighter">10:42</h1>
                <p className="text-2xl mt-2 font-medium">Tue, Oct 24</p>
                <div className="mt-12 flex gap-12 justify-center">
                    <div className="text-center">
                        <span className="block text-4xl font-bold">24°</span>
                        <span className="text-sm opacity-80 uppercase tracking-widest">High</span>
                    </div>
                    <div className="text-center">
                        <span className="block text-4xl font-bold opacity-75">18°</span>
                        <span className="text-sm opacity-60 uppercase tracking-widest">Low</span>
                    </div>
                </div>
            </div>
        </div>
    );
  }

  if (success) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center p-6 animate-fade-in">
        <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mb-4">
          <CheckCircle className="w-10 h-10 text-green-600" />
        </div>
        <h2 className="text-2xl font-bold mb-2">Report Received</h2>
        <div className="bg-gray-100 dark:bg-gray-800 p-4 rounded-xl mb-6 border-2 border-dashed border-gray-300">
          <span className="text-3xl font-mono font-bold text-brand-600 tracking-wider">
            {trackingCode}
          </span>
        </div>
        <button onClick={handleManualRedirect} className="bg-brand-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2">
          Track Case Now <ArrowRight className="w-5 h-5" />
        </button>
      </div>
    );
  }

  return (
    <div className="p-4 pb-20 animate-slide-up relative">
      <div className="flex justify-between items-start mb-6">
        <h1 className="text-2xl font-bold text-brand-700 dark:text-brand-400">{t.report_title}</h1>
        <button onClick={() => setIsCamouflaged(true)} className="bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-200 px-3 py-2 rounded-lg text-xs font-bold flex items-center gap-1">
            <Eye className="w-4 h-4" /> Mask Screen
        </button>
      </div>

      <div className="bg-yellow-50 dark:bg-yellow-900/20 border-l-4 border-yellow-400 p-4 mb-4 rounded-r flex gap-3">
        <AlertCircle className="w-5 h-5 text-yellow-500 flex-shrink-0" />
        <p className="text-sm text-yellow-700 dark:text-yellow-200">{t.safety_priority}</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5">
        <div className={`p-4 rounded-xl border-2 transition-colors cursor-pointer flex items-center gap-3 ${isIncognito ? 'bg-gray-800 border-gray-600 text-white' : 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-300'}`} onClick={() => setIsIncognito(!isIncognito)}>
           <EyeOff className="w-5 h-5" />
           <div className="flex-1 text-sm font-bold">Incognito Mode (Maximum Privacy)</div>
        </div>

        {errorMsg && <div className="bg-red-50 text-red-600 p-4 rounded-xl text-sm border border-red-100">{errorMsg}</div>}

        <div>
          <label className="block text-sm font-medium mb-1">{t.type_incident}</label>
          <select value={type} onChange={(e) => setType(e.target.value as GBVType)} className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800">
            {Object.values(GBVType).map(v => <option key={v} value={v}>{v}</option>)}
          </select>
        </div>

        <div className="grid grid-cols-2 gap-3">
          <div>
             <label className="block text-sm font-medium mb-1">{t.time_incident}</label>
             <input type="datetime-local" value={incidentDate} onChange={(e) => setIncidentDate(e.target.value)} className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 text-sm" />
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">{t.phone_number}</label>
            <input type="tel" value={phoneNumber} onChange={(e) => setPhoneNumber(e.target.value)} placeholder="+254..." className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 text-sm" />
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium mb-1">{t.location}</label>
          <div className="flex gap-2">
            <input type="text" placeholder={t.location_placeholder} value={location} onChange={(e) => setLocation(e.target.value)} className="flex-1 p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800" required />
            <button type="button" onClick={handleGetGPS} disabled={gettingLocation} className="bg-brand-600 text-white p-3 rounded-xl shadow-sm">
                {gettingLocation ? <Loader2 className="animate-spin w-5 h-5"/> : <Crosshair className="w-5 h-5" />}
            </button>
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium mb-1">{t.description}</label>
          <textarea placeholder={t.desc_placeholder} value={description} onChange={(e) => setDescription(e.target.value)} className="w-full p-3 h-32 rounded-xl border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 resize-none" required />
        </div>

        <div>
          <label className="block text-sm font-medium mb-2">{t.evidence}</label>
          <div className="flex gap-3 mb-4">
             {['photo', 'audio', 'video'].map(mediaType => (
               <label key={mediaType} className="flex flex-col items-center justify-center flex-1 h-20 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl cursor-pointer hover:border-brand-400">
                  {mediaType === 'photo' ? <Camera className="w-5 h-5 text-gray-400" /> : mediaType === 'audio' ? <Mic className="w-5 h-5 text-gray-400" /> : <FileUp className="w-5 h-5 text-gray-400" />}
                  <span className="text-[10px] text-gray-500 uppercase font-bold mt-1">{mediaType}</span>
                  <input type="file" accept={`${mediaType}/*`} className="hidden" onChange={handleFileChange} />
               </label>
             ))}
          </div>
          <div className="space-y-2">
              {files.map((f, idx) => (
                <div key={idx} className="flex items-center justify-between text-xs p-2 bg-gray-100 dark:bg-gray-800 rounded-lg">
                  <span className="truncate flex-1 pr-2">{f.name}</span>
                  <button type="button" onClick={() => removeFile(idx)} className="text-red-500"><XCircle className="w-4 h-4" /></button>
                </div>
              ))}
          </div>
        </div>

        <button type="submit" disabled={isSubmitting} className="w-full bg-brand-600 hover:bg-brand-700 text-white p-4 rounded-xl font-bold shadow-lg disabled:opacity-70 flex justify-center items-center">
          {isSubmitting ? <Loader2 className="animate-spin w-5 h-5 mr-2" /> : t.submit_btn}
        </button>
      </form>
    </div>
  );
};

