const API_KEY = process.env.API_KEY || '';

let ai: GoogleGenAI | null = null;
if (API_KEY) {
  ai = new GoogleGenAI({ apiKey: API_KEY });
}

export const GeminiService = {

  createChat(): Chat | null {
    if (ai) {
      try {
        return ai.chats.create({
          model: 'gemini-3-flash-preview',
          config: {
            tools: [{ googleSearch: {} }],
            systemInstruction: `You are SafeVoice AI, a GBV Crisis Specialist.
            SAFETY RULES:
            1. If a user mentions killing themselves, killing others, or is in active physical danger (e.g., 'he has a knife', 'I want to die'), START your response with: "EMERGENCY: PLEASE CALL 1195 OR 999 IMMEDIATELY. YOUR LIFE IS IN DANGER."
            2. Be empathetic but professional.
            3. Provide referrals to hospitals and legal aid.
            4. If asked to classify an incident, use the 6 core types of GBV: Physical, Sexual, Emotional, Economic, Harmful Traditional Practices, or Sexual Harassment.`
          }
        });
      } catch (e) {
        console.error("Failed to create chat session", e);
        return null;
      }
    }
    return null;
  },

  async classifyIncident(description: string): Promise<GBVType | string> {
     if (!ai) return "Unknown";
     try {
       const response = await ai.models.generateContent({
         model: 'gemini-3-flash-preview',
         contents: `Classify the following incident into one of the 6 core GBV types: Physical Violence, Sexual Violence, Emotional/Psychological Abuse, Economic/Financial Abuse, Harmful Traditional Practices, or Sexual Harassment. Return ONLY the category name. Description: "${description}"`,
       });
       return response.text.trim() as GBVType;
     } catch (e) {
       return "Review Pending";
     }
  },

  getOfflineResponse(userText: string): string {
    const lower = userText.toLowerCase();
    if (lower.includes('help') || lower.includes('danger') || lower.includes('knife') || lower.includes('kill')) {
        return "EMERGENCY: Please call 1195 immediately. If you are in Kenya, this is a 24-hour toll-free hotline for GBV. Move to a safe room and lock the door.";
    }
    return "I am here to support you. You can report an incident anonymously, create a safety plan, or find a nearby shelter in this app. Are you safe right now?";
  },

  async generateQuizForTopic(topic: string): Promise<QuizQuestion[]> {
    if (ai) {
      try {
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Generate 3 quiz questions about "${topic}" in GBV context. Return JSON.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: { type: Type.ARRAY, items: { type: Type.STRING } },
                  correctIndex: { type: Type.INTEGER }
                }
              }
            }
          }
        });
        return JSON.parse(response.text);
      } catch (error) {}
    }
    return [];
  },

  async generateSafetyPlan(inputs: any): Promise<string> {
    if (ai) {
      try {
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Create a 5-step safety plan for a survivor: ${JSON.stringify(inputs)}`,
        });
        return response.text;
      } catch (error) {}
    }
    return "Call 1195 and prepare a small bag with your ID and essential documents.";
  },

  async findNearbyPlaces(lat: number, lng: number): Promise<SupportCentre[]> {
    if (!ai) return [];
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: "Find 5 nearest GBV recovery centers or police stations near these coordinates.",
        config: {
          tools: [{ googleMaps: {} }],
          toolConfig: { retrievalConfig: { latLng: { latitude: lat, longitude: lng } } }
        },
      });
      const places: SupportCentre[] = [];
      response.candidates?.[0]?.groundingMetadata?.groundingChunks?.forEach((chunk: any, i: number) => {
        if (chunk.web) {
          places.push({ id: `gm_${i}`, name: chunk.web.title, address: "Nearby", type: "Support", distance: "Calculated", mapUri: chunk.web.uri });
        }
      });
      return places;
    } catch (e) { return []; }
  }
};

