                <div className={`max-w-[90%] p-3 rounded-2xl text-sm ${msg.sender === 'user' ? 'bg-brand-500 text-white rounded-tr-none' : 'bg-gray-100 dark:bg-gray-700 dark:text-gray-200 rounded-tl-none'}`}>
