                className="flex-1 p-3 rounded-2xl bg-white dark:bg-gray-800 text-sm border dark:border-gray-700 outline-none"
              />
              <button type="submit" disabled={loading} className="bg-brand-600 text-white p-3 rounded-2xl shadow-md disabled:opacity-50">
                <Send className="w-5 h-5" />
              </button>
            </form>
          </div>
        </div>
      )}
    </>
  );
};

import React, { useState } from 'react';
import { GBVType, Language } from '../types';
import { BackendService } from '../services/mockBackend';
import { getTranslation } from '../services/translations';
import { AlertCircle, Loader2, CheckCircle, Crosshair, ArrowRight, EyeOff, MapPin, Calendar, ListFilter, Map } from 'lucide-react';

interface ReportViewProps {
  onReportSubmitted: (code: string) => void;
  lang: Language;
}

export const ReportView: React.FC<ReportViewProps> = ({ onReportSubmitted, lang }) => {
  const t = getTranslation(lang);

  const [type, setType] = useState<GBVType>(GBVType.PHYSICAL);
  const [location, setLocation] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [incidentDate, setIncidentDate] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [gettingLocation, setGettingLocation] = useState(false);
  const [success, setSuccess] = useState(false);
  const [trackingCode, setTrackingCode] = useState('');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isIncognito, setIsIncognito] = useState(false);

  const handleGetGPS = () => {
    if (!navigator.geolocation) {
        alert("Geolocation is not supported by your browser");
        return;
    }
    setGettingLocation(true);
    setErrorMsg(null);

    navigator.geolocation.getCurrentPosition(
        (position) => {
            const { latitude, longitude, accuracy } = position.coords;
            // Higher accuracy is crucial for regions like Kakuma
            const mapLink = `https://maps.google.com/?q=${latitude},${longitude}`;
            setLocation(mapLink);
            setGettingLocation(false);
            console.log(`GPS Fixed with accuracy: ${accuracy}m`);
        },
        (error) => {
            let msg = "Unable to retrieve location.";
            if (error.code === 1) msg = "Permission denied. Please allow location access.";
            if (error.code === 3) msg = "GPS timeout. Try moving to an open area.";
            setErrorMsg(msg);
            setGettingLocation(false);
        },
        { 
          enableHighAccuracy: true, // MUST be true for precise Kakuma coordinates
          timeout: 15000,           // Longer timeout for remote areas
          maximumAge: 0 
        }
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMsg(null);

    if (!location.trim()) {
        setErrorMsg("Please provide a location.");
        return;
    }

    const anonymousUserId = isIncognito ? 'anon_' + Math.random().toString(36).substring(7) : (localStorage.getItem('safevoice_anon_id') || 'anon_user');

    setIsSubmitting(true);
    try {
      const report = await BackendService.createReport({
        type,
        location,
        phoneNumber,
        incidentDate: incidentDate || new Date().toISOString(),
        description: `Automatic report of ${type} at ${location}.`,
        attachments: [],
        anonymousUserId
      });
      setTrackingCode(report.trackingCode);
      setSuccess(true);
      setTimeout(() => onReportSubmitted(report.trackingCode), 3000);
    } catch (error: any) {
      setErrorMsg(error.message || "An unexpected error occurred.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (success) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center p-6 animate-fade-in">
        <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mb-4">
          <CheckCircle className="w-10 h-10 text-green-600" />
        </div>
        <h2 className="text-2xl font-bold mb-2">Report Sent</h2>
        <div className="bg-gray-100 dark:bg-gray-800 p-4 rounded-xl mb-6 border-2 border-dashed border-gray-300">
          <span className="text-3xl font-mono font-bold text-brand-600 tracking-wider">{trackingCode}</span>
        </div>
        <p className="text-sm text-gray-500">Redirecting to tracking view...</p>
      </div>
    );
  }

  return (
    <div className="p-4 pb-20 animate-slide-up relative">
      <div className="flex justify-between items-start mb-6">
        <h1 className="text-2xl font-bold text-brand-700 dark:text-brand-400">{t.report_title}</h1>
      </div>

      <div className="bg-yellow-50 dark:bg-yellow-900/20 border-l-4 border-yellow-400 p-4 mb-4 rounded-r flex gap-3">
        <AlertCircle className="w-5 h-5 text-yellow-500 flex-shrink-0" />
        <p className="text-sm text-yellow-700 dark:text-yellow-200">{t.safety_priority}</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className={`p-4 rounded-xl border-2 transition-colors cursor-pointer flex items-center gap-3 ${isIncognito ? 'bg-gray-800 border-gray-600 text-white' : 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-300'}`} onClick={() => setIsIncognito(!isIncognito)}>
           <EyeOff className="w-5 h-5" />
           <div className="flex-1 text-sm font-bold">Incognito Mode</div>
        </div>

        {errorMsg && <div className="bg-red-50 text-red-600 p-4 rounded-xl text-sm border border-red-100">{errorMsg}</div>}

        <div className="bg-white dark:bg-gray-800 p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 space-y-4">
            <div>
              <label className="flex items-center gap-2 text-xs font-bold uppercase text-gray-400 mb-2">
                <ListFilter className="w-3 h-3" /> {t.type_incident}
              </label>
              <select value={type} onChange={(e) => setType(e.target.value as GBVType)} className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 text-sm font-medium">
                {Object.values(GBVType).map(v => <option key={v} value={v}>{v}</option>)}
              </select>
            </div>

            <div>
              <label className="flex items-center gap-2 text-xs font-bold uppercase text-gray-400 mb-2">
                <Calendar className="w-3 h-3" /> {t.time_incident}
              </label>
              <input type="datetime-local" value={incidentDate} onChange={(e) => setIncidentDate(e.target.value)} className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 text-sm" />
            </div>

            <div>
              <label className="flex items-center gap-2 text-xs font-bold uppercase text-gray-400 mb-2">
                <MapPin className="w-3 h-3" /> {t.location}
              </label>
              <div className="flex gap-2">
                <input type="text" placeholder={t.location_placeholder} value={location} onChange={(e) => setLocation(e.target.value)} className="flex-1 p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 text-sm" required />
                <button type="button" onClick={handleGetGPS} disabled={gettingLocation} className={`bg-brand-600 text-white p-3 rounded-xl shadow-sm flex-shrink-0 transition-all ${gettingLocation ? 'animate-pulse scale-95 opacity-80' : 'active:scale-90'}`}>
                    {gettingLocation ? <Loader2 className="animate-spin w-5 h-5"/> : <Crosshair className="w-5 h-5" />}
                </button>
              </div>
              {location.includes('maps.google.com') && !gettingLocation && (
                <div className="mt-2 text-[10px] text-green-600 font-bold flex items-center gap-1"><CheckCircle className="w-3 h-3" /> GPS Coordinates Locked</div>
              )}
            </div>

            <div>
              <label className="flex items-center gap-2 text-xs font-bold uppercase text-gray-400 mb-2">
                <Phone className="w-3 h-3" /> {t.phone_number}
              </label>
              <input type="tel" value={phoneNumber} onChange={(e) => setPhoneNumber(e.target.value)} placeholder="+254..." className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 text-sm" />
            </div>
        </div>

        <button type="submit" disabled={isSubmitting} className="w-full bg-brand-600 hover:bg-brand-700 text-white p-5 rounded-2xl font-bold shadow-lg shadow-brand-500/20 disabled:opacity-70 flex justify-center items-center transition-all active:scale-95">
          {isSubmitting ? <Loader2 className="animate-spin w-5 h-5 mr-2" /> : t.submit_btn}
        </button>
      </form>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Hotline, SupportCentre } from '../types';
import { BackendService } from '../services/mockBackend';
import { GeminiService } from '../services/geminiService';
import { Phone, MapPin, ExternalLink, Navigation, Loader2, Map as MapIcon, Compass, Crosshair } from 'lucide-react';

export const HotlinesView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'hotlines' | 'centres'>('hotlines');
  const [hotlines, setHotlines] = useState<Hotline[]>([]);
  const [centres, setCentres] = useState<SupportCentre[]>([]);
  const [loadingCentres, setLoadingCentres] = useState(false);
  const [userLocation, setUserLocation] = useState<{lat: number, lng: number} | null>(null);
  const [locationError, setLocationError] = useState('');
  const [isOnlineSearch, setIsOnlineSearch] = useState(false);

  useEffect(() => {
    BackendService.getHotlines().then(setHotlines);
    BackendService.getSupportCentres(0, 0).then(setCentres);
  }, []);

  const handleLocateAndFetch = () => {
    setLoadingCentres(true);
    setLocationError('');
    setIsOnlineSearch(false);

    if (!navigator.geolocation) {
      setLocationError('Geolocation is not supported by your browser/device.');
      setLoadingCentres(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        setUserLocation({ lat: latitude, lng: longitude });

        if (navigator.onLine) {
           try {
             const onlineResults = await GeminiService.findNearbyPlaces(latitude, longitude);
             if (onlineResults.length > 0) {
                setCentres(onlineResults);
                setIsOnlineSearch(true);
                setLoadingCentres(false);
                return;
             }
           } catch (e) {
             console.log("Online search failed, sticking to local db");
           }
        }

        const localResults = await BackendService.getSupportCentres(latitude, longitude);
        setCentres(localResults);
        setLoadingCentres(false);
      },
      (err) => {
        console.error(err);
        setLocationError('Unable to lock GPS. Please ensure you are outdoors or near a window.');
        setLoadingCentres(false);
      },
      { 
        enableHighAccuracy: true, // Crucial for Kakuma/remote regions
        timeout: 15000,           // More time for sensors to stabilize
        maximumAge: 0 
      }
    );
  };

  useEffect(() => {
    if (activeTab === 'centres' && !userLocation) {
      handleLocateAndFetch();
    }
  }, [activeTab]);

  return (
    <div className="p-4 pb-20 animate-slide-up h-full flex flex-col">
      <h1 className="text-2xl font-bold mb-6 text-brand-700 dark:text-brand-400">Help & Support</h1>

      <div className="flex p-1 bg-gray-200 dark:bg-gray-800 rounded-xl mb-6">
        <button 
          onClick={() => setActiveTab('hotlines')}
          className={`flex-1 py-2 rounded-lg text-sm font-medium transition-all ${
            activeTab === 'hotlines' ? 'bg-white dark:bg-gray-700 text-brand-600 shadow-sm' : 'text-gray-500'
          }`}
        >
          Hotlines
        </button>
        <button 
          onClick={() => setActiveTab('centres')}
          className={`flex-1 py-2 rounded-lg text-sm font-medium transition-all ${
            activeTab === 'centres' ? 'bg-white dark:bg-gray-700 text-brand-600 shadow-sm' : 'text-gray-500'
          }`}
        >
          Find Shelters
        </button>
      </div>

      <div className="flex-1 overflow-y-auto space-y-4 no-scrollbar">
        {activeTab === 'hotlines' ? (
          hotlines.map(hotline => (
            <div key={hotline.id} className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 flex items-center justify-between">
              <div>
                <span className={`text-xs px-2 py-1 rounded-full ${
                  hotline.category === 'Emergency' ? 'bg-red-100 text-red-700' : 'bg-blue-100 text-blue-700'
                }`}>
                  {hotline.category}
                </span>
                <h3 className="font-bold text-lg mt-1">{hotline.number}</h3>
                <p className="text-sm text-gray-500">{hotline.name}</p>
              </div>
              <a href={`tel:${hotline.number}`} className="bg-green-500 hover:bg-green-600 text-white p-3 rounded-full shadow-lg transition-transform active:scale-90">
                <Phone className="w-5 h-5" />
              </a>
            </div>
          ))
        ) : (
          <>
            <div className="w-full h-56 bg-gray-200 dark:bg-gray-700 rounded-2xl mb-4 relative overflow-hidden shadow-inner border border-gray-300 dark:border-gray-600">
               {userLocation && navigator.onLine ? (
                 <iframe 
                   width="100%" 
                   height="100%" 
                   frameBorder="0" 
                   style={{ border: 0 }}
                   src={`https://maps.google.com/maps?q=${userLocation.lat},${userLocation.lng}&z=14&output=embed`}
                   allowFullScreen
                   title="User Location Map"
                 ></iframe>
               ) : (
                 <div className="absolute inset-0 flex items-center justify-center flex-col text-gray-400 bg-gray-100 dark:bg-gray-800 p-6 text-center">
                    {loadingCentres ? (
                       <div className="flex flex-col items-center">
                          <Loader2 className="w-10 h-10 mb-2 animate-spin text-brand-500" />
                          <p className="text-xs font-bold text-brand-600 uppercase tracking-tighter">Acquiring Satellites...</p>
                       </div>
                    ) : (
                       <MapIcon className="w-8 h-8 mb-2" />
                    )}
                    <span className="text-[10px] mt-2 leading-tight">
                      {loadingCentres 
                        ? 'Trying to pinpoint your location precisely...' 
                        : (userLocation ? 'Map view needs internet. Nearby centers listed below.' : 'GPS data needed to find nearest shelters.')
                      }
                    </span>
                 </div>
               )}
            </div>

            <div className="flex justify-between items-center mb-2">
               <div className="flex items-center gap-2">
                 <h3 className="font-bold text-gray-700 dark:text-gray-200">Nearby Support</h3>
                 {isOnlineSearch && <span className="text-[10px] bg-green-100 text-green-700 px-2 py-0.5 rounded-full font-bold flex items-center gap-1"><Compass className="w-3 h-3"/> Live GPS</span>}
               </div>
               <button 
                 onClick={handleLocateAndFetch} 
                 disabled={loadingCentres}
                 className={`text-xs text-brand-600 flex items-center bg-brand-50 dark:bg-brand-900/20 px-3 py-1.5 rounded-lg font-bold border border-brand-100 ${loadingCentres ? 'opacity-50' : 'active:scale-95'}`}
               >
                 <Crosshair className="w-3 h-3 mr-1" /> {loadingCentres ? 'Searching...' : 'Refresh GPS'}
               </button>
            </div>

            {locationError && (
              <div className="bg-red-50 text-red-600 p-3 rounded-xl text-[10px] font-bold border border-red-100 mb-4">{locationError}</div>
            )}

            {centres.map((centre, idx) => (
              <div key={centre.id || idx} className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 animate-fade-in">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-bold text-gray-900 dark:text-white max-w-[80%]">{centre.name}</h3>
                  <span className={`text-xs text-white px-2 py-1 rounded font-bold ${
                      centre.type === 'Police' ? 'bg-blue-600' : 
                      centre.type === 'Medical' ? 'bg-red-500' : 'bg-brand-500'
                  }`}>
                    {centre.type}
                  </span>
                </div>
                <p className="text-sm text-gray-500 mb-3">{centre.address}</p>
                <div className="flex gap-2">
                   <a 
                     href={centre.mapUri || `https://www.google.com/maps/dir/?api=1&destination=${encodeURIComponent(centre.name + ' ' + centre.address)}`}
                     target="_blank" 
                     rel="noopener noreferrer"
                     className="flex-1 py-3 bg-brand-50 dark:bg-brand-900/20 text-brand-700 dark:text-brand-300 rounded-lg text-sm font-bold flex items-center justify-center gap-2 hover:bg-brand-100 transition-colors"
                   >
                     <Navigation className="w-4 h-4" /> Get Directions
                   </a>
                </div>
              </div>
            ))}
          </>
        )}
      </div>
    </div>
  );
};

