        <div className={`p-4 rounded-xl border-2 transition-colors cursor-pointer flex items-center gap-3 ${isIncognito ? 'bg-gray-800 border-gray-600 text-white' : 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-300'}`} onClick={() => setIsIncognito(!isIncognito)}>
           <EyeOff className="w-5 h-5" />
           <div className="flex-1 text-sm font-bold">Incognito Mode</div>
        </div>

        {errorMsg && <div className="bg-red-50 text-red-600 p-4 rounded-xl text-sm border border-red-100">{errorMsg}</div>}

        <div className="bg-white dark:bg-gray-800 p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 space-y-4">
            <div>
              <label className="flex items-center gap-2 text-xs font-bold uppercase text-gray-400 mb-2">
                <ListFilter className="w-3 h-3" /> {t.type_incident}
              </label>
              <select value={type} onChange={(e) => setType(e.target.value as GBVType)} className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 text-sm font-medium">
                {Object.values(GBVType).map(v => <option key={v} value={v}>{v}</option>)}
              </select>
            </div>

            <div>
              <label className="flex items-center gap-2 text-xs font-bold uppercase text-gray-400 mb-2">
                <Calendar className="w-3 h-3" /> {t.time_incident}
              </label>
              <input type="datetime-local" value={incidentDate} onChange={(e) => setIncidentDate(e.target.value)} className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 text-sm" />
            </div>

            <div>
              <label className="flex items-center gap-2 text-xs font-bold uppercase text-gray-400 mb-2">
                <MapPin className="w-3 h-3" /> {t.location}
              </label>
              <div className="flex gap-2">
                <input type="text" placeholder={t.location_placeholder} value={location} onChange={(e) => setLocation(e.target.value)} className="flex-1 p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 text-sm" required />
                <button type="button" onClick={handleGetGPS} disabled={gettingLocation} className={`bg-brand-600 text-white p-3 rounded-xl shadow-sm flex-shrink-0 transition-all ${gettingLocation ? 'animate-pulse scale-95 opacity-80' : 'active:scale-90'}`}>
                    {gettingLocation ? <Loader2 className="animate-spin w-5 h-5"/> : <Crosshair className="w-5 h-5" />}
                </button>
              </div>
              {location.includes('maps.google.com') && !gettingLocation && (
                <div className="mt-2 text-[10px] text-green-600 font-bold flex items-center gap-1"><CheckCircle className="w-3 h-3" /> GPS Coordinates Locked</div>
              )}
            </div>

            <div>
              <label className="flex items-center gap-2 text-xs font-bold uppercase text-gray-400 mb-2">
                <Phone className="w-3 h-3" /> {t.phone_number}
              </label>
              <input type="tel" value={phoneNumber} onChange={(e) => setPhoneNumber(e.target.value)} placeholder="+254..." className="w-full p-3 rounded-xl border border-gray-300 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 text-sm" />
            </div>
        </div>

        <button type="submit" disabled={isSubmitting} className="w-full bg-brand-600 hover:bg-brand-700 text-white p-5 rounded-2xl font-bold shadow-lg shadow-brand-500/20 disabled:opacity-70 flex justify-center items-center transition-all active:scale-95">
          {isSubmitting ? <Loader2 className="animate-spin w-5 h-5 mr-2" /> : t.submit_btn}
        </button>

        {draftSavedFeedback && (
          <p className="text-center text-xs font-bold text-green-600 animate-fade-in">Draft progress saved locally.</p>
        )}
      </form>
    </div>
  );
};

import { GoogleGenAI, Type, Chat } from "@google/genai";
import { QuizQuestion, SupportCentre, GBVType } from '../types';

export const GeminiService = {

  // Create a new chat session with SafeVoice context
  createChat(): Chat | null {
    try {
      // Create a new instance right before use
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      return ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
          tools: [{ googleSearch: {} }],
          systemInstruction: `You are SafeVoice AI, a highly specialized expert ONLY in Gender-Based Violence (GBV). 

          CORE MANDATE:
          1. You MUST REFUSE to answer any questions that are not related to GBV incidents, prevention, survivor support, or GBV educational knowledge.
          2. If a user asks about general topics (e.g., weather, cooking, sports, general news, entertainment), you must politely decline and state that your expertise is strictly limited to GBV.
          3. Example refusal: "I am a specialized assistant dedicated solely to Gender-Based Violence (GBV) support and education. I cannot provide information on that topic. Is there anything related to your safety or GBV knowledge I can help you with?"

          ALLOWED KNOWLEDGE DOMAIN:
          - The 6 types of GBV (Physical, Sexual, Emotional, Economic, Harmful Practices, Harassment).
          - Survivor rights and legal frameworks (e.g., Sexual Offences Act).
          - Safety planning and exit strategies.
          - Inter-agency prevention and recovery processes (Medical, Police, Legal, NGO).
          - Support center locations and hotline information.

          SAFETY & CRISIS RULES:
          1. If a user mentions killing themselves, killing others, or is in active physical danger, START your response with: "EMERGENCY: PLEASE CALL 1195 OR 999 IMMEDIATELY. YOUR LIFE IS IN DANGER."
          2. Be empathetic, professional, and non-judgmental.
          3. Never provide medical or legal advice that supersedes official local authorities.`
        }
      });
    } catch (e) {
      console.error("Failed to create chat session", e);
      return null;
    }
  },

  // Classify description into GBV categories
  async classifyIncident(description: string): Promise<GBVType | string> {
     try {
       const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
       const response = await ai.models.generateContent({
         model: 'gemini-3-flash-preview',
         contents: `Classify the following incident into one of the 6 core GBV types: Physical Violence, Sexual Violence, Emotional/Psychological Abuse, Economic/Financial Abuse, Harmful Traditional Practices, or Sexual Harassment. Return ONLY the category name. Description: "${description}"`,
       });
       return response.text.trim() as GBVType;
     } catch (e) {
       return "Review Pending";
     }
  },

  // Basic responses when offline or on error
  getOfflineResponse(userText: string): string {
    const lower = userText.toLowerCase();
    if (lower.includes('help') || lower.includes('danger') || lower.includes('knife') || lower.includes('kill')) {
        return "EMERGENCY: Please call 1195 immediately. If you are in Kenya, this is a 24-hour toll-free hotline for GBV. Move to a safe room and lock the door.";
    }
    return "I am a specialized AI for GBV support. I am here to help with reports, safety plans, or finding recovery centers. Are you safe right now?";
  },

  // Generate educational quiz questions
  async generateQuizForTopic(topic: string): Promise<QuizQuestion[]> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate 3 quiz questions about "${topic}" in GBV context. Return JSON.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                question: { type: Type.STRING },
                options: { type: Type.ARRAY, items: { type: Type.STRING } },
                correctIndex: { type: Type.INTEGER }
              }
            }
          }
        }
      });
      return JSON.parse(response.text.trim());
    } catch (error) {
      return [];
    }
  },

  // Generate personalized safety plan
  async generateSafetyPlan(inputs: any): Promise<string> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Create a 5-step safety plan for a survivor: ${JSON.stringify(inputs)}`,
      });
      return response.text;
    } catch (error) {
      return "Call 1195 and prepare a small bag with your ID and essential documents.";
    }
  },

  // Find centers using Google Maps grounding (requires Gemini 2.5 series)
  async findNearbyPlaces(lat: number, lng: number): Promise<SupportCentre[]> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash', 
        contents: "What GBV recovery centers or police stations are nearby?",
        config: {
          tools: [{ googleMaps: {} }],
          toolConfig: {
            retrievalConfig: {
              latLng: {
                latitude: lat,
                longitude: lng
              }
            }
          }
        },
      });
      const places: SupportCentre[] = [];
      response.candidates?.[0]?.groundingMetadata?.groundingChunks?.forEach((chunk: any, i: number) => {
        if (chunk.maps) {
          places.push({ 
            id: `gm_${i}`, 
            name: chunk.maps.title, 
            address: "Nearby Support", 
            type: "Support", 
            distance: "Calculated via GPS", 
            mapUri: chunk.maps.uri 
          });
        }
      });
      return places;
    } catch (e) {
      console.error("Maps grounding failed", e);
      return [];
    }
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { GeminiService } from '../services/geminiService';
import { Bot, X, Send, Loader2, Sparkles, MessageCircleHeart, ShieldAlert } from 'lucide-react';
import { Chat } from "@google/genai";
import { Language } from '../types';
import { getTranslation } from '../services/translations';

interface Message {
  id: string;
  text: string;
  sender: 'user' | 'bot';
  isCrisis?: boolean;
}

export const FloatingAI: React.FC<{ lang: Language }> = ({ lang }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    { id: '1', text: "Hello, I am the SafeVoice AI. I specialize exclusively in support for Gender-Based Violence (GBV). Ask me about safety, rights, or recovery knowledge.", sender: 'bot' }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const chatSession = useRef<Chat | null>(null);

  useEffect(() => {
    if (isOpen && !chatSession.current) {
      const session = GeminiService.createChat();
      if (session) chatSession.current = session;
    }
  }, [isOpen]);

  const scrollToBottom = () => messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  useEffect(scrollToBottom, [messages]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || loading) return;

    const userText = input;
    setMessages(prev => [...prev, { id: Date.now().toString(), text: userText, sender: 'user' }]);
    setInput('');
    setLoading(true);

    try {
      let botText = "";
      if (chatSession.current) {
        try {
          const result = await chatSession.current.sendMessage({ message: userText });
          botText = result.text || "";
        } catch (apiError) {
          botText = GeminiService.getOfflineResponse(userText);
        }
      } else {
        botText = GeminiService.getOfflineResponse(userText);
      }

      const isCrisis = botText.includes("EMERGENCY");
      setMessages(prev => [...prev, { id: (Date.now() + 1).toString(), text: botText, sender: 'bot', isCrisis }]);
    } catch (error) {
      setMessages(prev => [...prev, { id: 'err', text: "I'm having trouble connecting. Please call 1195 if you need help.", sender: 'bot' }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      {/* Floating Bubble */}
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`fixed bottom-20 left-4 z-[60] w-14 h-14 rounded-full shadow-2xl flex items-center justify-center transition-all duration-300 transform active:scale-90 ${isOpen ? 'bg-gray-800 rotate-90 scale-0' : 'bg-brand-600 scale-100'}`}
      >
        <Sparkles className="w-7 h-7 text-white animate-pulse" />
      </button>

      {/* Chat Window Overlay */}
      {isOpen && (
        <div className="fixed inset-x-4 bottom-24 z-[70] bg-white dark:bg-gray-800 rounded-3xl shadow-2xl border border-brand-100 dark:border-gray-700 flex flex-col max-h-[70vh] animate-slide-up overflow-hidden">
          <div className="bg-brand-600 p-4 flex justify-between items-center">
            <div className="flex items-center gap-2 text-white">
               <Bot className="w-5 h-5" />
               <h3 className="font-bold text-sm">SafeVoice AI Support</h3>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-white/80 hover:text-white">
              <X className="w-6 h-6" />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4 no-scrollbar">
            {messages.map((msg) => (
              <div key={msg.id} className={`flex flex-col ${msg.sender === 'user' ? 'items-end' : 'items-start'}`}>
                {msg.isCrisis && (
                  <div className="mb-2 bg-red-600 text-white p-2 rounded-lg text-[10px] font-black uppercase flex items-center gap-1">
                    <ShieldAlert className="w-3 h-3" /> Crisis Alert
                  </div>
                )}
                <div className={`max-w-[90%] p-3 rounded-2xl text-sm ${msg.sender === 'user' ? 'bg-brand-500 text-white rounded-tr-none' : 'bg-gray-100 dark:bg-gray-700 dark:text-gray-200 rounded-tl-none'}`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {loading && <Loader2 className="w-5 h-5 animate-spin text-brand-400" />}
            <div ref={messagesEndRef} />
          </div>

          <div className="p-3 border-t dark:border-gray-700 bg-gray-50 dark:bg-gray-900">
            <form onSubmit={handleSend} className="flex gap-2">
              <input 
                type="text" 
                value={input} 
                onChange={(e) => setInput(e.target.value)} 
                placeholder="Ask specialized GBV AI..." 
                className="flex-1 p-3 rounded-2xl bg-white dark:bg-gray-800 text-sm border dark:border-gray-700 outline-none"
              />
              <button type="submit" disabled={loading} className="bg-brand-600 text-white p-3 rounded-2xl shadow-md disabled:opacity-50">
                <Send className="w-5 h-5" />
              </button>
            </form>
          </div>
        </div>
      )}
    </>
  );
};

